const state = {
  theme: localStorage.getItem("nova-theme") || "light",
  background: localStorage.getItem("nova-bg") || "flow-gradient",
  backgroundImageUrl: localStorage.getItem("nova-bg-image-url-v1") || "",
  backgroundImageSource: localStorage.getItem("nova-bg-image-source-v1") || "",
  backgroundImageSourceMode: localStorage.getItem("nova-bg-image-source-mode-v1") || localStorage.getItem("nova-bg-image-source-v1") || "local",
  backgroundImageFitMode: localStorage.getItem("nova-bg-image-fit-mode-v1") || "fill",
  collapsed: localStorage.getItem("nova-sidebar-collapsed") === "true",
  mainView: localStorage.getItem("nova-main-view") || "search",
};

