const availableBackgroundIds = new Set(bgOptions.map((option) => option.dataset.bg).filter(Boolean));
if (!availableBackgroundIds.has(state.background)) state.background = "flow-gradient";
if (!["local", "url"].includes(state.backgroundImageSourceMode)) state.backgroundImageSourceMode = "local";
if (!["fill", "fit", "center"].includes(state.backgroundImageFitMode)) state.backgroundImageFitMode = "fill";
if (!["search", "recommend", "internal", "website", "favorites", "vault", "notes", "tasks", "tutorial", "local", "ai"].includes(state.mainView)) state.mainView = "search";
if (/^blob:/i.test(state.backgroundImageUrl)) {
  state.backgroundImageUrl = "";
  state.backgroundImageSource = "";
}
