function applyTheme() {
  body.dataset.theme = state.theme;
  const label = state.theme === "dark" ? "浅色" : "深色";
  themeToggle.querySelector(".menu-label").textContent = label;
  localStorage.setItem("nova-theme", state.theme);
}

function normalizeBackgroundImageUrl(rawUrl) {
  if (!rawUrl || typeof rawUrl !== "string") return "";
  const value = rawUrl.trim();
  if (!value) return "";
  if (/^data:image\//i.test(value)) return value;
  if (/^blob:/i.test(value)) return value;
  if (/^https?:\/\//i.test(value)) return value;
  return "";
}

function normalizeBackgroundImageSourceMode(rawMode) {
  return rawMode === "url" ? "url" : "local";
}

function normalizeBackgroundImageFitMode(rawMode) {
  return rawMode === "fit" || rawMode === "center" || rawMode === "fill" ? rawMode : "fill";
}

function escapeCssUrlValue(value) {
  return String(value).replaceAll("\\", "\\\\").replaceAll('"', '\\"').replaceAll("\n", "").replaceAll("\r", "");
}

function updateBackgroundImageStatus(message, isError = false) {
  if (!bgImageStatus) return;
  bgImageStatus.textContent = message;
  bgImageStatus.classList.toggle("is-error", isError);
}

function getBackgroundImageStatusText() {
  const sourceLabel = normalizeBackgroundImageSourceMode(state.backgroundImageSourceMode) === "url" ? "网络图片" : "本地图片";
  if (!state.backgroundImageUrl) return `未启用图片背景（当前来源：${sourceLabel}）`;
  const modeLabel = state.backgroundImageFitMode === "fit" ? "适应" : state.backgroundImageFitMode === "center" ? "居中" : "填充";
  return state.backgroundImageSource === "local"
    ? `已启用图片背景（本地图片，${modeLabel}）`
    : `已启用图片背景（网络图片，${modeLabel}）`;
}

function persistBackgroundImageState() {
  try {
    localStorage.setItem(BG_IMAGE_SOURCE_MODE_STORE_KEY, normalizeBackgroundImageSourceMode(state.backgroundImageSourceMode));
    localStorage.setItem(BG_IMAGE_FIT_MODE_STORE_KEY, normalizeBackgroundImageFitMode(state.backgroundImageFitMode));
    if (state.backgroundImageSource === "local") {
      const isDataUrl = /^data:image\//i.test(state.backgroundImageUrl);
      if (isDataUrl) {
        localStorage.setItem(BG_IMAGE_URL_STORE_KEY, state.backgroundImageUrl);
        localStorage.setItem(BG_IMAGE_SOURCE_STORE_KEY, "local");
      } else if (canUseLocalBackgroundCache()) {
        localStorage.removeItem(BG_IMAGE_URL_STORE_KEY);
        localStorage.setItem(BG_IMAGE_SOURCE_STORE_KEY, "local");
      } else {
        localStorage.removeItem(BG_IMAGE_URL_STORE_KEY);
        localStorage.removeItem(BG_IMAGE_SOURCE_STORE_KEY);
      }
    } else if (state.backgroundImageUrl) {
      localStorage.setItem(BG_IMAGE_URL_STORE_KEY, state.backgroundImageUrl);
      localStorage.setItem(BG_IMAGE_SOURCE_STORE_KEY, state.backgroundImageSource || "url");
    } else {
      localStorage.removeItem(BG_IMAGE_URL_STORE_KEY);
      localStorage.removeItem(BG_IMAGE_SOURCE_STORE_KEY);
    }
  } catch {
    updateBackgroundImageStatus("图片背景过大，刷新后可能失效。", true);
  }
}

function isSupportedImageFile(file) {
  if (!file) return false;
  const type = String(file.type || "").trim().toLowerCase();
  if (type.startsWith("image/")) return true;
  return /\.(avif|bmp|gif|heic|heif|ico|jpe?g|png|svg|tiff?|webp)$/i.test(file.name || "");
}

function syncBackgroundImageFileApplyButton() {
  if (!bgImageFileApply) return;
  const sourceMode = normalizeBackgroundImageSourceMode(state.backgroundImageSourceMode);
  const file = pendingBackgroundImageFile || bgImageFileInput?.files?.[0] || null;
  bgImageFileApply.disabled = sourceMode !== "local" || !file;
}

function revokeBackgroundBlobUrl() {
  if (!activeBackgroundBlobUrl) return;
  URL.revokeObjectURL(activeBackgroundBlobUrl);
  activeBackgroundBlobUrl = "";
}

function canUseLocalBackgroundCache() {
  const protocol = window.location.protocol;
  return Boolean(window.caches) && (protocol === "https:" || protocol === "http:");
}

function getLocalBackgroundCacheKey() {
  return new URL(BG_IMAGE_LOCAL_CACHE_PATH, window.location.href).href;
}

async function cacheLocalBackgroundFile(file) {
  if (!canUseLocalBackgroundCache()) return false;
  try {
    const cache = await caches.open(BG_IMAGE_LOCAL_CACHE_NAME);
    const response = new Response(file, {
      headers: {
        "Content-Type": file.type || "application/octet-stream",
      },
    });
    await cache.put(getLocalBackgroundCacheKey(), response);
    return true;
  } catch {
    return false;
  }
}

async function clearCachedLocalBackground() {
  if (!canUseLocalBackgroundCache()) return;
  try {
    const cache = await caches.open(BG_IMAGE_LOCAL_CACHE_NAME);
    await cache.delete(getLocalBackgroundCacheKey());
  } catch {
    // Ignore cache clear errors to avoid blocking UI operations.
  }
}

async function restoreCachedLocalBackgroundIfNeeded() {
  if (state.backgroundImageSource !== "local" || state.backgroundImageUrl) return;
  if (!canUseLocalBackgroundCache()) {
    state.backgroundImageSource = "";
    persistBackgroundImageState();
    return;
  }
  try {
    const cache = await caches.open(BG_IMAGE_LOCAL_CACHE_NAME);
    const cachedResponse = await cache.match(getLocalBackgroundCacheKey());
    if (!cachedResponse) {
      state.backgroundImageSource = "";
      persistBackgroundImageState();
      return;
    }
    const cachedBlob = await cachedResponse.blob();
    if (!cachedBlob || cachedBlob.size <= 0) {
      state.backgroundImageSource = "";
      persistBackgroundImageState();
      return;
    }
    revokeBackgroundBlobUrl();
    const blobUrl = URL.createObjectURL(cachedBlob);
    activeBackgroundBlobUrl = blobUrl;
    state.backgroundImageUrl = blobUrl;
    state.backgroundImageSource = "local";
    applyBackground();
  } catch {
    state.backgroundImageSource = "";
    persistBackgroundImageState();
  }
}

function clearBackgroundImage({ keepInput = false, statusMessage = "已清除图片背景" } = {}) {
  revokeBackgroundBlobUrl();
  state.backgroundImageUrl = "";
  state.backgroundImageSource = "";
  pendingBackgroundImageFile = null;
  void clearCachedLocalBackground();
  if (bgImageFileInput) bgImageFileInput.value = "";
  if (!keepInput && bgImageUrlInput) bgImageUrlInput.value = "";
  syncBackgroundImageFileApplyButton();
  applyBackground();
  updateBackgroundImageStatus(statusMessage, false);
}

function syncBackgroundImageSourceModeInputs() {
  if (!bgImageSourceInputs.length) return;
  const mode = normalizeBackgroundImageSourceMode(state.backgroundImageSourceMode);
  bgImageSourceInputs.forEach((input) => {
    input.checked = input.value === mode;
  });
}

function syncBackgroundImageInputAvailability() {
  const mode = normalizeBackgroundImageSourceMode(state.backgroundImageSourceMode);
  if (bgImageFileInput) bgImageFileInput.disabled = mode !== "local";
  if (bgImageUrlInput) bgImageUrlInput.disabled = mode !== "url";
  if (bgImageUrlApply) bgImageUrlApply.disabled = mode !== "url";
  syncBackgroundImageFileApplyButton();
}

function setBackgroundImageSourceMode(rawMode, options = {}) {
  const { clearOnSwitch = true } = options;
  const nextMode = normalizeBackgroundImageSourceMode(rawMode);
  const hasChanged = state.backgroundImageSourceMode !== nextMode;
  state.backgroundImageSourceMode = nextMode;
  if (
    clearOnSwitch &&
    hasChanged &&
    state.backgroundImageUrl &&
    state.backgroundImageSource &&
    state.backgroundImageSource !== nextMode
  ) {
    clearBackgroundImage({ keepInput: true, statusMessage: `已切换到${nextMode === "url" ? "网络图片" : "本地图片"}模式，请重新应用图片背景` });
    return;
  }
  applyBackground();
}

function syncBackgroundImageFitModeInputs() {
  if (!bgImageModeInputs.length) return;
  const mode = normalizeBackgroundImageFitMode(state.backgroundImageFitMode);
  bgImageModeInputs.forEach((input) => {
    input.checked = input.value === mode;
  });
}

function getBackgroundImagePlacementRule() {
  const mode = normalizeBackgroundImageFitMode(state.backgroundImageFitMode);
  if (mode === "fit") return "center / contain no-repeat";
  if (mode === "center") return "center / auto no-repeat";
  return "center / cover no-repeat";
}

function applyBackground() {
  body.dataset.bg = state.background;
  bgOptions.forEach((option) => {
    option.classList.toggle("is-selected", option.dataset.bg === state.background);
  });
  state.backgroundImageSourceMode = normalizeBackgroundImageSourceMode(state.backgroundImageSourceMode);
  state.backgroundImageFitMode = normalizeBackgroundImageFitMode(state.backgroundImageFitMode);
  syncBackgroundImageSourceModeInputs();
  syncBackgroundImageFitModeInputs();
  syncBackgroundImageInputAvailability();
  const safeImageUrl = normalizeBackgroundImageUrl(state.backgroundImageUrl);
  if (safeImageUrl) {
    const overlay =
      state.theme === "dark"
        ? "linear-gradient(180deg, rgba(4, 11, 20, 0.5), rgba(4, 11, 20, 0.68))"
        : "linear-gradient(180deg, rgba(255, 255, 255, 0.3), rgba(255, 255, 255, 0.5))";
    body.style.setProperty("--page-bg", `${overlay}, url("${escapeCssUrlValue(safeImageUrl)}") ${getBackgroundImagePlacementRule()}`);
    body.classList.add("has-custom-background");
    state.backgroundImageUrl = safeImageUrl;
  } else {
    body.style.removeProperty("--page-bg");
    body.classList.remove("has-custom-background");
    state.backgroundImageUrl = "";
    if (state.backgroundImageSource !== "local") {
      state.backgroundImageSource = "";
    }
  }

  if (bgImageUrlInput && state.backgroundImageSource === "url" && state.backgroundImageUrl) {
    bgImageUrlInput.value = state.backgroundImageUrl;
  }
  updateBackgroundImageStatus(getBackgroundImageStatusText());
  try {
    localStorage.setItem("nova-bg", state.background);
  } catch {
    // Ignore storage write failure to keep runtime behavior available.
  }
  persistBackgroundImageState();
}

function applySidebar() {
  body.classList.toggle("sidebar-collapsed", state.collapsed);
  collapseText.textContent = state.collapsed ? "展开" : "收起";
  collapseToggle.title = state.collapsed ? "展开侧栏" : "收起侧栏";
  collapseToggle.querySelector("svg").style.transform = state.collapsed ? "rotate(180deg)" : "rotate(0deg)";
  syncSidebarHoverTitles();
  localStorage.setItem("nova-sidebar-collapsed", String(state.collapsed));
}

function syncSidebarHoverTitles() {
  if (!sidebarHoverTitleButtons.length) return;
  const isMobileLayout = window.innerWidth <= 980;
  const isMobileSidebarOpen = body.classList.contains("sidebar-open");
  const shouldShowHoverTitle = isMobileLayout ? !isMobileSidebarOpen : Boolean(state.collapsed);
  sidebarHoverTitleButtons.forEach((button) => {
    if (!(button instanceof HTMLElement)) return;
    const storedTitle = String(button.dataset.sidebarTitle || button.getAttribute("title") || "").trim();
    if (storedTitle && !button.dataset.sidebarTitle) {
      button.dataset.sidebarTitle = storedTitle;
    }
    const hoverTitle = String(button.dataset.sidebarTitle || "").trim();
    if (shouldShowHoverTitle && hoverTitle) {
      button.setAttribute("title", hoverTitle);
    } else {
      button.removeAttribute("title");
    }
  });
}

function syncMobileTriggerState() {
  if (!mobileTrigger) return;
  const opened = body.classList.contains("sidebar-open");
  mobileTrigger.setAttribute("aria-expanded", String(opened));
  mobileTrigger.setAttribute("aria-label", opened ? "收起侧栏" : "展开侧栏");
  syncSidebarHoverTitles();
}

function closeSidebarOnMenuNavigate() {
  if (window.innerWidth > 980) return;
  body.classList.remove("sidebar-open");
  syncMobileTriggerState();
}

function renderProtectedFeatureAccessState() {
  const authenticated = Boolean(notesState.authenticated);
  protectedFeaturePanels.forEach(({ authPlaceholder, workspace }) => {
    if (authPlaceholder) authPlaceholder.hidden = authenticated;
    if (workspace) workspace.hidden = !authenticated;
  });
  const activeProtectedFeature = state.mainView;
  if (authenticated && protectedFeatureState[activeProtectedFeature]) {
    void ensureProtectedFeatureLoaded(activeProtectedFeature);
  }
  if (!authenticated) {
    if (localState.statusTimer) {
      window.clearTimeout(localState.statusTimer);
      localState.statusTimer = null;
    }
    if (localStatus) {
      localStatus.hidden = true;
      localStatus.textContent = "";
      localStatus.classList.remove("is-error");
    }
    if (state.mainView === "local") {
      setViewSearchMetaText("local", "请先登录后使用本地快捷");
    }
    Object.keys(protectedFeatureState).forEach((feature) => clearProtectedFeatureStatus(feature));
    clearAiAssistantStateForLogout();
    closeWebsiteAddModal();
    closeAiApiSettingsModal();
    syncAiAssistantUi();
    renderAiMessages();
  }
  renderWebsiteCollectionCanvas();
  portalSearchSyncSettingsAccess();
  syncTasksImportUndoButtonState();
  syncWebsiteImportUndoButtonState();
}

function applyMainView() {
  const view = ALL_MAIN_VIEWS.includes(state.mainView) ? state.mainView : "search";
  state.mainView = view;
  const activeCollectionFeature = getWebsiteCollectionActiveFeature(view);
  if (
    websiteAddModal &&
    !websiteAddModal.hidden &&
    websiteCollectionRuntimeState.modalFeature &&
    websiteCollectionRuntimeState.modalFeature !== activeCollectionFeature
  ) {
    closeWebsiteAddModal();
  }
  syncWebsiteCollectionRuntimeForView(view);
  body.dataset.mainView = view;

  if (menuSearchButton) menuSearchButton.classList.toggle("is-active", view === "search");
  if (menuInternalButton) menuInternalButton.classList.toggle("is-active", view === "internal");
  if (menuRecommendButton) menuRecommendButton.classList.toggle("is-active", view === "recommend");
  if (menuWebsiteButton) menuWebsiteButton.classList.toggle("is-active", view === "website");
  if (menuFavoritesButton) menuFavoritesButton.classList.toggle("is-active", view === "favorites");
  if (menuVaultButton) menuVaultButton.classList.toggle("is-active", view === "vault");
  if (menuTasksButton) menuTasksButton.classList.toggle("is-active", view === "tasks");
  if (menuTutorialButton) menuTutorialButton.classList.toggle("is-active", view === "tutorial");
  if (menuLocalButton) menuLocalButton.classList.toggle("is-active", view === "local");
  if (menuNotesButton) menuNotesButton.classList.toggle("is-active", view === "notes");
  if (menuAiButton) menuAiButton.classList.toggle("is-active", view === "ai");

  const focusedMode = view !== "search";
  if (heroSection) heroSection.hidden = focusedMode;
  if (statsGridSection) statsGridSection.hidden = focusedMode;
  if (portalSearchCanvas) portalSearchCanvas.hidden = view !== "search";
  portalSearchSyncCosmosAnimation();
  if (panelGrid) panelGrid.hidden = view === "search";
  if (taskPanel) taskPanel.hidden = focusedMode;
  if (recommendPanel) recommendPanel.hidden = false;
  if (recommendGrid) recommendGrid.hidden = !RECOMMEND_GRID_VIEWS.has(view) || view === "search";
  const websiteCollectionViewActive = view === "website" || view === "favorites";
  if (websiteCenter) websiteCenter.hidden = !websiteCollectionViewActive;
  if (favoritesCenter) favoritesCenter.hidden = true;
  if (vaultCenter) vaultCenter.hidden = view !== "vault";
  if (tasksCenter) tasksCenter.hidden = view !== "tasks";
  if (aiCenter) aiCenter.hidden = view !== "ai";
  if (tutorialCenter) tutorialCenter.hidden = view !== "tutorial";
  if (localCenter) localCenter.hidden = view !== "local";
  if (notesCenter) notesCenter.hidden = view !== "notes";
  if (view !== "tasks") closeTasksSearchResultModal();
  if (view !== "tasks") closeTasksAlarmModal();
  if (view !== "ai") closeAiApiSettingsModal();
  renderProtectedFeatureAccessState();
  syncViewSearchBarVisibility(view);
  if (panelGrid) panelGrid.classList.toggle("recommend-only", focusedMode);

  if (topbarTitle) {
    if (view === "recommend") topbarTitle.textContent = RECOMMEND_TOPBAR_TITLE;
    else if (view === "internal") topbarTitle.textContent = INTERNAL_TOPBAR_TITLE;
    else if (view === "website") topbarTitle.textContent = WEBSITE_TOPBAR_TITLE;
    else if (view === "favorites") topbarTitle.textContent = FAVORITES_TOPBAR_TITLE;
    else if (view === "vault") topbarTitle.textContent = VAULT_TOPBAR_TITLE;
    else if (view === "tasks") topbarTitle.textContent = TASKS_TOPBAR_TITLE;
    else if (view === "tutorial") topbarTitle.textContent = TUTORIAL_TOPBAR_TITLE;
    else if (view === "local") topbarTitle.textContent = LOCAL_TOPBAR_TITLE;
    else if (view === "notes") topbarTitle.textContent = NOTES_TOPBAR_TITLE;
    else if (view === "ai") topbarTitle.textContent = AI_TOPBAR_TITLE;
    else topbarTitle.textContent = DEFAULT_TOPBAR_TITLE;
  }
  if (topbarSubtitle) {
    if (view === "recommend") topbarSubtitle.textContent = RECOMMEND_TOPBAR_SUBTITLE;
    else if (view === "internal") topbarSubtitle.textContent = INTERNAL_TOPBAR_SUBTITLE;
    else if (view === "website") topbarSubtitle.textContent = WEBSITE_TOPBAR_SUBTITLE;
    else if (view === "favorites") topbarSubtitle.textContent = FAVORITES_TOPBAR_SUBTITLE;
    else if (view === "vault") topbarSubtitle.textContent = VAULT_TOPBAR_SUBTITLE;
    else if (view === "tasks") topbarSubtitle.textContent = TASKS_TOPBAR_SUBTITLE;
    else if (view === "tutorial") topbarSubtitle.textContent = TUTORIAL_TOPBAR_SUBTITLE;
    else if (view === "local") topbarSubtitle.textContent = LOCAL_TOPBAR_SUBTITLE;
    else if (view === "notes") topbarSubtitle.textContent = NOTES_TOPBAR_SUBTITLE;
    else if (view === "ai") topbarSubtitle.textContent = AI_TOPBAR_SUBTITLE;
    else topbarSubtitle.textContent = DEFAULT_TOPBAR_SUBTITLE;
  }

  if (view === "recommend") {
    void loadRecommendItems();
  } else if (view === "internal") {
    void loadInternalItems();
  } else if (view === "tutorial") {
    void loadTutorialFiles();
  } else if (view === "ai") {
    onAiMainViewEnter();
  } else if (view === "local") {
    if (notesState.authenticated) void loadLocalShortcuts();
  } else if (view === "notes") {
    renderNotesCenter();
  } else if (PROTECTED_MAIN_VIEWS.has(view)) {
    renderProtectedFeatureAccessState();
  } else {
    void loadRecommendItems();
  }

  try {
    localStorage.setItem("nova-main-view", view);
  } catch {
    // Ignore storage write failure to keep runtime behavior available.
  }
}

function openBackgroundModal() {
  backgroundModal.hidden = false;
}

function closeBgModal() {
  backgroundModal.hidden = true;
}

function applyBackgroundImageFromUrl(rawUrl) {
  if (normalizeBackgroundImageSourceMode(state.backgroundImageSourceMode) !== "url") {
    updateBackgroundImageStatus("当前为本地图片模式，请切换到网络图片后再应用", true);
    return false;
  }
  const normalizedUrl = normalizeBackgroundImageUrl(rawUrl);
  if (!normalizedUrl || !/^https?:\/\//i.test(normalizedUrl)) {
    updateBackgroundImageStatus("请输入有效的网络图片地址（http/https）", true);
    return false;
  }
  revokeBackgroundBlobUrl();
  void clearCachedLocalBackground();
  state.backgroundImageUrl = normalizedUrl;
  state.backgroundImageSourceMode = "url";
  state.backgroundImageSource = "url";
  applyBackground();
  return true;
}

async function applyBackgroundImageFromLocalFile(file) {
  if (normalizeBackgroundImageSourceMode(state.backgroundImageSourceMode) !== "local") {
    updateBackgroundImageStatus("当前为网络图片模式，请切换到本地图片后再应用", true);
    return false;
  }
  if (!file) {
    updateBackgroundImageStatus("请选择本地图片文件", true);
    return false;
  }
  if (!isSupportedImageFile(file)) {
    updateBackgroundImageStatus("仅支持图片文件类型", true);
    return false;
  }
  try {
    revokeBackgroundBlobUrl();
    const imageUrl = URL.createObjectURL(file);
    activeBackgroundBlobUrl = imageUrl;
    state.backgroundImageUrl = imageUrl;
    state.backgroundImageSourceMode = "local";
    state.backgroundImageSource = "local";
    applyBackground();
    const cached = await cacheLocalBackgroundFile(file);
    if (!cached && !canUseLocalBackgroundCache()) {
      updateBackgroundImageStatus("已启用图片背景（本地图片，仅当前会话有效）", false);
    }
    return true;
  } catch {
    updateBackgroundImageStatus("本地图片读取失败，请重试", true);
    return false;
  }
}

function pad2(value) {
  return String(value).padStart(2, "0");
}

function toDateKey(date) {
  return `${date.getFullYear()}-${pad2(date.getMonth() + 1)}-${pad2(date.getDate())}`;
}

function parseDateKey(dateKey) {
  const match = /^(\d{4})-(\d{2})-(\d{2})$/.exec(dateKey);
  if (!match) return null;
  const year = Number(match[1]);
  const month = Number(match[2]);
  const day = Number(match[3]);
  if (!year || !month || !day) return null;
  return new Date(year, month - 1, day);
}

function formatDuration(totalSeconds) {
  const safe = Math.max(0, Math.floor(totalSeconds));
  const hours = Math.floor(safe / 3600);
  const minutes = Math.floor((safe % 3600) / 60);
  const seconds = safe % 60;
  return `${pad2(hours)}时 ${pad2(minutes)}分 ${pad2(seconds)}秒`;
}

function isSameDate(dateA, dateB) {
  return (
    dateA.getFullYear() === dateB.getFullYear() &&
    dateA.getMonth() === dateB.getMonth() &&
    dateA.getDate() === dateB.getDate()
  );
}

function formatGregorianDate(date) {
  return `${date.getFullYear()}/${pad2(date.getMonth() + 1)}/${pad2(date.getDate())}`;
}

function formatTime24(date) {
  return `${pad2(date.getHours())}:${pad2(date.getMinutes())}:${pad2(date.getSeconds())}`;
}

function escapeHtml(raw) {
  return String(raw)
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#39;");
}

function escapeRegex(raw) {
  return String(raw).replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function buildHighlightedTextFragment(text, keyword) {
  const fragment = document.createDocumentFragment();
  const rawText = String(text ?? "");
  const safeKeyword = String(keyword ?? "").trim();
  if (!safeKeyword) {
    fragment.append(document.createTextNode(rawText));
    return fragment;
  }

  const matcher = new RegExp(escapeRegex(safeKeyword), "gi");
  let cursor = 0;
  let matched = matcher.exec(rawText);
  while (matched) {
    const start = matched.index;
    const end = start + matched[0].length;
    if (start > cursor) {
      fragment.append(document.createTextNode(rawText.slice(cursor, start)));
    }
    const mark = document.createElement("mark");
    mark.className = "notice-highlight";
    mark.textContent = rawText.slice(start, end);
    fragment.append(mark);
    cursor = end;
    if (matcher.lastIndex === matched.index) matcher.lastIndex += 1;
    matched = matcher.exec(rawText);
  }

  if (cursor < rawText.length) {
    fragment.append(document.createTextNode(rawText.slice(cursor)));
  }
  return fragment;
}

function setHighlightedText(target, text, keyword) {
  if (!target) return;
  target.textContent = "";
  target.append(buildHighlightedTextFragment(text, keyword));
}

function loadStoredSearchKeyword(storeKey) {
  try {
    return normalizeSearchKeyword(localStorage.getItem(storeKey) || "");
  } catch {
    return "";
  }
}

function normalizeSearchKeyword(rawKeyword) {
  return String(rawKeyword ?? "").replace(/\s+/g, " ").trim();
}

function resolveAppUrl(rawPath, fallbackBase = "") {
  const safePath = String(rawPath || "").trim();
  if (!safePath) return "";
  if (/^[a-z][a-z0-9+.-]*:/i.test(safePath)) return safePath;

  const baseCandidates = [];
  const safeFallbackBase = String(fallbackBase || "").trim();
  if (safeFallbackBase) baseCandidates.push(safeFallbackBase);
  const safeDocumentBase = typeof document !== "undefined" ? String(document.baseURI || "").trim() : "";
  if (safeDocumentBase) baseCandidates.push(safeDocumentBase);
  const safeWindowHref = typeof window !== "undefined" ? String(window.location?.href || "").trim() : "";
  if (safeWindowHref) baseCandidates.push(safeWindowHref);
  const safeWindowOrigin = typeof window !== "undefined" ? String(window.location?.origin || "").trim() : "";
  if (safeWindowOrigin && safeWindowOrigin !== "null") baseCandidates.push(`${safeWindowOrigin}/`);

  for (const base of baseCandidates) {
    try {
      return new URL(safePath, base).toString();
    } catch {
      // Try next candidate base.
    }
  }
  return safePath;
}

function createDebouncedFunction(callback, waitMs = VIEW_SEARCH_DEBOUNCE_MS) {
  let timerId = null;
  return (...args) => {
    if (timerId) window.clearTimeout(timerId);
    timerId = window.setTimeout(() => {
      timerId = null;
      callback(...args);
    }, waitMs);
  };
}

function getViewSearchStoreKey(view) {
  if (view === "recommend") return VIEW_SEARCH_RECOMMEND_STORE_KEY;
  if (view === "internal") return VIEW_SEARCH_INTERNAL_STORE_KEY;
  if (view === "local") return VIEW_SEARCH_LOCAL_STORE_KEY;
  return "";
}

function getViewSearchElements(view) {
  if (view === "recommend") {
    return {
      bar: recommendSearchBar,
      input: recommendSearchInput,
      clear: recommendSearchClear,
      meta: recommendSearchMeta,
    };
  }
  if (view === "internal") {
    return {
      bar: internalSearchBar,
      input: internalSearchInput,
      clear: internalSearchClear,
      meta: internalSearchMeta,
    };
  }
  if (view === "local") {
    return {
      bar: localSearchBar,
      input: localSearchInput,
      clear: localSearchClear,
      meta: localSearchMeta,
    };
  }
  return { bar: null, input: null, clear: null, meta: null };
}

function getViewSearchKeyword(view) {
  if (view === "recommend" || view === "internal" || view === "local") {
    return viewSearchState[view] || "";
  }
  return "";
}

function setViewSearchMetaText(view, text) {
  const { meta } = getViewSearchElements(view);
  if (!meta) return;
  meta.textContent = text || "";
}

function syncViewSearchInputValue(view) {
  const { input } = getViewSearchElements(view);
  if (!input) return;
  input.value = getViewSearchKeyword(view);
}

function syncViewSearchClearButton(view) {
  const { input, clear } = getViewSearchElements(view);
  if (!clear) return;
  const keyword = normalizeSearchKeyword(input?.value || getViewSearchKeyword(view));
  clear.disabled = !keyword;
}

function persistViewSearchKeyword(view) {
  const storeKey = getViewSearchStoreKey(view);
  if (!storeKey) return;
  try {
    localStorage.setItem(storeKey, getViewSearchKeyword(view));
  } catch {
    // Ignore storage write failure and keep runtime behavior available.
  }
}

function setViewSearchKeyword(view, rawKeyword, options = {}) {
  const safeView = view === "internal" || view === "local" ? view : "recommend";
  const keyword = normalizeSearchKeyword(rawKeyword);
  const shouldSyncInput = options.syncInput === true;
  const shouldRefresh = options.refresh !== false;
  viewSearchState[safeView] = keyword;
  persistViewSearchKeyword(safeView);
  if (shouldSyncInput) syncViewSearchInputValue(safeView);
  syncViewSearchClearButton(safeView);
  if (!shouldRefresh) return;
  if (safeView === "recommend") {
    renderRecommendGroups(recommendState.groups, "recommend");
  } else if (safeView === "internal") {
    renderRecommendGroups(internalState.groups, "internal");
  } else if (safeView === "local") {
    renderLocalShortcuts();
  }
}

