function portalSearchReadStorage(key, fallback = "") {
  try {
    const stored = localStorage.getItem(key);
    return stored == null ? fallback : stored;
  } catch {
    return fallback;
  }
}

function portalSearchWriteStorage(key, value) {
  try {
    localStorage.setItem(key, value);
  } catch {
    // Ignore storage write failure to keep runtime available.
  }
}

function portalSearchCanUseSettings() {
  const username = String(notesState.account?.username || "").trim();
  return Boolean(notesState.authenticated && username);
}

function getPortalSearchCustomEnginesStorageKey(username = notesState.account?.username) {
  const normalized = normalizeNotesUsernameKey(username);
  if (!normalized) return "";
  return `${PORTAL_SEARCH_STORAGE_KEYS.customEngines}::${encodeURIComponent(normalized)}`;
}

function migratePortalSearchCustomEnginesNamespaceStorage(previousUsername, nextUsername) {
  const oldKey = getPortalSearchCustomEnginesStorageKey(previousUsername);
  const nextKey = getPortalSearchCustomEnginesStorageKey(nextUsername);
  if (!oldKey || !nextKey || oldKey === nextKey) return;
  try {
    const payload = localStorage.getItem(oldKey);
    if (!payload) return;
    localStorage.setItem(nextKey, payload);
    localStorage.removeItem(oldKey);
  } catch {
    // Ignore migration failures to avoid blocking username updates.
  }
}

function portalSearchMigrateLegacyCustomEnginesStorageForUser(username = notesState.account?.username) {
  const namespacedKey = getPortalSearchCustomEnginesStorageKey(username);
  if (!namespacedKey) return;
  const namespacedPayload = portalSearchReadStorage(namespacedKey, "");
  if (namespacedPayload) return;
  const legacyPayload = portalSearchReadStorage(PORTAL_SEARCH_STORAGE_KEYS.customEngines, "");
  if (!legacyPayload) return;
  portalSearchWriteStorage(namespacedKey, legacyPayload);
  try {
    localStorage.removeItem(PORTAL_SEARCH_STORAGE_KEYS.customEngines);
  } catch {
    // Ignore legacy key cleanup failures.
  }
}

function portalSearchRequestSettingsAuth() {
  if (portalSearchCanUseSettings()) return;
  openNotesAuthModal({ mode: notesState.accounts.length > 0 ? "login" : "register" });
}

function portalSearchSyncSettingsAccess(options = {}) {
  const force = Boolean(options.force);
  const canUseSettings = portalSearchCanUseSettings();
  const currentUsernameKey = canUseSettings ? normalizeNotesUsernameKey(notesState.account?.username || "") : "";
  const authUserChanged = portalSearchState.settingsAuthUserKey !== currentUsernameKey;
  if (authUserChanged) {
    portalSearchState.settingsAuthUserKey = currentUsernameKey;
  }
  const settingsButton = portalSearchById("portalSearchOpenSettings");
  if (settingsButton) settingsButton.hidden = !canUseSettings;

  if (!canUseSettings) {
    portalSearchCloseSettings();
    portalSearchState.customEngines = [];
    if (String(portalSearchState.currentEngine || "").startsWith("custom_")) {
      portalSearchState.currentEngine = PORTAL_SEARCH_PRESET_ENGINES[0].id;
      portalSearchWriteStorage(PORTAL_SEARCH_STORAGE_KEYS.currentEngine, portalSearchState.currentEngine);
    }
  } else if (authUserChanged || force) {
    portalSearchLoadCustomEngines();
  }

  if (!portalSearchState.initialized && !force) return;
  if (!force && !authUserChanged) return;
  portalSearchEnsureCurrentEngine();
  portalSearchRenderEngineSelector();
  portalSearchRenderActiveContext();
  portalSearchRenderSettings();
}

function portalSearchById(id) {
  return document.getElementById(id);
}

function portalSearchEscapeHtml(value) {
  return String(value)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

function portalSearchTokenize(value) {
  return String(value || "")
    .split(/[\s,]+/)
    .map((item) => item.trim().toLowerCase())
    .filter(Boolean);
}

function portalSearchEscapeRegExp(value) {
  return String(value || "").replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function portalSearchNormalizeHighlightTokens(tokens) {
  return Array.from(
    new Set(
      (Array.isArray(tokens) ? tokens : [])
        .map((token) => String(token || "").trim())
        .filter((token) => token && token.length <= 64)
    )
  ).sort((a, b) => b.length - a.length);
}

function portalSearchHighlightText(value, tokens) {
  const rawText = String(value || "");
  if (!rawText) return "";
  const normalizedTokens = portalSearchNormalizeHighlightTokens(tokens);
  if (!normalizedTokens.length) return portalSearchEscapeHtml(rawText);
  const pattern = normalizedTokens.map((token) => portalSearchEscapeRegExp(token)).join("|");
  if (!pattern) return portalSearchEscapeHtml(rawText);
  const regex = new RegExp(pattern, "gi");
  let lastIndex = 0;
  let html = "";
  rawText.replace(regex, (match, offset) => {
    const safeOffset = Number(offset) || 0;
    if (safeOffset > lastIndex) {
      html += portalSearchEscapeHtml(rawText.slice(lastIndex, safeOffset));
    }
    html += `<mark class="portal-search-result-highlight">${portalSearchEscapeHtml(match)}</mark>`;
    lastIndex = safeOffset + match.length;
    return match;
  });
  if (lastIndex < rawText.length) {
    html += portalSearchEscapeHtml(rawText.slice(lastIndex));
  }
  return html;
}

function portalSearchGetExtension(fileName) {
  const parts = String(fileName || "").toLowerCase().split(".");
  return parts.length > 1 ? parts.pop() : "";
}

function portalSearchBuildDocumentParseStatus(guard) {
  const succeeded = Math.max(0, Number(guard?.documentParsedCount) || 0);
  const failed = Math.max(0, Number(guard?.documentParseFailedCount) || 0);
  const skipped = Math.max(0, Number(guard?.documentParseSkippedCount) || 0);
  if (succeeded + failed + skipped <= 0) return "";
  const details = [`文档解析成功 ${succeeded}`];
  if (failed > 0) details.push(`失败 ${failed}`);
  if (skipped > 0) details.push(`跳过 ${skipped}`);
  return `，${details.join(" / ")}`;
}

function portalSearchWrapPromiseWithTimeout(taskPromise, timeoutMs, options = {}) {
  const safeTimeoutMs = Number.isFinite(Number(timeoutMs)) ? Math.max(1000, Math.floor(Number(timeoutMs))) : 30000;
  const timeoutMessage = String(options.message || "操作超时");
  const timeoutCode = String(options.code || "TIMEOUT");
  let timerId = 0;
  const timeoutPromise = new Promise((_, reject) => {
    timerId = window.setTimeout(() => {
      const error = new Error(timeoutMessage);
      error.code = timeoutCode;
      reject(error);
    }, safeTimeoutMs);
  });
  return Promise.race([Promise.resolve(taskPromise), timeoutPromise]).finally(() => {
    if (timerId) window.clearTimeout(timerId);
  });
}

function portalSearchLoadRuntimeScript(url, options = {}) {
  const safeUrl = String(url || "").trim();
  if (!safeUrl) {
    return Promise.reject(new Error("脚本地址为空"));
  }
  const isReady = typeof options.isReady === "function" ? options.isReady : () => false;
  if (isReady()) return Promise.resolve();
  const cached = portalSearchRuntimeScriptPromises.get(safeUrl);
  if (cached) return cached;

  const promise = new Promise((resolve, reject) => {
    if (typeof document === "undefined") {
      reject(new Error("当前环境不支持动态脚本加载"));
      return;
    }
    const script = document.createElement("script");
    script.src = safeUrl;
    script.async = true;
    script.defer = true;
    script.crossOrigin = "anonymous";
    script.setAttribute("data-portal-runtime", safeUrl);
    script.onload = () => {
      if (!isReady()) {
        reject(new Error(`脚本加载成功但运行时不可用：${safeUrl}`));
        return;
      }
      resolve();
    };
    script.onerror = () => {
      reject(new Error(`脚本加载失败：${safeUrl}`));
    };
    document.head.append(script);
  })
    .catch((error) => {
      portalSearchRuntimeScriptPromises.delete(safeUrl);
      throw error;
    })
    .then(() => {
      return undefined;
    });

  portalSearchRuntimeScriptPromises.set(safeUrl, promise);
  return promise;
}

async function portalSearchEnsurePdfJsRuntime() {
  await portalSearchLoadRuntimeScript(PORTAL_SEARCH_PDFJS_SCRIPT_URL, {
    isReady: () => Boolean(window.pdfjsLib && typeof window.pdfjsLib.getDocument === "function"),
  });
  if (window.pdfjsLib?.GlobalWorkerOptions) {
    window.pdfjsLib.GlobalWorkerOptions.workerSrc = PORTAL_SEARCH_PDFJS_WORKER_URL;
  }
}

async function portalSearchEnsureTesseractRuntime() {
  await portalSearchLoadRuntimeScript(PORTAL_SEARCH_TESSERACT_SCRIPT_URL, {
    isReady: () => Boolean(window.Tesseract && typeof window.Tesseract.recognize === "function"),
  });
}

function portalSearchExtractPdfTextFromTextContent(textContent) {
  if (!Array.isArray(textContent?.items)) return "";
  const chunks = textContent.items
    .map((item) => String(item?.str || "").replace(/\s+/g, " ").trim())
    .filter(Boolean);
  if (!chunks.length) return "";
  return chunks.join(" ");
}

async function portalSearchRecognizePdfCanvasText(canvas) {
  await portalSearchEnsureTesseractRuntime();
  const recognizer = window.Tesseract;
  if (!recognizer || typeof recognizer.recognize !== "function") {
    const error = new Error("网页 OCR 运行时不可用");
    error.code = "PDF_OCR_RUNTIME_UNAVAILABLE";
    throw error;
  }
  const languages = [];
  const primary = String(PORTAL_SEARCH_PDF_OCR_PRIMARY_LANG || "").trim();
  const fallback = String(PORTAL_SEARCH_PDF_OCR_FALLBACK_LANG || "").trim();
  if (primary) languages.push(primary);
  if (fallback && fallback !== primary) languages.push(fallback);
  if (!languages.length) languages.push("eng");

  let lastError = null;
  for (const lang of languages) {
    try {
      const result = await portalSearchWrapPromiseWithTimeout(
        recognizer.recognize(canvas, lang, {
          logger: () => {
            // Ignore per-page OCR logs to keep console clean.
          },
        }),
        PORTAL_SEARCH_PDF_OCR_PAGE_TIMEOUT_MS,
        {
          code: "PDF_OCR_TIMEOUT",
          message: "PDF OCR 页面识别超时",
        }
      );
      const text = normalizeVaultSearchCorpusText(String(result?.data?.text || ""));
      if (text) return text;
    } catch (error) {
      lastError = error;
    }
  }
  if (lastError) throw lastError;
  return "";
}

async function portalSearchExtractPdfTextByWebRuntime(file) {
  if (!(file instanceof Blob)) return "";
  await portalSearchEnsurePdfJsRuntime();
  const pdfjsLib = window.pdfjsLib;
  if (!pdfjsLib || typeof pdfjsLib.getDocument !== "function") {
    const error = new Error("PDF 解析运行时不可用");
    error.code = "PDF_WEB_PARSE_UNAVAILABLE";
    throw error;
  }

  const arrayBuffer = await file.arrayBuffer();
  const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
  let pdfDocument = null;
  try {
    pdfDocument = await portalSearchWrapPromiseWithTimeout(loadingTask.promise, PORTAL_SEARCH_PDF_WEB_PARSE_TIMEOUT_MS, {
      code: "PDF_WEB_PARSE_TIMEOUT",
      message: "PDF 网页解析超时",
    });
    const totalPages = Number(pdfDocument?.numPages) || 0;
    if (totalPages <= 0) return "";
    const pageLimit = Math.min(totalPages, PORTAL_SEARCH_PDF_WEB_PARSE_MAX_PAGES);
    const allowOcr = file.size <= PORTAL_SEARCH_PDF_OCR_MAX_FILE_BYTES;
    const ocrPageLimit = Math.min(pageLimit, PORTAL_SEARCH_PDF_OCR_MAX_PAGES);
    let ocrPageCount = 0;
    let combinedLength = 0;
    const textChunks = [];

    for (let pageIndex = 1; pageIndex <= pageLimit; pageIndex += 1) {
      const page = await pdfDocument.getPage(pageIndex);
      let pageText = "";
      try {
        const textContent = await page.getTextContent({ normalizeWhitespace: true });
        pageText = portalSearchExtractPdfTextFromTextContent(textContent);
      } catch {
        pageText = "";
      }

      if (pageText) {
        textChunks.push(pageText);
        combinedLength += pageText.length;
      } else if (allowOcr && ocrPageCount < ocrPageLimit) {
        if (!portalSearchState.pdfWebOcrNoticeShown) {
          portalSearchState.pdfWebOcrNoticeShown = true;
          portalSearchSetNotice("检测到扫描版 PDF，正在使用网页 OCR 提取文本（速度较慢）。", {
            tone: "info",
            durationMs: 4200,
          });
        }
        const canvas = document.createElement("canvas");
        let context = null;
        try {
          let viewport = page.getViewport({ scale: PORTAL_SEARCH_PDF_OCR_RENDER_SCALE });
          const currentPixels = Math.max(1, viewport.width * viewport.height);
          if (currentPixels > PORTAL_SEARCH_PDF_OCR_MAX_PIXELS) {
            const shrinkRatio = Math.sqrt(PORTAL_SEARCH_PDF_OCR_MAX_PIXELS / currentPixels);
            viewport = page.getViewport({ scale: PORTAL_SEARCH_PDF_OCR_RENDER_SCALE * shrinkRatio });
          }
          canvas.width = Math.max(1, Math.floor(viewport.width));
          canvas.height = Math.max(1, Math.floor(viewport.height));
          context = canvas.getContext("2d", { alpha: false });
          if (!context) throw new Error("无法初始化 OCR 画布");
          await page.render({ canvasContext: context, viewport }).promise;
          const ocrText = await portalSearchRecognizePdfCanvasText(canvas);
          if (ocrText) {
            textChunks.push(ocrText);
            combinedLength += ocrText.length;
          }
          ocrPageCount += 1;
        } finally {
          canvas.width = 1;
          canvas.height = 1;
          if (context && typeof context.clearRect === "function") {
            context.clearRect(0, 0, 1, 1);
          }
        }
      }

      if (combinedLength >= PORTAL_SEARCH_MAX_TEXT_CHARS * 2) {
        break;
      }
    }

    const mergedText = normalizeVaultSearchCorpusText(textChunks.join("\n\n"));
    if (!mergedText) return "";
    return mergedText.length > PORTAL_SEARCH_MAX_TEXT_CHARS ? mergedText.slice(0, PORTAL_SEARCH_MAX_TEXT_CHARS) : mergedText;
  } finally {
    try {
      if (loadingTask && typeof loadingTask.destroy === "function") {
        await loadingTask.destroy();
      }
    } catch {
      // Ignore PDF loading task destroy failures.
    }
    try {
      if (pdfDocument && typeof pdfDocument.cleanup === "function") {
        pdfDocument.cleanup();
      }
    } catch {
      // Ignore cleanup failures.
    }
    try {
      if (pdfDocument && typeof pdfDocument.destroy === "function") {
        await pdfDocument.destroy();
      }
    } catch {
      // Ignore document destroy failures.
    }
  }
}

async function portalSearchExtractDocumentText(file, extension) {
  if (!(file instanceof Blob)) return "";
  const safeExtension = String(extension || "").trim().toLowerCase();
  if (!PORTAL_SEARCH_DOCUMENT_EXTENSIONS.has(safeExtension)) return "";
  if (safeExtension === "pdf") {
    try {
      return await portalSearchExtractPdfTextByWebRuntime(file);
    } catch (error) {
      if (!portalSearchState.pdfWebRuntimeUnavailableNoticeShown) {
        portalSearchState.pdfWebRuntimeUnavailableNoticeShown = true;
        portalSearchSetNotice("PDF 网页解析/OCR 运行时加载失败，请检查网络后重试索引。", {
          tone: "info",
          durationMs: 4600,
        });
      }
      if (!error?.code) {
        error.code = "PDF_WEB_PARSE_FAILED";
      }
      throw error;
    }
  }
  if (portalSearchState.documentParseEndpointUnavailable) return "";
  if ((Number(file.size) || 0) <= 0) return "";
  if (Number(file.size) > PORTAL_SEARCH_MAX_DOCUMENT_FILE_BYTES) {
    const error = new Error(`文档体积超出限制（>${portalSearchFormatBytes(PORTAL_SEARCH_MAX_DOCUMENT_FILE_BYTES)}）`);
    error.code = "DOCUMENT_TOO_LARGE";
    throw error;
  }

  const mimeType = normalizeVaultFileMimeType(file.type, file.name);
  const fileName = String(file.name || "").trim() || `document.${safeExtension}`;
  const requestUrl = new URL(resolveAppUrl(AI_API_ATTACHMENT_PARSE_URL));
  requestUrl.searchParams.set("name", fileName);
  requestUrl.searchParams.set("type", String(mimeType || "").trim().toLowerCase());
  requestUrl.searchParams.set("includeImages", "0");

  const controller = typeof AbortController === "function" ? new AbortController() : null;
  const timeoutId =
    controller &&
    window.setTimeout(() => {
      controller.abort();
    }, PORTAL_SEARCH_DOCUMENT_PARSE_TIMEOUT_MS);

  try {
    try {
      const response = await fetch(requestUrl.toString(), {
        method: "POST",
        headers: {
          "Content-Type": "application/octet-stream",
        },
        body: file,
        signal: controller?.signal,
        cache: "no-store",
      });

      const raw = await response.text();
      let payload = null;
      try {
        payload = raw ? JSON.parse(raw) : {};
      } catch {
        payload = null;
      }

      if (!response.ok) {
        if (response.status === 404 || response.status === 405) {
          portalSearchState.documentParseEndpointUnavailable = true;
          if (!portalSearchState.documentParseUnavailableNoticeShown) {
            portalSearchState.documentParseUnavailableNoticeShown = true;
            portalSearchSetNotice("当前服务未启用文档解析接口，Office 文档将仅索引名称和路径。", {
              tone: "info",
              durationMs: 4600,
            });
          }
          const error = new Error("文档解析接口不可用");
          error.code = "DOCUMENT_PARSE_UNAVAILABLE";
          throw error;
        }
        const message = String(payload?.error || payload?.message || raw || `文档解析失败（${response.status}）`).trim();
        const error = new Error(message || "文档解析失败");
        error.code = "DOCUMENT_PARSE_FAILED";
        throw error;
      }

      const extractedText = normalizeVaultSearchCorpusText(String(payload?.text || "").replace(/\u0000/g, ""));
      if (!extractedText) return "";
      if (extractedText.length > PORTAL_SEARCH_MAX_TEXT_CHARS) {
        return extractedText.slice(0, PORTAL_SEARCH_MAX_TEXT_CHARS);
      }
      return extractedText;
    } catch (error) {
      if (error?.name === "AbortError") {
        const timeoutError = new Error("文档解析超时");
        timeoutError.code = "DOCUMENT_PARSE_TIMEOUT";
        throw timeoutError;
      }
      if (error?.code) throw error;
      portalSearchState.documentParseEndpointUnavailable = true;
      if (!portalSearchState.documentParseUnavailableNoticeShown) {
        portalSearchState.documentParseUnavailableNoticeShown = true;
        portalSearchSetNotice("文档解析服务当前不可用，Office 文档将仅索引名称和路径。", {
          tone: "info",
          durationMs: 4600,
        });
      }
      const unavailableError = new Error("文档解析服务不可用");
      unavailableError.code = "DOCUMENT_PARSE_UNAVAILABLE";
      throw unavailableError;
    }
  } finally {
    if (timeoutId) window.clearTimeout(timeoutId);
  }
}

function portalSearchFormatBytes(size) {
  const safeSize = Number(size) || 0;
  if (safeSize < 1024) return `${safeSize} B`;
  if (safeSize < 1024 * 1024) return `${(safeSize / 1024).toFixed(1)} KB`;
  if (safeSize < 1024 * 1024 * 1024) return `${(safeSize / (1024 * 1024)).toFixed(1)} MB`;
  return `${(safeSize / (1024 * 1024 * 1024)).toFixed(1)} GB`;
}

function portalSearchFormatTime(timestamp) {
  const date = new Date(timestamp || Date.now());
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, "0");
  const day = String(date.getDate()).padStart(2, "0");
  const hour = String(date.getHours()).padStart(2, "0");
  const minute = String(date.getMinutes()).padStart(2, "0");
  return `${year}-${month}-${day} ${hour}:${minute}`;
}

function portalSearchFormatDurationMs(durationMs) {
  const safeMs = Math.max(0, Number(durationMs) || 0);
  const totalSeconds = Math.floor(safeMs / 1000);
  if (totalSeconds < 60) return `${totalSeconds} 秒`;
  const minutes = Math.floor(totalSeconds / 60);
  const seconds = totalSeconds % 60;
  if (minutes < 60) return `${minutes} 分 ${String(seconds).padStart(2, "0")} 秒`;
  const hours = Math.floor(minutes / 60);
  const remainMinutes = minutes % 60;
  return `${hours} 小时 ${String(remainMinutes).padStart(2, "0")} 分`;
}

function portalSearchFormatSiteCountValue(value) {
  const count = Number(value);
  if (!Number.isFinite(count) || count < 0) return "--";
  return String(Math.max(0, Math.floor(count)));
}

function portalSearchSetNotice(message, options = {}) {
  const node = portalSearchById("portalSearchNotice");
  if (!node) return;
  const text = String(message || "").trim();
  const tone = options.tone === "error" ? "error" : options.tone === "success" ? "success" : "info";
  const autoHide = options.autoHide !== false;
  const durationRaw = Number(options.durationMs);
  const durationMs = Number.isFinite(durationRaw) ? Math.max(1200, durationRaw) : 3600;

  if (portalSearchState.noticeTimerId) {
    window.clearTimeout(portalSearchState.noticeTimerId);
    portalSearchState.noticeTimerId = null;
  }

  if (!text) {
    node.hidden = true;
    node.textContent = "";
    node.classList.remove("is-info", "is-success", "is-error");
    node.removeAttribute("role");
    return;
  }

  node.hidden = false;
  node.textContent = text;
  node.classList.remove("is-info", "is-success", "is-error");
  node.classList.add(`is-${tone}`);
  node.setAttribute("role", tone === "error" ? "alert" : "status");

  if (!autoHide) return;
  portalSearchState.noticeTimerId = window.setTimeout(() => {
    if (node.textContent !== text) return;
    portalSearchSetNotice("");
  }, durationMs);
}

function portalSearchRenderActiveContext() {
  const node = portalSearchById("portalSearchActiveContext");
  if (!node) return;
  const isLocalMode = portalSearchState.currentMode === "local";
  node.dataset.mode = isLocalMode ? "local" : "web";
  if (isLocalMode) {
    node.textContent = "当前模式：本地搜索 · 当前引擎：本地模式无需引擎";
    return;
  }
  const allEngines = portalSearchGetAllEngines();
  const current = allEngines.find((engine) => engine.id === portalSearchState.currentEngine) || allEngines[0] || PORTAL_SEARCH_PRESET_ENGINES[0];
  node.textContent = `当前模式：网络搜索 · 当前引擎：${current?.name || PORTAL_SEARCH_PRESET_ENGINES[0].name}`;
}

function portalSearchRenderSiteStats(stats = portalSearchState.siteStats, options = {}) {
  const internalNode = portalSearchById("portalSearchSiteInternalCount");
  const recommendNode = portalSearchById("portalSearchSiteRecommendCount");
  const tutorialNode = portalSearchById("portalSearchSiteTutorialCount");
  const metaNode = portalSearchById("portalSearchSiteMeta");
  if (internalNode) internalNode.textContent = portalSearchFormatSiteCountValue(stats?.internal);
  if (recommendNode) recommendNode.textContent = portalSearchFormatSiteCountValue(stats?.recommend);
  if (tutorialNode) tutorialNode.textContent = portalSearchFormatSiteCountValue(stats?.tutorial);
  if (metaNode) {
    if (options.loading) {
      metaNode.textContent = "统计加载中...";
    } else if (options.error) {
      metaNode.textContent = "统计读取失败，已回退默认值";
    } else if (Number(stats?.updatedAt) > 0) {
      metaNode.textContent = `更新于 ${portalSearchFormatTime(stats.updatedAt)}`;
    } else {
      metaNode.textContent = "等待统计数据";
    }
  }
}

async function portalSearchFetchRecommendGroupItemCount(url, groups, loaded, fallbackGroups) {
  if (loaded) return countRecommendItems(groups);
  try {
    const response = await fetch(url, { cache: "no-store" });
    if (!response.ok) throw new Error(`读取失败（${response.status}）`);
    const payload = await response.json();
    const parsedGroups = normalizeRecommendGroups(parseRecommendGroupsPayload(payload));
    if (parsedGroups.length > 0) return countRecommendItems(parsedGroups);
  } catch {
    // Ignore and fallback below.
  }
  const fallback = Array.isArray(groups) && groups.length ? groups : fallbackGroups;
  return countRecommendItems(fallback);
}

async function portalSearchFetchTutorialDocumentCount() {
  if (tutorialState.loaded) return Array.isArray(tutorialState.documents) ? tutorialState.documents.length : 0;
  try {
    const docs = await discoverTutorialFilesFromApi();
    return Array.isArray(docs) ? docs.length : 0;
  } catch {
    return Array.isArray(tutorialState.documents) ? tutorialState.documents.length : 0;
  }
}

async function portalSearchLoadSiteStats(forceReload = false) {
  if (portalSearchState.siteStatsLoading) return portalSearchState.siteStatsPromise || Promise.resolve();
  if (!forceReload && Number(portalSearchState.siteStats.updatedAt) > 0) {
    portalSearchRenderSiteStats(portalSearchState.siteStats);
    return;
  }

  portalSearchState.siteStatsLoading = true;
  portalSearchRenderSiteStats(portalSearchState.siteStats, { loading: true });
  portalSearchState.siteStatsPromise = Promise.all([
    portalSearchFetchRecommendGroupItemCount(
      INTERNAL_DATA_URL,
      internalState.groups,
      internalState.loaded,
      DEFAULT_INTERNAL_GROUPS
    ),
    portalSearchFetchRecommendGroupItemCount(
      RECOMMEND_DATA_URL,
      recommendState.groups,
      recommendState.loaded,
      DEFAULT_RECOMMEND_GROUPS
    ),
    portalSearchFetchTutorialDocumentCount(),
  ])
    .then(([internalCount, recommendCount, tutorialCount]) => {
      portalSearchState.siteStats = {
        internal: internalCount,
        recommend: recommendCount,
        tutorial: tutorialCount,
        updatedAt: Date.now(),
      };
      portalSearchRenderSiteStats(portalSearchState.siteStats);
    })
    .catch(() => {
      portalSearchState.siteStats = {
        internal: countRecommendItems(internalState.groups.length ? internalState.groups : DEFAULT_INTERNAL_GROUPS),
        recommend: countRecommendItems(recommendState.groups.length ? recommendState.groups : DEFAULT_RECOMMEND_GROUPS),
        tutorial: Array.isArray(tutorialState.documents) ? tutorialState.documents.length : 0,
        updatedAt: Date.now(),
      };
      portalSearchRenderSiteStats(portalSearchState.siteStats, { error: true });
    })
    .finally(() => {
      portalSearchState.siteStatsLoading = false;
      portalSearchState.siteStatsPromise = null;
    });
  return portalSearchState.siteStatsPromise;
}

function portalSearchCreateCosmosStars(width, height, count) {
  const stars = [];
  const safeCount = Math.max(0, Math.floor(Number(count) || 0));
  for (let i = 0; i < safeCount; i += 1) {
    stars.push({
      x: Math.random() * width,
      y: Math.random() * height,
      size: 0.55 + Math.random() * 1.6,
      alpha: 0.24 + Math.random() * 0.6,
      twinkle: 0.6 + Math.random() * 2.4,
      phase: Math.random() * Math.PI * 2,
      vx: (Math.random() - 0.5) * 0.025,
      vy: 0.01 + Math.random() * 0.055,
    });
  }
  return stars;
}

function portalSearchCreateCosmosGlobePoints(count) {
  const points = [];
  const safeCount = Math.max(12, Math.floor(Number(count) || 0));
  const offset = 2 / safeCount;
  const increment = Math.PI * (3 - Math.sqrt(5));
  for (let i = 0; i < safeCount; i += 1) {
    const y = i * offset - 1 + offset / 2;
    const radius = Math.sqrt(Math.max(0, 1 - y * y));
    const phi = i * increment;
    points.push({
      x: Math.cos(phi) * radius,
      y,
      z: Math.sin(phi) * radius,
      size: 0.45 + Math.random() * 1.15,
      phase: Math.random() * Math.PI * 2,
    });
  }
  return points;
}

function portalSearchCreateCosmosOrbitParticles(count) {
  const particles = [];
  const safeCount = Math.max(6, Math.floor(Number(count) || 0));
  for (let i = 0; i < safeCount; i += 1) {
    particles.push({
      orbit: 1.08 + Math.random() * 0.96,
      ellipse: 0.08 + Math.random() * 0.28,
      angle: Math.random() * Math.PI * 2,
      speed: (0.16 + Math.random() * 0.52) * (Math.random() > 0.5 ? 1 : -1),
      size: 0.8 + Math.random() * 1.7,
      alpha: 0.26 + Math.random() * 0.45,
    });
  }
  return particles;
}

function portalSearchSeedCosmosRuntime() {
  const runtime = portalSearchState.cosmos;
  const width = Math.max(320, Number(runtime.width) || 0);
  const height = Math.max(180, Number(runtime.height) || 0);
  const areaDensity = Math.max(0.72, Math.min(1.6, (width * height) / (980 * 360)));
  const compactDensity = width < 760 ? 0.76 : 1;
  const motionDensity = runtime.reducedMotion ? 0.58 : 1;
  const starCount = Math.max(40, Math.round(128 * areaDensity * compactDensity * motionDensity));
  const globeCount = Math.max(170, Math.round(520 * areaDensity * compactDensity * motionDensity));
  const orbitCount = Math.max(18, Math.round(58 * areaDensity * compactDensity * motionDensity));
  runtime.stars = portalSearchCreateCosmosStars(width, height, starCount);
  runtime.globePoints = portalSearchCreateCosmosGlobePoints(globeCount);
  runtime.orbitParticles = portalSearchCreateCosmosOrbitParticles(orbitCount);
}

function portalSearchResizeCosmosCanvas(forceReseed = false) {
  const runtime = portalSearchState.cosmos;
  const panel = runtime.panel;
  const canvas = runtime.canvas;
  if (!(panel instanceof HTMLElement) || !(canvas instanceof HTMLCanvasElement)) return;
  const rect = panel.getBoundingClientRect();
  const width = Math.max(280, Math.floor(rect.width));
  const height = Math.max(180, Math.floor(rect.height));
  const dpr = Math.min(PORTAL_SEARCH_COSMOS_MAX_PIXEL_RATIO, window.devicePixelRatio || 1);
  const pixelWidth = Math.max(1, Math.floor(width * dpr));
  const pixelHeight = Math.max(1, Math.floor(height * dpr));
  const sizeChanged = runtime.width !== width || runtime.height !== height || runtime.dpr !== dpr;
  if (canvas.width !== pixelWidth) canvas.width = pixelWidth;
  if (canvas.height !== pixelHeight) canvas.height = pixelHeight;
  runtime.width = width;
  runtime.height = height;
  runtime.dpr = dpr;
  if (!runtime.context) {
    runtime.context = canvas.getContext("2d");
  }
  if (!runtime.context) return;
  runtime.context.setTransform(dpr, 0, 0, dpr, 0, 0);
  runtime.context.imageSmoothingEnabled = true;
  portalSearchConstrainCosmosPan();
  if (sizeChanged || forceReseed || runtime.stars.length === 0 || runtime.globePoints.length === 0) {
    portalSearchSeedCosmosRuntime();
  }
}

function portalSearchRequestCosmosResize(forceReseed = false) {
  const runtime = portalSearchState.cosmos;
  if (runtime.resizeTimerId) {
    window.clearTimeout(runtime.resizeTimerId);
    runtime.resizeTimerId = 0;
  }
  runtime.resizeTimerId = window.setTimeout(() => {
    runtime.resizeTimerId = 0;
    portalSearchResizeCosmosCanvas(forceReseed);
  }, PORTAL_SEARCH_COSMOS_RESIZE_DEBOUNCE_MS);
}

function portalSearchClampCosmosValue(value, min, max) {
  const safe = Number.isFinite(value) ? value : min;
  return Math.min(max, Math.max(min, safe));
}

function portalSearchGetCosmosViewMetrics() {
  const runtime = portalSearchState.cosmos;
  const width = Math.max(0, Number(runtime.width) || 0);
  const height = Math.max(0, Number(runtime.height) || 0);
  if (width <= 0 || height <= 0) return null;
  const minZoom = Number(runtime.minZoom) || PORTAL_SEARCH_COSMOS_ZOOM_MIN;
  const maxZoom = Number(runtime.maxZoom) || PORTAL_SEARCH_COSMOS_ZOOM_MAX;
  const zoom = portalSearchClampCosmosValue(Number(runtime.zoom) || 1, minZoom, maxZoom);
  runtime.zoom = zoom;
  const baseX = width * 0.5;
  const baseY = height * 0.52;
  const baseRadius = Math.min(width * 0.15, height * 0.27);
  const maxRadiusByWidth = Math.max(20, (width * 0.5 - 8) / 2.15);
  const maxRadiusByHeight = Math.max(20, (height * 0.5 - 8) / 1.82);
  const earthRadius = Math.max(18, Math.min(baseRadius * zoom, maxRadiusByWidth, maxRadiusByHeight));
  const extentX = earthRadius * 2.15 + 4;
  const extentY = earthRadius * 1.82 + 4;
  return { width, height, baseX, baseY, earthRadius, extentX, extentY };
}

function portalSearchConstrainCosmosPan() {
  const runtime = portalSearchState.cosmos;
  const metrics = portalSearchGetCosmosViewMetrics();
  if (!metrics) return null;

  const minCenterX = metrics.extentX;
  const maxCenterX = metrics.width - metrics.extentX;
  const minCenterY = metrics.extentY;
  const maxCenterY = metrics.height - metrics.extentY;

  if (maxCenterX <= minCenterX) {
    runtime.panX = 0;
  } else {
    const centerX = metrics.baseX + (Number(runtime.panX) || 0);
    const clampedCenterX = Math.min(maxCenterX, Math.max(minCenterX, centerX));
    runtime.panX = clampedCenterX - metrics.baseX;
  }

  if (maxCenterY <= minCenterY) {
    runtime.panY = 0;
  } else {
    const centerY = metrics.baseY + (Number(runtime.panY) || 0);
    const clampedCenterY = Math.min(maxCenterY, Math.max(minCenterY, centerY));
    runtime.panY = clampedCenterY - metrics.baseY;
  }

  return {
    ...metrics,
    earthX: metrics.baseX + runtime.panX,
    earthY: metrics.baseY + runtime.panY,
  };
}

function portalSearchSetCosmosZoom(nextZoom, pivotX, pivotY) {
  const runtime = portalSearchState.cosmos;
  const minZoom = Number(runtime.minZoom) || PORTAL_SEARCH_COSMOS_ZOOM_MIN;
  const maxZoom = Number(runtime.maxZoom) || PORTAL_SEARCH_COSMOS_ZOOM_MAX;
  const previousZoom = portalSearchClampCosmosValue(Number(runtime.zoom) || 1, minZoom, maxZoom);
  const safeNextZoom = portalSearchClampCosmosValue(Number(nextZoom), minZoom, maxZoom);
  if (!Number.isFinite(safeNextZoom)) return;

  const pointerX = Number(pivotX);
  const pointerY = Number(pivotY);
  if (
    Number.isFinite(pointerX) &&
    Number.isFinite(pointerY) &&
    previousZoom > 0 &&
    safeNextZoom !== previousZoom &&
    runtime.width > 0 &&
    runtime.height > 0
  ) {
    const currentCenterX = runtime.width * 0.5 + (Number(runtime.panX) || 0);
    const currentCenterY = runtime.height * 0.52 + (Number(runtime.panY) || 0);
    const ratio = safeNextZoom / previousZoom;
    runtime.panX -= (pointerX - currentCenterX) * (ratio - 1);
    runtime.panY -= (pointerY - currentCenterY) * (ratio - 1);
  }

  runtime.zoom = safeNextZoom;
  portalSearchConstrainCosmosPan();
}

function portalSearchGetCosmosPalette() {
  const isDarkTheme = String(state.theme || body?.dataset?.theme || "").toLowerCase() === "dark";
  if (isDarkTheme) {
    return {
      isDarkTheme: true,
      backgroundA: "#041022",
      backgroundB: "#09244a",
      backgroundC: "#020915",
      star: "rgb(178 220 255)",
      earthOuterGlow: "rgba(44, 145, 255, 0.36)",
      earthInnerGlow: "rgba(71, 192, 255, 0.28)",
      earthCoreA: "#1d68cf",
      earthCoreB: "#2cb0f8",
      earthRim: "rgba(139, 214, 255, 0.6)",
      earthPointFront: "rgb(126 231 255)",
      earthPointBack: "rgb(87 143 214)",
      ring: "rgba(129, 204, 255, 0.36)",
      orbitParticle: "rgb(140 218 255)",
      starAlphaBoost: 1,
      orbitAlphaBoost: 1,
      pointAlphaBoost: 1,
      orbitSizeBoost: 1,
      ringAlpha: 0.36,
    };
  }
  return {
    isDarkTheme: false,
    backgroundA: "#061b38",
    backgroundB: "#0a2f59",
    backgroundC: "#061226",
    star: "rgb(36 123 226)",
    earthOuterGlow: "rgba(17, 116, 228, 0.52)",
    earthInnerGlow: "rgba(83, 208, 255, 0.3)",
    earthCoreA: "#2a7ee0",
    earthCoreB: "#38bff7",
    earthRim: "rgba(83, 178, 243, 0.82)",
    earthPointFront: "rgb(98 208 255)",
    earthPointBack: "rgb(39 111 198)",
    ring: "rgba(42, 144, 234, 0.6)",
    orbitParticle: "rgb(6 115 225)",
    starAlphaBoost: 1.48,
    orbitAlphaBoost: 1.62,
    pointAlphaBoost: 1.2,
    orbitSizeBoost: 1.16,
    ringAlpha: 0.58,
  };
}

function portalSearchDrawCosmosScene(deltaSeconds = 0) {
  const runtime = portalSearchState.cosmos;
  const context = runtime.context;
  if (!context || runtime.width <= 0 || runtime.height <= 0) return;

  const width = runtime.width;
  const height = runtime.height;
  const motionFactor = runtime.reducedMotion ? 0.36 : 1;
  const deltaScale = deltaSeconds > 0 ? deltaSeconds * 60 * motionFactor : 0;
  const palette = portalSearchGetCosmosPalette();
  const isDarkTheme = palette.isDarkTheme !== false;
  const starAlphaBoost = Number(palette.starAlphaBoost) || 1;
  const orbitAlphaBoost = Number(palette.orbitAlphaBoost) || 1;
  const pointAlphaBoost = Number(palette.pointAlphaBoost) || 1;
  const orbitSizeBoost = Number(palette.orbitSizeBoost) || 1;
  const ringAlpha = Number(palette.ringAlpha) || 0.36;
  const starAlphaFloor = isDarkTheme ? 0.08 : 0.2;
  const orbitAlphaFloor = isDarkTheme ? 0.2 : 0.34;
  const pointAlphaFloor = isDarkTheme ? 0.08 : 0.14;

  context.setTransform(runtime.dpr, 0, 0, runtime.dpr, 0, 0);
  context.clearRect(0, 0, width, height);

  runtime.stars.forEach((star) => {
    star.x += star.vx * deltaScale;
    star.y += star.vy * deltaScale;
    if (star.x < -4) star.x = width + 4;
    else if (star.x > width + 4) star.x = -4;
    if (star.y > height + 4) star.y = -4;
    const twinkle = 0.64 + 0.36 * Math.sin(runtime.time * star.twinkle + star.phase);
    context.globalAlpha = Math.max(starAlphaFloor, Math.min(0.98, star.alpha * twinkle * starAlphaBoost));
    context.fillStyle = palette.star;
    context.beginPath();
    context.arc(star.x, star.y, star.size, 0, Math.PI * 2);
    context.fill();
  });
  context.globalAlpha = 1;

  const view = portalSearchConstrainCosmosPan();
  if (!view) return;
  const earthX = view.earthX;
  const earthY = view.earthY;
  const earthRadius = view.earthRadius;

  const outerGlow = context.createRadialGradient(earthX, earthY, earthRadius * 0.45, earthX, earthY, earthRadius * 1.72);
  outerGlow.addColorStop(0, palette.earthOuterGlow);
  outerGlow.addColorStop(0.62, palette.earthInnerGlow);
  outerGlow.addColorStop(1, "rgba(0,0,0,0)");
  context.fillStyle = outerGlow;
  context.beginPath();
  context.arc(earthX, earthY, earthRadius * 1.7, 0, Math.PI * 2);
  context.fill();

  context.save();
  context.translate(earthX, earthY);
  context.rotate(-0.32 + Math.sin(runtime.time * 0.18) * 0.08);
  context.strokeStyle = palette.ring;
  context.globalAlpha = ringAlpha;
  context.lineWidth = 1;
  context.setLineDash([6, 8]);
  for (let i = 0; i < 3; i += 1) {
    const ringRadiusX = earthRadius * (1.22 + i * 0.2);
    const ringRadiusY = earthRadius * (0.34 + i * 0.08);
    context.beginPath();
    context.ellipse(0, 0, ringRadiusX, ringRadiusY, 0, 0, Math.PI * 2);
    context.stroke();
  }
  context.restore();
  context.setLineDash([]);
  context.globalAlpha = 1;

  runtime.orbitParticles.forEach((particle) => {
    particle.angle += particle.speed * deltaSeconds * motionFactor * 0.46;
    const orbitRadiusX = earthRadius * particle.orbit;
    const orbitRadiusY = earthRadius * (0.24 + particle.ellipse);
    const x = earthX + Math.cos(particle.angle) * orbitRadiusX;
    const y = earthY + Math.sin(particle.angle + runtime.time * 0.12) * orbitRadiusY;
    context.globalAlpha = Math.max(orbitAlphaFloor, Math.min(0.98, particle.alpha * orbitAlphaBoost));
    context.fillStyle = palette.orbitParticle;
    context.beginPath();
    context.arc(x, y, particle.size * orbitSizeBoost, 0, Math.PI * 2);
    context.fill();
  });
  context.globalAlpha = 1;

  const sphereGradient = context.createRadialGradient(
    earthX - earthRadius * 0.3,
    earthY - earthRadius * 0.42,
    earthRadius * 0.12,
    earthX,
    earthY,
    earthRadius * 1.04
  );
  sphereGradient.addColorStop(0, palette.earthCoreB);
  sphereGradient.addColorStop(1, palette.earthCoreA);
  context.fillStyle = sphereGradient;
  context.beginPath();
  context.arc(earthX, earthY, earthRadius, 0, Math.PI * 2);
  context.fill();
  context.strokeStyle = palette.earthRim;
  context.lineWidth = 1.2;
  context.stroke();

  const spin = runtime.time * (runtime.reducedMotion ? 0.07 : 0.18);
  const sinSpin = Math.sin(spin);
  const cosSpin = Math.cos(spin);
  const tilt = 0.55;
  const sinTilt = Math.sin(tilt);
  const cosTilt = Math.cos(tilt);

  runtime.globePoints.forEach((point) => {
    const rotatedX = point.x * cosSpin + point.z * sinSpin;
    const rotatedZ = -point.x * sinSpin + point.z * cosSpin;
    const wobbleY = point.y + Math.sin(runtime.time * 0.42 + point.phase) * 0.03;
    const tiltedY = wobbleY * cosTilt - rotatedZ * sinTilt;
    const tiltedZ = wobbleY * sinTilt + rotatedZ * cosTilt;
    const depth = (tiltedZ + 1) * 0.5;
    const perspective = 0.72 + depth * 0.46;
    const x = earthX + rotatedX * earthRadius * perspective;
    const y = earthY + tiltedY * earthRadius * perspective;
    const size = point.size * (0.56 + depth * 1.24);
    const alpha = Math.max(
      pointAlphaFloor,
      Math.min(0.98, (0.18 + depth * 0.82) * (runtime.reducedMotion ? 0.82 : 1) * pointAlphaBoost)
    );
    context.globalAlpha = alpha;
    context.fillStyle = depth >= 0.5 ? palette.earthPointFront : palette.earthPointBack;
    context.beginPath();
    context.arc(x, y, size, 0, Math.PI * 2);
    context.fill();
  });
  context.globalAlpha = 1;
}

function portalSearchShouldAnimateCosmos() {
  const runtime = portalSearchState.cosmos;
  if (!runtime.initialized) return false;
  if (!(runtime.panel instanceof HTMLElement) || runtime.panel.hidden) return false;
  if (!(runtime.canvas instanceof HTMLCanvasElement)) return false;
  if (state.mainView !== "search") return false;
  if (document.visibilityState !== "visible") return false;
  return true;
}

function portalSearchCosmosTick(timestamp) {
  const runtime = portalSearchState.cosmos;
  if (!runtime.running) return;
  if (!portalSearchShouldAnimateCosmos()) {
    portalSearchStopCosmosAnimation();
    return;
  }
  if (!runtime.lastFrameTs) runtime.lastFrameTs = timestamp;
  const deltaMs = Math.max(8, Math.min(40, timestamp - runtime.lastFrameTs));
  runtime.lastFrameTs = timestamp;
  runtime.time += deltaMs / 1000;
  portalSearchDrawCosmosScene(deltaMs / 1000);
  runtime.frameId = window.requestAnimationFrame(portalSearchCosmosTick);
}

function portalSearchStartCosmosAnimation() {
  const runtime = portalSearchState.cosmos;
  if (runtime.running) return;
  portalSearchResizeCosmosCanvas();
  runtime.running = true;
  runtime.lastFrameTs = 0;
  runtime.frameId = window.requestAnimationFrame(portalSearchCosmosTick);
}

function portalSearchStopCosmosAnimation() {
  const runtime = portalSearchState.cosmos;
  runtime.running = false;
  runtime.lastFrameTs = 0;
  runtime.dragging = false;
  runtime.dragPointerId = null;
  if (runtime.canvas instanceof HTMLCanvasElement) {
    runtime.canvas.classList.remove("is-dragging");
  }
  if (runtime.frameId) {
    window.cancelAnimationFrame(runtime.frameId);
    runtime.frameId = 0;
  }
}

function portalSearchInitializeCosmosPanel() {
  const runtime = portalSearchState.cosmos;
  const panel = portalSearchById("portalSearchCosmosPanel");
  const canvas = portalSearchById("portalSearchCosmosCanvas");
  if (!(panel instanceof HTMLElement) || !(canvas instanceof HTMLCanvasElement)) {
    portalSearchStopCosmosAnimation();
    return;
  }

  runtime.panel = panel;
  runtime.canvas = canvas;
  if (!runtime.context) runtime.context = canvas.getContext("2d");
  if (!runtime.context) return;

  if (!runtime.motionBound && typeof window.matchMedia === "function") {
    runtime.mediaQuery = window.matchMedia("(prefers-reduced-motion: reduce)");
    runtime.reducedMotion = Boolean(runtime.mediaQuery.matches);
    runtime.mediaQueryHandler = () => {
      runtime.reducedMotion = Boolean(runtime.mediaQuery?.matches);
      portalSearchResizeCosmosCanvas(true);
      portalSearchSyncCosmosAnimation();
    };
    if (typeof runtime.mediaQuery.addEventListener === "function") {
      runtime.mediaQuery.addEventListener("change", runtime.mediaQueryHandler);
    } else if (typeof runtime.mediaQuery.addListener === "function") {
      runtime.mediaQuery.addListener(runtime.mediaQueryHandler);
    }
    runtime.motionBound = true;
  }

  if (!runtime.visibilityBound) {
    runtime.visibilityHandler = () => {
      portalSearchSyncCosmosAnimation();
    };
    document.addEventListener("visibilitychange", runtime.visibilityHandler);
    runtime.visibilityBound = true;
  }

  if (!runtime.resizeBound) {
    runtime.resizeHandler = () => {
      portalSearchRequestCosmosResize();
    };
    window.addEventListener("resize", runtime.resizeHandler);
    runtime.resizeBound = true;
  }

  if (!runtime.interactionBound) {
    runtime.wheelHandler = (event) => {
      if (!(runtime.canvas instanceof HTMLCanvasElement) || runtime.panel?.hidden) return;
      let deltaY = Number(event.deltaY) || 0;
      const deltaMode = Number(event.deltaMode) || 0;
      if (deltaMode === 1) deltaY *= 16;
      else if (deltaMode === 2) deltaY *= Math.max(180, runtime.height || 0);
      if (!Number.isFinite(deltaY) || deltaY === 0) return;
      event.preventDefault();
      const rect = runtime.canvas.getBoundingClientRect();
      const pivotX = event.clientX - rect.left;
      const pivotY = event.clientY - rect.top;
      const factor = Math.exp(-deltaY * PORTAL_SEARCH_COSMOS_WHEEL_SENSITIVITY);
      const nextZoom = (Number(runtime.zoom) || 1) * factor;
      portalSearchSetCosmosZoom(nextZoom, pivotX, pivotY);
      if (!runtime.running) portalSearchDrawCosmosScene(0);
    };

    const finishDrag = (event) => {
      if (!runtime.dragging) return;
      if (
        event &&
        Number.isFinite(event.pointerId) &&
        runtime.dragPointerId != null &&
        event.pointerId !== runtime.dragPointerId
      ) {
        return;
      }
      const activePointerId = runtime.dragPointerId;
      runtime.dragging = false;
      runtime.dragPointerId = null;
      if (runtime.canvas instanceof HTMLCanvasElement) {
        runtime.canvas.classList.remove("is-dragging");
        if (activePointerId != null && typeof runtime.canvas.releasePointerCapture === "function") {
          try {
            runtime.canvas.releasePointerCapture(activePointerId);
          } catch {
            // Ignore releasePointerCapture failure when capture is already released.
          }
        }
      }
      if (!runtime.running) portalSearchDrawCosmosScene(0);
    };

    runtime.pointerDownHandler = (event) => {
      if (event.button !== 0) return;
      if (!(runtime.canvas instanceof HTMLCanvasElement)) return;
      runtime.dragging = true;
      runtime.dragPointerId = event.pointerId;
      runtime.dragStartX = event.clientX;
      runtime.dragStartY = event.clientY;
      runtime.panStartX = Number(runtime.panX) || 0;
      runtime.panStartY = Number(runtime.panY) || 0;
      runtime.canvas.classList.add("is-dragging");
      if (typeof runtime.canvas.setPointerCapture === "function") {
        try {
          runtime.canvas.setPointerCapture(event.pointerId);
        } catch {
          // Ignore setPointerCapture failure when pointer capture is unavailable.
        }
      }
      event.preventDefault();
    };

    runtime.pointerMoveHandler = (event) => {
      if (!runtime.dragging) return;
      if (runtime.dragPointerId != null && event.pointerId !== runtime.dragPointerId) return;
      runtime.panX = runtime.panStartX + (event.clientX - runtime.dragStartX);
      runtime.panY = runtime.panStartY + (event.clientY - runtime.dragStartY);
      portalSearchConstrainCosmosPan();
      if (!runtime.running) portalSearchDrawCosmosScene(0);
      event.preventDefault();
    };

    runtime.pointerUpHandler = (event) => {
      finishDrag(event);
    };

    runtime.pointerCancelHandler = (event) => {
      finishDrag(event);
    };

    runtime.pointerLeaveHandler = (event) => {
      if (!runtime.dragging) return;
      if (event.buttons === 0) finishDrag(event);
    };

    canvas.addEventListener("wheel", runtime.wheelHandler, { passive: false });
    canvas.addEventListener("pointerdown", runtime.pointerDownHandler);
    canvas.addEventListener("pointermove", runtime.pointerMoveHandler);
    canvas.addEventListener("pointerup", runtime.pointerUpHandler);
    canvas.addEventListener("pointercancel", runtime.pointerCancelHandler);
    canvas.addEventListener("lostpointercapture", runtime.pointerCancelHandler);
    canvas.addEventListener("pointerleave", runtime.pointerLeaveHandler);
    runtime.interactionBound = true;
  }

  runtime.initialized = true;
  portalSearchResizeCosmosCanvas(runtime.globePoints.length === 0 || runtime.stars.length === 0);
}

function portalSearchSyncCosmosAnimation() {
  portalSearchInitializeCosmosPanel();
  if (!portalSearchShouldAnimateCosmos()) {
    portalSearchStopCosmosAnimation();
    return;
  }
  portalSearchStartCosmosAnimation();
}

function portalSearchRenderSitePanelVisibility() {
  const panel = portalSearchById("portalSearchSitePanel");
  const cosmosPanel = portalSearchById("portalSearchCosmosPanel");
  if (!panel) {
    if (cosmosPanel) cosmosPanel.hidden = true;
    portalSearchStopCosmosAnimation();
    return;
  }
  const shouldShow = portalSearchState.currentMode === "web";
  panel.hidden = !shouldShow;
  if (cosmosPanel) cosmosPanel.hidden = !shouldShow;
  if (shouldShow) void portalSearchLoadSiteStats();
  portalSearchSyncCosmosAnimation();
}

function openPortalSearchDb() {
  return new Promise((resolve, reject) => {
    if (typeof indexedDB === "undefined") {
      reject(new Error("浏览器不支持 IndexedDB"));
      return;
    }
    const request = indexedDB.open(PORTAL_SEARCH_DB_NAME, PORTAL_SEARCH_DB_VERSION);
    request.onupgradeneeded = () => {
      const db = request.result;
      if (!db.objectStoreNames.contains(PORTAL_SEARCH_DB_INDEX_STORE)) {
        db.createObjectStore(PORTAL_SEARCH_DB_INDEX_STORE, { keyPath: "id" });
      }
      if (!db.objectStoreNames.contains(PORTAL_SEARCH_DB_META_STORE)) {
        db.createObjectStore(PORTAL_SEARCH_DB_META_STORE, { keyPath: "id" });
      }
    };
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error || new Error("本地索引数据库打开失败"));
  });
}

function portalSearchDbRequest(request) {
  return new Promise((resolve, reject) => {
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error || new Error("本地索引数据库请求失败"));
  });
}

function portalSearchDbTxDone(tx) {
  return new Promise((resolve, reject) => {
    tx.oncomplete = () => resolve();
    tx.onerror = () => reject(tx.error || new Error("本地索引数据库事务失败"));
    tx.onabort = () => reject(tx.error || new Error("本地索引数据库事务已中断"));
  });
}

async function portalSearchGetDb() {
  if (!portalSearchState.dbPromise) {
    portalSearchState.dbPromise = openPortalSearchDb().catch((error) => {
      portalSearchState.dbPromise = null;
      throw error;
    });
  }
  return portalSearchState.dbPromise;
}

function portalSearchNormalizePathSeparators(path) {
  return String(path || "").replaceAll("\\", "/").replace(/\/+/g, "/");
}

function portalSearchDeriveRelativePath(path, rootName = "") {
  const safePath = portalSearchNormalizePathSeparators(path).replace(/^\/+/, "");
  if (!safePath) return "";
  const safeRoot = String(rootName || "").trim();
  if (safeRoot) {
    if (safePath === safeRoot) return "";
    if (safePath.startsWith(`${safeRoot}/`)) return safePath.slice(safeRoot.length + 1);
  }
  const parts = safePath.split("/").filter(Boolean);
  if (parts.length <= 1) return parts[0] || "";
  return parts.slice(1).join("/");
}

function portalSearchBuildLocalIndexEntry(payload, options = {}) {
  const rootName = String(options.rootName || "").trim();
  const name = String(payload?.name || "").trim() || "未命名文件";
  const path = portalSearchNormalizePathSeparators(String(payload?.path || name)).replace(/^\/+/, "");
  const relativePathRaw = portalSearchNormalizePathSeparators(String(payload?.relativePath || "")).replace(/^\/+/, "");
  const relativePath = relativePathRaw || portalSearchDeriveRelativePath(path, rootName);
  const extension = String(payload?.extension || portalSearchGetExtension(name)).trim().toLowerCase();
  const size = Math.max(0, Number(payload?.size) || 0);
  const modified = Number(payload?.modified) || Date.now();
  const text = typeof payload?.text === "string" ? payload.text : "";
  const id = String(payload?.id || "").trim() || path.toLowerCase();
  const file = payload?.file instanceof Blob ? payload.file : null;
  return {
    id,
    name,
    path,
    relativePath,
    extension,
    size,
    modified,
    text,
    textLower: text.toLowerCase(),
    nameLower: name.toLowerCase(),
    pathLower: path.toLowerCase(),
    file,
  };
}

function portalSearchSerializeLocalIndexEntry(item) {
  const normalized = portalSearchBuildLocalIndexEntry(item, {
    rootName: portalSearchState.selectedRootName || "",
  });
  return {
    id: normalized.id,
    name: normalized.name,
    path: normalized.path,
    relativePath: normalized.relativePath,
    extension: normalized.extension,
    size: normalized.size,
    modified: normalized.modified,
    text: normalized.text,
  };
}

async function portalSearchPersistLocalIndexSnapshot(options = {}) {
  const items = Array.isArray(options.items) ? options.items : [];
  const rootName = String(options.rootName || "").trim();
  const directoryHandle =
    options.directoryHandle && typeof options.directoryHandle.values === "function" ? options.directoryHandle : null;
  const textCount = Math.max(0, Number(options.textCount) || 0);
  const scannedCount = Math.max(0, Number(options.scannedCount) || 0);
  const searchableCount = Math.max(0, Number(options.searchableCount) || 0);
  const textDirectSuccessCount = Math.max(0, Number(options.textDirectSuccessCount) || 0);
  const documentParsedCount = Math.max(0, Number(options.documentParsedCount) || 0);
  const documentParseFailedCount = Math.max(0, Number(options.documentParseFailedCount) || 0);
  const documentParseSkippedCount = Math.max(0, Number(options.documentParseSkippedCount) || 0);
  const unsupportedTypeCount = Math.max(0, Number(options.unsupportedTypeCount) || 0);
  const oversizeSkippedCount = Math.max(0, Number(options.oversizeSkippedCount) || 0);
  const readFailedCount = Math.max(0, Number(options.readFailedCount) || 0);
  const textParseSkippedCount = Math.max(0, Number(options.textParseSkippedCount) || 0);
  const documentParseFailedFiles = portalSearchNormalizeIndexReportDetailList(options.documentParseFailedFiles, {
    maxItems: PORTAL_SEARCH_INDEX_DETAIL_MAX_ITEMS,
  });
  const oversizeSkippedFiles = portalSearchNormalizeIndexReportDetailList(options.oversizeSkippedFiles, {
    maxItems: PORTAL_SEARCH_INDEX_DETAIL_MAX_ITEMS,
  });
  const readFailedFiles = portalSearchNormalizeIndexReportDetailList(options.readFailedFiles, {
    maxItems: PORTAL_SEARCH_INDEX_DETAIL_MAX_ITEMS,
  });
  const db = await portalSearchGetDb();
  const updatedAt = Date.now();
  const tx = db.transaction([PORTAL_SEARCH_DB_INDEX_STORE, PORTAL_SEARCH_DB_META_STORE], "readwrite");
  const indexStore = tx.objectStore(PORTAL_SEARCH_DB_INDEX_STORE);
  const metaStore = tx.objectStore(PORTAL_SEARCH_DB_META_STORE);
  indexStore.clear();
  items.forEach((entry) => {
    indexStore.put(portalSearchSerializeLocalIndexEntry(entry));
  });
  metaStore.put({
    id: PORTAL_SEARCH_DB_META_KEYS.snapshot,
    updatedAt,
    rootName,
    count: items.length,
    textCount,
    scannedCount,
    searchableCount,
    textDirectSuccessCount,
    documentParsedCount,
    documentParseFailedCount,
    documentParseSkippedCount,
    unsupportedTypeCount,
    oversizeSkippedCount,
    readFailedCount,
    textParseSkippedCount,
    documentParseFailedFiles,
    oversizeSkippedFiles,
    readFailedFiles,
  });
  await portalSearchDbTxDone(tx);

  // Save directory handle in a separate transaction so handle serialization failures
  // never roll back the already persisted index snapshot.
  try {
    const handleTx = db.transaction(PORTAL_SEARCH_DB_META_STORE, "readwrite");
    handleTx.objectStore(PORTAL_SEARCH_DB_META_STORE).put({
      id: PORTAL_SEARCH_DB_META_KEYS.directory,
      rootName,
      handle: directoryHandle,
    });
    await portalSearchDbTxDone(handleTx);
  } catch {
    try {
      const fallbackTx = db.transaction(PORTAL_SEARCH_DB_META_STORE, "readwrite");
      fallbackTx.objectStore(PORTAL_SEARCH_DB_META_STORE).put({
        id: PORTAL_SEARCH_DB_META_KEYS.directory,
        rootName,
        handle: null,
      });
      await portalSearchDbTxDone(fallbackTx);
    } catch {
      // Ignore fallback persistence failures.
    }
  }
  return updatedAt;
}

async function portalSearchLoadPersistedLocalSnapshot() {
  const db = await portalSearchGetDb();
  const tx = db.transaction([PORTAL_SEARCH_DB_INDEX_STORE, PORTAL_SEARCH_DB_META_STORE], "readonly");
  const indexStore = tx.objectStore(PORTAL_SEARCH_DB_INDEX_STORE);
  const metaStore = tx.objectStore(PORTAL_SEARCH_DB_META_STORE);
  const [snapshotMeta, directoryMeta, rawItems] = await Promise.all([
    portalSearchDbRequest(metaStore.get(PORTAL_SEARCH_DB_META_KEYS.snapshot)),
    portalSearchDbRequest(metaStore.get(PORTAL_SEARCH_DB_META_KEYS.directory)),
    portalSearchDbRequest(indexStore.getAll()),
  ]);
  await portalSearchDbTxDone(tx);
  const hasSnapshot = Boolean(snapshotMeta || directoryMeta || (Array.isArray(rawItems) && rawItems.length));
  if (!hasSnapshot) return null;
  const rootName = String(snapshotMeta?.rootName || directoryMeta?.rootName || "").trim();
  const items = (Array.isArray(rawItems) ? rawItems : [])
    .map((entry) => portalSearchBuildLocalIndexEntry(entry, { rootName }))
    .filter((entry) => Boolean(entry.path));
  const updatedAt = Number(snapshotMeta?.updatedAt) || Date.now();
  const textCount = Number(snapshotMeta?.textCount) || items.filter((entry) => Boolean(entry.text)).length;
  const count = Number(snapshotMeta?.count);
  const hasIndexReport =
    snapshotMeta &&
    [
      "scannedCount",
      "searchableCount",
      "textDirectSuccessCount",
      "documentParsedCount",
      "documentParseFailedCount",
      "documentParseSkippedCount",
      "unsupportedTypeCount",
      "oversizeSkippedCount",
      "readFailedCount",
      "textParseSkippedCount",
      "documentParseFailedFiles",
      "oversizeSkippedFiles",
      "readFailedFiles",
    ].some((key) => key in snapshotMeta);
  const scannedCount = Number(snapshotMeta?.scannedCount);
  const searchableCount = Number(snapshotMeta?.searchableCount);
  const textDirectSuccessCount = Number(snapshotMeta?.textDirectSuccessCount);
  const documentParsedCount = Number(snapshotMeta?.documentParsedCount);
  const documentParseFailedCount = Number(snapshotMeta?.documentParseFailedCount);
  const documentParseSkippedCount = Number(snapshotMeta?.documentParseSkippedCount);
  const unsupportedTypeCount = Number(snapshotMeta?.unsupportedTypeCount);
  const oversizeSkippedCount = Number(snapshotMeta?.oversizeSkippedCount);
  const readFailedCount = Number(snapshotMeta?.readFailedCount);
  const textParseSkippedCount = Number(snapshotMeta?.textParseSkippedCount);
  const documentParseFailedFiles = portalSearchNormalizeIndexReportDetailList(snapshotMeta?.documentParseFailedFiles, {
    maxItems: PORTAL_SEARCH_INDEX_DETAIL_MAX_ITEMS,
  });
  const oversizeSkippedFiles = portalSearchNormalizeIndexReportDetailList(snapshotMeta?.oversizeSkippedFiles, {
    maxItems: PORTAL_SEARCH_INDEX_DETAIL_MAX_ITEMS,
  });
  const readFailedFiles = portalSearchNormalizeIndexReportDetailList(snapshotMeta?.readFailedFiles, {
    maxItems: PORTAL_SEARCH_INDEX_DETAIL_MAX_ITEMS,
  });
  return {
    rootName,
    updatedAt,
    textCount,
    count: Number.isFinite(count) ? count : items.length,
    hasIndexReport: Boolean(hasIndexReport),
    scannedCount: Number.isFinite(scannedCount) ? Math.max(0, Math.floor(scannedCount)) : null,
    searchableCount: Number.isFinite(searchableCount) ? Math.max(0, Math.floor(searchableCount)) : null,
    textDirectSuccessCount: Number.isFinite(textDirectSuccessCount) ? Math.max(0, Math.floor(textDirectSuccessCount)) : null,
    documentParsedCount: Number.isFinite(documentParsedCount) ? Math.max(0, Math.floor(documentParsedCount)) : null,
    documentParseFailedCount: Number.isFinite(documentParseFailedCount) ? Math.max(0, Math.floor(documentParseFailedCount)) : null,
    documentParseSkippedCount: Number.isFinite(documentParseSkippedCount) ? Math.max(0, Math.floor(documentParseSkippedCount)) : null,
    unsupportedTypeCount: Number.isFinite(unsupportedTypeCount) ? Math.max(0, Math.floor(unsupportedTypeCount)) : null,
    oversizeSkippedCount: Number.isFinite(oversizeSkippedCount) ? Math.max(0, Math.floor(oversizeSkippedCount)) : null,
    readFailedCount: Number.isFinite(readFailedCount) ? Math.max(0, Math.floor(readFailedCount)) : null,
    textParseSkippedCount: Number.isFinite(textParseSkippedCount) ? Math.max(0, Math.floor(textParseSkippedCount)) : null,
    documentParseFailedFiles,
    oversizeSkippedFiles,
    readFailedFiles,
    directoryHandle: directoryMeta?.handle || null,
    items,
  };
}

async function portalSearchQueryDirectoryPermission(handle) {
  if (!handle) return false;
  if (typeof handle.queryPermission !== "function") return true;
  try {
    const permission = await handle.queryPermission({ mode: "read" });
    return permission === "granted";
  } catch {
    return false;
  }
}

function portalSearchGetResultRelativePathForDirectory(item) {
  const direct = portalSearchNormalizePathSeparators(String(item?.relativePath || "")).replace(/^\/+/, "");
  if (direct) return direct;
  const fullPath = portalSearchNormalizePathSeparators(String(item?.path || "")).replace(/^\/+/, "");
  if (!fullPath) return "";
  const rootName = String(portalSearchState.selectedRootName || portalSearchState.directoryHandle?.name || "").trim();
  return portalSearchDeriveRelativePath(fullPath, rootName);
}

async function portalSearchResolveResultFileHandleFromDirectory(item) {
  const directoryHandle = portalSearchState.directoryHandle;
  if (!directoryHandle || typeof directoryHandle.getFileHandle !== "function") return null;
  const relativePath = portalSearchGetResultRelativePathForDirectory(item);
  const segments = relativePath
    .split("/")
    .map((part) => part.trim())
    .filter(Boolean);
  if (!segments.length) return null;
  let cursor = directoryHandle;
  for (let i = 0; i < segments.length - 1; i += 1) {
    if (!cursor || typeof cursor.getDirectoryHandle !== "function") return null;
    cursor = await cursor.getDirectoryHandle(segments[i]);
  }
  if (!cursor || typeof cursor.getFileHandle !== "function") return null;
  return await cursor.getFileHandle(segments[segments.length - 1]);
}

async function portalSearchClearPersistedLocalSnapshot() {
  const db = await portalSearchGetDb();
  const tx = db.transaction([PORTAL_SEARCH_DB_INDEX_STORE, PORTAL_SEARCH_DB_META_STORE], "readwrite");
  tx.objectStore(PORTAL_SEARCH_DB_INDEX_STORE).clear();
  const metaStore = tx.objectStore(PORTAL_SEARCH_DB_META_STORE);
  metaStore.delete(PORTAL_SEARCH_DB_META_KEYS.snapshot);
  metaStore.delete(PORTAL_SEARCH_DB_META_KEYS.directory);
  await portalSearchDbTxDone(tx);
}

async function portalSearchGetFileForResultItem(item) {
  if (item?.file instanceof Blob) {
    return item.file;
  }
  const key = String(item?.pathLower || item?.path || "").trim().toLowerCase();
  if (key) {
    const cachedFile = portalSearchState.selectedFilesByPath.get(key);
    if (cachedFile instanceof Blob) {
      if (item && typeof item === "object") item.file = cachedFile;
      return cachedFile;
    }
  }
  if (portalSearchState.directoryHandle && typeof portalSearchState.directoryHandle.values === "function") {
    const granted = await portalSearchQueryDirectoryPermission(portalSearchState.directoryHandle);
    if (!granted) {
      throw new Error("当前目录授权未就绪，请点击“选择文件夹并索引”重新确认后再预览。");
    }
    try {
      const fileHandle = await portalSearchResolveResultFileHandleFromDirectory(item);
      if (!fileHandle || typeof fileHandle.getFile !== "function") {
        throw new Error("文件句柄不可用");
      }
      const file = await fileHandle.getFile();
      if (!(file instanceof Blob)) {
        throw new Error("文件对象不可用");
      }
      if (item && typeof item === "object") item.file = file;
      if (key) {
        portalSearchState.selectedFilesByPath.set(key, file);
      }
      return file;
    } catch {
      throw new Error("无法从当前目录读取该文件。请确认文件未移动，并点击“重新索引”。");
    }
  }
  throw new Error("当前仅保留历史索引文本缓存。请先“选择文件夹并索引”或“重新索引”后再预览。");
}

async function portalSearchRestorePersistedLocalState() {
  if (!portalSearchState.supportsEnhancedLocal) return;
  const reindexButton = portalSearchById("portalSearchReindexBtn");
  const cancelButton = portalSearchById("portalSearchCancelIndexBtn");
  const clearIndexButton = portalSearchById("portalSearchClearIndexBtn");
  portalSearchState.directoryHandle = null;
  portalSearchState.selectedFilesByPath = new Map();
  portalSearchState.selectedRootName = "";
  portalSearchUpdateLocalStatus("正在加载历史索引...");
  portalSearchSetIndexReport({
    note: "正在加载历史索引...",
  });
  if (cancelButton) cancelButton.disabled = true;
  try {
    const snapshot = await portalSearchLoadPersistedLocalSnapshot();
    if (!snapshot) {
      portalSearchSetProgress(0);
      portalSearchUpdateLocalStatus("尚未选择文件夹");
      portalSearchSetIndexReport({
        note: "暂无历史索引",
      });
      if (reindexButton) reindexButton.disabled = false;
      if (clearIndexButton) clearIndexButton.disabled = true;
      return;
    }

    portalSearchState.localIndex = snapshot.items;
    portalSearchState.localResults = [];
    portalSearchState.selectedRootName = String(snapshot.rootName || "").trim();
    portalSearchState.directoryHandle =
      snapshot.directoryHandle && typeof snapshot.directoryHandle.values === "function" ? snapshot.directoryHandle : null;
    const hasDirectoryHandle = Boolean(portalSearchState.directoryHandle);
    const hasDirectoryPermission = hasDirectoryHandle
      ? await portalSearchQueryDirectoryPermission(portalSearchState.directoryHandle)
      : false;
    if (snapshot.items.length > 0) {
      portalSearchSetProgress(100);
      const base = `已加载历史索引：${snapshot.items.length} 个文件（${portalSearchFormatTime(snapshot.updatedAt)}）`;
      if (hasDirectoryHandle && hasDirectoryPermission) {
        portalSearchUpdateLocalStatus(`${base}，可直接预览文件并“重新索引”当前目录。`);
      } else if (hasDirectoryHandle) {
        portalSearchUpdateLocalStatus(`${base}，目录授权未就绪，请点击“选择文件夹并索引”重新确认。`);
      } else {
        portalSearchUpdateLocalStatus(`${base}，当前仅恢复历史索引文本，重新索引前请先选择文件夹。`);
      }
      if (snapshot.hasIndexReport) {
        const parseSkipped =
          (Number(snapshot.documentParseSkippedCount) || 0) +
          (Number(snapshot.textParseSkippedCount) || 0) +
          (Number(snapshot.unsupportedTypeCount) || 0);
        portalSearchSetIndexReport({
          scanned: snapshot.scannedCount,
          indexed: snapshot.count,
          searchable: snapshot.searchableCount,
          textSuccess: snapshot.textDirectSuccessCount,
          docSuccess: snapshot.documentParsedCount,
          failed: snapshot.documentParseFailedCount,
          skipped: parseSkipped,
          unsupported: snapshot.unsupportedTypeCount,
          oversize: snapshot.oversizeSkippedCount,
          readFailed: snapshot.readFailedCount,
          failedFiles: snapshot.documentParseFailedFiles,
          oversizeFiles: snapshot.oversizeSkippedFiles,
          readFailedFiles: snapshot.readFailedFiles,
          note: `历史索引报告（${portalSearchFormatTime(snapshot.updatedAt)}）`,
        });
      } else {
        portalSearchSetIndexReport({
          scanned: null,
          indexed: snapshot.count,
          searchable: snapshot.textCount,
          textSuccess: null,
          docSuccess: null,
          failed: null,
          skipped: null,
          unsupported: null,
          oversize: null,
          readFailed: null,
          note: "历史索引未包含文档解析统计，请重新索引",
        });
      }
    } else {
      portalSearchSetProgress(0);
      if (hasDirectoryHandle && hasDirectoryPermission) {
        portalSearchUpdateLocalStatus("当前无索引内容，可直接“重新索引”当前目录。");
      } else {
        portalSearchUpdateLocalStatus("未检测到可用历史索引，请先选择文件夹并索引。");
      }
      const parseSkipped =
        (Number(snapshot.documentParseSkippedCount) || 0) +
        (Number(snapshot.textParseSkippedCount) || 0) +
        (Number(snapshot.unsupportedTypeCount) || 0);
      portalSearchSetIndexReport({
        scanned: snapshot.hasIndexReport ? snapshot.scannedCount : null,
        indexed: snapshot.count,
        searchable: snapshot.hasIndexReport ? snapshot.searchableCount : snapshot.textCount,
        textSuccess: snapshot.hasIndexReport ? snapshot.textDirectSuccessCount : null,
        docSuccess: snapshot.hasIndexReport ? snapshot.documentParsedCount : null,
        failed: snapshot.hasIndexReport ? snapshot.documentParseFailedCount : null,
        skipped: snapshot.hasIndexReport ? parseSkipped : null,
        unsupported: snapshot.hasIndexReport ? snapshot.unsupportedTypeCount : null,
        oversize: snapshot.hasIndexReport ? snapshot.oversizeSkippedCount : null,
        readFailed: snapshot.hasIndexReport ? snapshot.readFailedCount : null,
        failedFiles: snapshot.hasIndexReport ? snapshot.documentParseFailedFiles : [],
        oversizeFiles: snapshot.hasIndexReport ? snapshot.oversizeSkippedFiles : [],
        readFailedFiles: snapshot.hasIndexReport ? snapshot.readFailedFiles : [],
        note: snapshot.hasIndexReport ? "历史索引报告（当前无可用索引内容）" : "当前无索引内容，等待重新索引",
      });
    }
    if (reindexButton) reindexButton.disabled = false;
    if (clearIndexButton) clearIndexButton.disabled = snapshot.items.length === 0;
  } catch (error) {
    portalSearchSetProgress(0);
    portalSearchUpdateLocalStatus(`历史索引加载失败：${error?.message || "未知错误"}`);
    portalSearchSetIndexReport({
      note: "历史索引加载失败",
    });
    if (reindexButton) reindexButton.disabled = false;
    if (clearIndexButton) clearIndexButton.disabled = portalSearchState.localIndex.length === 0;
  }
}

function portalSearchLoadCustomEngines() {
  if (!portalSearchCanUseSettings()) {
    portalSearchState.customEngines = [];
    return;
  }
  portalSearchMigrateLegacyCustomEnginesStorageForUser();
  const key = getPortalSearchCustomEnginesStorageKey();
  const stored = key ? portalSearchReadStorage(key, "") : "";
  if (!stored) {
    portalSearchState.customEngines = [];
    return;
  }
  try {
    const parsed = JSON.parse(stored);
    if (!Array.isArray(parsed)) {
      portalSearchState.customEngines = [];
      return;
    }
    portalSearchState.customEngines = parsed
      .filter((item) => item && typeof item === "object")
      .map((item) => ({
        name: String(item.name || "").trim(),
        url: String(item.url || "").trim(),
      }))
      .filter((item) => item.name && item.url);
  } catch {
    portalSearchState.customEngines = [];
  }
}

function portalSearchSaveCustomEngines() {
  if (!portalSearchCanUseSettings()) return;
  const key = getPortalSearchCustomEnginesStorageKey();
  if (!key) return;
  portalSearchWriteStorage(key, JSON.stringify(portalSearchState.customEngines));
}

function portalSearchGetAllEngines() {
  return [
    ...PORTAL_SEARCH_PRESET_ENGINES,
    ...portalSearchState.customEngines.map((engine, index) => ({
      id: `custom_${index}`,
      name: engine.name,
      url: engine.url,
      custom: true,
    })),
  ];
}

function portalSearchEnsureCurrentEngine() {
  const allEngines = portalSearchGetAllEngines();
  const exists = allEngines.some((engine) => engine.id === portalSearchState.currentEngine);
  if (!exists) {
    portalSearchState.currentEngine = PORTAL_SEARCH_PRESET_ENGINES[0].id;
    portalSearchWriteStorage(PORTAL_SEARCH_STORAGE_KEYS.currentEngine, portalSearchState.currentEngine);
  }
}

function portalSearchBuildSearchUrl(template, query) {
  const encodedQuery = encodeURIComponent(query);
  if (template.includes("{q}")) {
    return template.replaceAll("{q}", encodedQuery);
  }
  return `${template}${encodedQuery}`;
}

function portalSearchNormalizeCustomEngineUrl(rawUrl) {
  let url = String(rawUrl || "").trim();
  if (!url) throw new Error("empty");
  if (!/^https?:\/\//i.test(url)) {
    url = `https://${url}`;
  }
  url = url.replaceAll("{keyword}", "{q}");
  if (!url.includes("{q}")) {
    if (url.endsWith("=")) url = `${url}{q}`;
    else if (url.includes("?")) url = `${url}&q={q}`;
    else url = `${url}?q={q}`;
  }
  const testUrl = url.replaceAll("{q}", "test");
  new URL(testUrl);
  return url;
}

function portalSearchSetResultPanel(title, meta, contentHtml) {
  const titleNode = portalSearchById("portalSearchResultTitle");
  const metaNode = portalSearchById("portalSearchResultMeta");
  const listNode = portalSearchById("portalSearchResultList");
  const panelNode = portalSearchById("portalSearchResultPanel");
  if (!titleNode || !metaNode || !listNode || !panelNode) return;
  titleNode.textContent = title;
  metaNode.textContent = meta || "";
  listNode.innerHTML = contentHtml;
  panelNode.classList.add("show");
}

function portalSearchSetResultPanelState(stateType, message, options = {}) {
  const safeType = stateType === "loading" || stateType === "error" ? stateType : "empty";
  const role = safeType === "error" ? "alert" : "status";
  const title = String(options.title || "结果");
  const meta = String(options.meta || "");
  const text = String(message || "").trim() || (safeType === "loading" ? "正在加载..." : safeType === "error" ? "读取失败，请稍后重试。" : "暂无结果");
  const html = `<div class="portal-search-result-state is-${safeType}" role="${role}">${portalSearchEscapeHtml(text)}</div>`;
  portalSearchSetResultPanel(title, meta, html);
}

function portalSearchClearResultPanel() {
  const panelNode = portalSearchById("portalSearchResultPanel");
  const listNode = portalSearchById("portalSearchResultList");
  const metaNode = portalSearchById("portalSearchResultMeta");
  if (panelNode) panelNode.classList.remove("show");
  if (listNode) listNode.innerHTML = "";
  if (metaNode) metaNode.textContent = "";
}

function portalSearchGetVisibleEngineOptions() {
  const menuNode = portalSearchById("portalSearchEngineDropdownMenu");
  if (!menuNode) return [];
  return Array.from(menuNode.querySelectorAll(".portal-search-engine-dropdown-item")).filter(
    (node) => node instanceof HTMLElement && !node.hidden && !node.disabled
  );
}

function portalSearchSetEngineDropdownOpen(open, options = {}) {
  const dropdown = portalSearchById("portalSearchEngineDropdown");
  const button = portalSearchById("portalSearchEngineDropdownBtn");
  if (!dropdown || !button) return;
  const nextOpen = Boolean(open) && portalSearchState.currentMode !== "local";
  dropdown.classList.toggle("open", nextOpen);
  button.setAttribute("aria-expanded", nextOpen ? "true" : "false");
  if (!nextOpen) return;
  if (options.focusActive) {
    const focusActiveOption = () => {
      const optionsList = portalSearchGetVisibleEngineOptions();
      const activeNode =
        optionsList.find((node) => node.classList.contains("active")) ||
        optionsList[Math.max(0, Number(options.focusIndex) || 0)] ||
        optionsList[0];
      if (activeNode instanceof HTMLElement) {
        activeNode.focus();
      }
    };
    window.setTimeout(focusActiveOption, 120);
    window.setTimeout(() => {
      if (document.activeElement === button) {
        focusActiveOption();
      }
    }, 240);
  }
}

function portalSearchCloseEngineDropdown() {
  portalSearchSetEngineDropdownOpen(false);
}

function portalSearchGetFocusableElements(container) {
  if (!(container instanceof HTMLElement)) return [];
  const selector =
    'button:not([disabled]), [href], input:not([disabled]):not([type="hidden"]), select:not([disabled]), textarea:not([disabled]), [tabindex]:not([tabindex="-1"])';
  return Array.from(container.querySelectorAll(selector)).filter(
    (node) =>
      node instanceof HTMLElement &&
      !node.hidden &&
      node.getAttribute("aria-hidden") !== "true" &&
      node.getClientRects().length > 0
  );
}

function portalSearchHandleSettingsPanelKeydown(event) {
  const panel = event.currentTarget;
  if (!(panel instanceof HTMLElement)) return;
  if (event.key === "Escape") {
    event.preventDefault();
    event.stopPropagation();
    portalSearchCloseSettings();
    return;
  }
  if (event.key !== "Tab") return;
  const focusables = portalSearchGetFocusableElements(panel);
  if (!focusables.length) {
    event.preventDefault();
    panel.focus();
    return;
  }
  const first = focusables[0];
  const last = focusables[focusables.length - 1];
  const active = document.activeElement;
  if (event.shiftKey) {
    if (active === first || !panel.contains(active)) {
      event.preventDefault();
      last.focus();
    }
    return;
  }
  if (active === last) {
    event.preventDefault();
    first.focus();
  }
}

function portalSearchDetectEnhancedSupport() {
  const probe = document.createElement("input");
  probe.type = "file";
  const canUseFsHandle = typeof window.showDirectoryPicker === "function" && window.isSecureContext;
  const canUseFolderInput = "webkitdirectory" in probe;
  return canUseFsHandle || canUseFolderInput;
}

function portalSearchRenderEnhancedSupport() {
  const badge = portalSearchById("portalSearchSupportBadge");
  const localModeButton = portalSearchRoot?.querySelector('.portal-search-mode-btn[data-mode="local"]');
  const note = portalSearchById("portalSearchLocalHelp");
  if (!badge || !localModeButton || !note) return;

  if (portalSearchState.supportsEnhancedLocal) {
    badge.textContent = "本地索引可用";
    badge.classList.remove("warn");
    badge.classList.add("ok");
    localModeButton.disabled = false;
    localModeButton.removeAttribute("title");
    note.textContent = "数据仅在本机浏览器内索引。选择一次文件夹后，可直接“重新索引”当前目录。";
    portalSearchRenderSupportBadgeVisibility();
    return;
  }

  badge.textContent = "本地索引不可用";
  badge.classList.remove("ok");
  badge.classList.add("warn");
  localModeButton.disabled = true;
  localModeButton.title = "当前浏览器不支持本地目录索引";
  note.textContent = "当前环境不支持本地目录索引。请使用较新的 Chrome/Edge 浏览器。";
  portalSearchRenderSupportBadgeVisibility();
}

function portalSearchRenderSupportBadgeVisibility() {
  const badge = portalSearchById("portalSearchSupportBadge");
  if (!badge) return;
  const shouldShow = !portalSearchState.supportsEnhancedLocal || portalSearchState.currentMode === "local";
  badge.hidden = !shouldShow;
}

function portalSearchRenderModeSwitch() {
  const modeSwitch = portalSearchById("portalSearchModeSwitch");
  const searchInput = portalSearchById("portalSearchInput");
  const engineDropdown = portalSearchById("portalSearchEngineDropdown");
  const localPanel = portalSearchById("portalSearchLocalPanel");
  if (!modeSwitch || !searchInput || !engineDropdown || !localPanel) return;

  if (portalSearchState.currentMode === "local" && !portalSearchState.supportsEnhancedLocal) {
    portalSearchState.currentMode = "web";
  }

  const isLocalMode = portalSearchState.currentMode === "local";
  if (portalSearchRoot) {
    portalSearchRoot.classList.toggle("is-local-mode", isLocalMode);
  }
  modeSwitch.querySelectorAll(".portal-search-mode-btn").forEach((button) => {
    button.classList.toggle("active", button.dataset.mode === portalSearchState.currentMode);
  });

  searchInput.placeholder = isLocalMode ? "输入文件名或文件内容关键词..." : "输入关键词搜索...";
  engineDropdown.style.display = isLocalMode ? "none" : "flex";
  engineDropdown.classList.toggle("disabled", isLocalMode);
  localPanel.classList.toggle("is-active", isLocalMode);
  if (!isLocalMode) {
    portalSearchHideIndexReportHover();
    portalSearchClearResultPanel();
  }
  portalSearchRenderSitePanelVisibility();
  portalSearchRenderSupportBadgeVisibility();
  portalSearchRenderActiveContext();
  if (isLocalMode) portalSearchCloseEngineDropdown();
  portalSearchWriteStorage(PORTAL_SEARCH_STORAGE_KEYS.searchMode, portalSearchState.currentMode);
}

function portalSearchRenderEngineSelector() {
  portalSearchEnsureCurrentEngine();
  const allEngines = portalSearchGetAllEngines();
  const currentEngineNode = portalSearchById("portalSearchCurrentEngineName");
  const menuNode = portalSearchById("portalSearchEngineDropdownMenu");
  if (!currentEngineNode || !menuNode) return;

  const currentEngine = allEngines.find((engine) => engine.id === portalSearchState.currentEngine) || allEngines[0];
  currentEngineNode.textContent = currentEngine?.name || PORTAL_SEARCH_PRESET_ENGINES[0].name;
  portalSearchRenderActiveContext();

  menuNode.innerHTML = allEngines
    .map(
      (engine, index) =>
        `<button class="portal-search-engine-dropdown-item ${engine.id === portalSearchState.currentEngine ? "active" : ""}" id="portalSearchEngineOption-${index}" role="option" aria-selected="${engine.id === portalSearchState.currentEngine ? "true" : "false"}" tabindex="-1" type="button" data-engine="${portalSearchEscapeHtml(engine.id)}">${portalSearchEscapeHtml(engine.name)}</button>`
    )
    .join("");
  const activeOption = menuNode.querySelector(".portal-search-engine-dropdown-item.active");
  if (activeOption instanceof HTMLElement) {
    menuNode.setAttribute("aria-activedescendant", activeOption.id);
  } else {
    menuNode.removeAttribute("aria-activedescendant");
  }

  menuNode.querySelectorAll(".portal-search-engine-dropdown-item").forEach((button) => {
    button.addEventListener("click", () => {
      portalSearchState.currentEngine = String(button.dataset.engine || PORTAL_SEARCH_PRESET_ENGINES[0].id);
      portalSearchWriteStorage(PORTAL_SEARCH_STORAGE_KEYS.currentEngine, portalSearchState.currentEngine);
      portalSearchRenderEngineSelector();
      portalSearchCloseEngineDropdown();
    });
  });
}

function portalSearchRenderSettings() {
  const presetContainer = portalSearchById("portalSearchPresetEngines");
  const customContainer = portalSearchById("portalSearchCustomEngines");
  if (!presetContainer || !customContainer) return;

  presetContainer.innerHTML = PORTAL_SEARCH_PRESET_ENGINES.map(
    (engine) =>
      `<div class="portal-search-engine-item"><span class="portal-search-engine-item-name">${portalSearchEscapeHtml(engine.name)}</span><span class="portal-search-custom-badge">默认</span></div>`
  ).join("");

  if (!portalSearchState.customEngines.length) {
    customContainer.innerHTML = `<p class="portal-search-empty-text">暂无自定义引擎</p>`;
    return;
  }

  customContainer.innerHTML = portalSearchState.customEngines
    .map(
      (engine, index) =>
        `<div class="portal-search-engine-item"><span class="portal-search-engine-item-name">${portalSearchEscapeHtml(engine.name)}</span><div class="portal-search-engine-item-actions"><button class="portal-search-delete-btn" type="button" aria-label="删除引擎" data-index="${index}"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg></button></div></div>`
    )
    .join("");

  customContainer.querySelectorAll(".portal-search-delete-btn").forEach((button) => {
    button.addEventListener("click", () => {
      if (!portalSearchCanUseSettings()) {
        portalSearchRequestSettingsAuth();
        return;
      }
      const index = Number.parseInt(button.dataset.index || "", 10);
      if (!Number.isFinite(index) || index < 0 || index >= portalSearchState.customEngines.length) return;
      portalSearchState.customEngines.splice(index, 1);
      portalSearchSaveCustomEngines();
      portalSearchRenderEngineSelector();
      portalSearchRenderSettings();
    });
  });
}

function portalSearchOpenSettings() {
  if (!portalSearchCanUseSettings()) {
    portalSearchRequestSettingsAuth();
    return;
  }
  const panel = portalSearchById("portalSearchSettingsPanel");
  const overlay = portalSearchById("portalSearchOverlay");
  if (!panel || !overlay) return;
  if (portalSearchState.settingsCloseTimerId) {
    window.clearTimeout(portalSearchState.settingsCloseTimerId);
    portalSearchState.settingsCloseTimerId = null;
  }
  portalSearchState.settingsFocusReturnElement = document.activeElement instanceof HTMLElement ? document.activeElement : null;
  panel.hidden = false;
  overlay.hidden = false;
  requestAnimationFrame(() => {
    panel.classList.add("is-open");
    overlay.classList.add("is-open");
    const focusables = portalSearchGetFocusableElements(panel);
    const target = focusables[0] || panel;
    if (target instanceof HTMLElement) target.focus();
  });
}

function portalSearchCloseSettings() {
  const panel = portalSearchById("portalSearchSettingsPanel");
  const overlay = portalSearchById("portalSearchOverlay");
  if (!panel || !overlay || panel.hidden) return;
  const returnFocusElement = portalSearchState.settingsFocusReturnElement instanceof HTMLElement ? portalSearchState.settingsFocusReturnElement : null;
  portalSearchState.settingsFocusReturnElement = null;
  panel.classList.remove("is-open");
  overlay.classList.remove("is-open");
  if (portalSearchState.settingsCloseTimerId) window.clearTimeout(portalSearchState.settingsCloseTimerId);
  portalSearchState.settingsCloseTimerId = window.setTimeout(() => {
    panel.hidden = true;
    overlay.hidden = true;
    portalSearchState.settingsCloseTimerId = null;
    if (
      returnFocusElement &&
      returnFocusElement.isConnected &&
      typeof returnFocusElement.focus === "function" &&
      state.mainView === "search"
    ) {
      returnFocusElement.focus();
    }
  }, 220);
}

function portalSearchRevokePreviewBlobUrl() {
  const url = String(portalSearchState.previewBlobUrl || "").trim();
  if (!url) return;
  try {
    URL.revokeObjectURL(url);
  } catch {
    // Ignore invalid blob URL revocation.
  }
  portalSearchState.previewBlobUrl = "";
}

function portalSearchSetPreviewOpenPayload(payload = null) {
  if (!payload || typeof payload !== "object") {
    portalSearchState.previewOpenPayload = null;
    return;
  }
  const mode = String(payload.mode || "").trim().toLowerCase();
  if (!mode) {
    portalSearchState.previewOpenPayload = null;
    return;
  }
  portalSearchState.previewOpenPayload = {
    mode,
    url: String(payload.url || "").trim(),
    title: String(payload.title || "文档预览"),
    kind: String(payload.kind || "").trim().toLowerCase(),
    contentHtml: typeof payload.contentHtml === "string" ? payload.contentHtml : "",
  };
}

function portalSearchOpenBlankTab() {
  let previewWindow = null;
  try {
    previewWindow = window.open("", "_blank");
  } catch {
    previewWindow = null;
  }
  if (!previewWindow) return null;
  try {
    previewWindow.opener = null;
  } catch {
    // Some browser contexts disallow opener assignment.
  }
  return previewWindow;
}

function portalSearchBuildPreviewDocumentHtml(title, contentHtml) {
  return `<!doctype html>
<html lang="zh-CN">
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <title>${portalSearchEscapeHtml(title)}</title>
    <style>
      :root {
        color-scheme: ${String(state.theme || body?.dataset?.theme || "").toLowerCase() === "dark" ? "dark" : "light"};
      }
      * { box-sizing: border-box; }
      body {
        margin: 0;
        background: ${String(state.theme || body?.dataset?.theme || "").toLowerCase() === "dark" ? "#071522" : "#f6f9fc"};
        color: ${String(state.theme || body?.dataset?.theme || "").toLowerCase() === "dark" ? "#e8f3ff" : "#1c2733"};
        font-family: "Microsoft YaHei", -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
      }
      main {
        min-height: 100vh;
        padding: 16px;
      }
      .doc {
        max-width: 1080px;
        margin: 0 auto;
        border: 1px solid ${String(state.theme || body?.dataset?.theme || "").toLowerCase() === "dark" ? "#244866" : "#d9e6f2"};
        border-radius: 12px;
        background: ${String(state.theme || body?.dataset?.theme || "").toLowerCase() === "dark" ? "#0f273d" : "#ffffff"};
        padding: 14px;
        line-height: 1.72;
        word-break: break-word;
      }
      .doc pre {
        margin: 0;
        white-space: pre-wrap;
        word-break: break-word;
        font-family: Consolas, Monaco, "Courier New", monospace;
        font-size: 13px;
        line-height: 1.65;
      }
      .doc > *:first-child { margin-top: 0; }
      .doc > *:last-child { margin-bottom: 0; }
      .doc img { max-width: 100%; height: auto; border-radius: 6px; }
      .doc table { width: 100%; border-collapse: collapse; margin: 0.8em 0; }
      .doc th, .doc td {
        border: 1px solid ${String(state.theme || body?.dataset?.theme || "").toLowerCase() === "dark" ? "#244866" : "#d9e6f2"};
        padding: 6px 8px;
        text-align: left;
        vertical-align: top;
      }
      .doc code {
        font-family: Consolas, Monaco, "Courier New", monospace;
        font-size: 0.92em;
      }
    </style>
  </head>
  <body>
    <main>
      <article class="doc">${contentHtml}</article>
    </main>
  </body>
</html>`;
}

function portalSearchBuildImagePreviewDocumentHtml(title, imageUrl) {
  const isDarkTheme = String(state.theme || body?.dataset?.theme || "").toLowerCase() === "dark";
  const palette = isDarkTheme
    ? {
        colorScheme: "dark",
        bodyBg: "#071522",
        bodyText: "#e8f3ff",
        line: "#244866",
        surface: "#102b43",
        surfaceSoft: "#0c2439",
        muted: "#b7cee4",
      }
    : {
        colorScheme: "light",
        bodyBg: "#f6f9fc",
        bodyText: "#1c2733",
        line: "#d9e6f2",
        surface: "#ffffff",
        surfaceSoft: "#f6f9fc",
        muted: "#5a6b7b",
      };
  const safeTitle = portalSearchEscapeHtml(title || "图片预览");
  const safeImageUrl = portalSearchEscapeHtml(String(imageUrl || "").trim());
  return `<!doctype html>
<html lang="zh-CN">
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <title>${safeTitle}</title>
    <style>
      :root {
        color-scheme: ${palette.colorScheme};
        --pv-bg: ${palette.bodyBg};
        --pv-text: ${palette.bodyText};
        --pv-line: ${palette.line};
        --pv-surface: ${palette.surface};
        --pv-surface-soft: ${palette.surfaceSoft};
        --pv-muted: ${palette.muted};
      }
      * { box-sizing: border-box; }
      body {
        margin: 0;
        background: var(--pv-bg);
        color: var(--pv-text);
        font-family: "Microsoft YaHei", -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
      }
      main {
        height: 100vh;
        padding: 12px;
      }
      .image-stage {
        width: 100%;
        height: 100%;
        position: relative;
        background: var(--pv-surface);
        border: 1px solid var(--pv-line);
        border-radius: 12px;
        overflow: hidden;
        cursor: grab;
        user-select: none;
      }
      .image-stage.dragging { cursor: grabbing; }
      .zoom-image {
        position: absolute;
        left: 50%;
        top: 50%;
        max-width: 100%;
        max-height: 100%;
        width: auto;
        height: auto;
        transform: translate(-50%, -50%) scale(1);
        transform-origin: center center;
        user-select: none;
        pointer-events: none;
      }
      .image-hint {
        position: absolute;
        right: 12px;
        bottom: 12px;
        font-size: 12px;
        color: var(--pv-muted);
        background: var(--pv-surface-soft);
        border: 1px solid var(--pv-line);
        border-radius: 999px;
        padding: 4px 10px;
        pointer-events: none;
      }
    </style>
  </head>
  <body>
    <main>
      <div id="image-stage" class="image-stage" title="滚轮缩放，按住左键拖拽移动，双击重置">
        <img id="preview-image" class="zoom-image" src="${safeImageUrl}" alt="${safeTitle}" draggable="false" />
        <div class="image-hint">滚轮缩放 · 左键拖拽移动 · 双击重置</div>
      </div>
    </main>
    <script>
      (() => {
        const stage = document.getElementById("image-stage");
        const img = document.getElementById("preview-image");
        if (!stage || !img) return;
        const minScale = 0.2;
        const maxScale = 8;
        let scale = 1;
        let tx = 0;
        let ty = 0;
        let dragging = false;
        let lastX = 0;
        let lastY = 0;
        function render() {
          img.style.transform = "translate(-50%, -50%) translate(" + tx + "px, " + ty + "px) scale(" + scale + ")";
        }
        function zoomAt(clientX, clientY, ratio) {
          const rect = stage.getBoundingClientRect();
          const x = clientX - rect.left - rect.width / 2;
          const y = clientY - rect.top - rect.height / 2;
          const nextScale = Math.min(maxScale, Math.max(minScale, scale * ratio));
          if (nextScale === scale) return;
          const k = nextScale / scale;
          tx = tx + (1 - k) * (x - tx);
          ty = ty + (1 - k) * (y - ty);
          scale = nextScale;
          render();
        }
        stage.addEventListener("wheel", (event) => {
          event.preventDefault();
          const ratio = Math.exp(-event.deltaY * 0.0015);
          zoomAt(event.clientX, event.clientY, ratio);
        }, { passive: false });
        stage.addEventListener("mousedown", (event) => {
          if (event.button !== 0) return;
          dragging = true;
          lastX = event.clientX;
          lastY = event.clientY;
          stage.classList.add("dragging");
          event.preventDefault();
        });
        window.addEventListener("mousemove", (event) => {
          if (!dragging) return;
          tx += event.clientX - lastX;
          ty += event.clientY - lastY;
          lastX = event.clientX;
          lastY = event.clientY;
          render();
        });
        window.addEventListener("mouseup", () => {
          if (!dragging) return;
          dragging = false;
          stage.classList.remove("dragging");
        });
        stage.addEventListener("dblclick", () => {
          scale = 1;
          tx = 0;
          ty = 0;
          render();
        });
        img.addEventListener("dragstart", (event) => event.preventDefault());
        render();
      })();
    <\/script>
  </body>
</html>`;
}

function portalSearchOpenBlobUrlInNewTab(blobUrl) {
  const url = String(blobUrl || "").trim();
  if (!url) return false;
  const previewWindow = portalSearchOpenBlankTab();
  if (!previewWindow) {
    portalSearchSetNotice("浏览器拦截了新标签页，请允许弹窗后重试。", { tone: "error", durationMs: 4600 });
    return false;
  }
  try {
    previewWindow.location.replace(url);
  } catch {
    try {
      previewWindow.location.href = url;
    } catch {
      // Ignore location assignment failure and keep opened tab for manual recovery.
    }
  }
  return true;
}

function portalSearchOpenImagePreviewInNewTab(title, imageUrl) {
  const url = String(imageUrl || "").trim();
  if (!url) return false;
  const previewWindow = portalSearchOpenBlankTab();
  if (!previewWindow) {
    portalSearchSetNotice("浏览器拦截了新标签页，请允许弹窗后重试。", { tone: "error", durationMs: 4600 });
    return false;
  }
  const html = portalSearchBuildImagePreviewDocumentHtml(title || "图片预览", url);
  try {
    previewWindow.document.open("text/html", "replace");
    previewWindow.document.write(html);
    previewWindow.document.close();
    return true;
  } catch {
    try {
      previewWindow.location.replace(url);
      return true;
    } catch {
      try {
        previewWindow.close();
      } catch {
        // Ignore close failures.
      }
      portalSearchSetNotice("浏览器拦截了新标签页，请允许弹窗后重试。", { tone: "error", durationMs: 4600 });
      return false;
    }
  }
}

function portalSearchOpenPreviewHtmlInNewTab(title, contentHtml) {
  const previewWindow = portalSearchOpenBlankTab();
  if (!previewWindow) {
    portalSearchSetNotice("浏览器拦截了新标签页，请允许弹窗后重试。", { tone: "error", durationMs: 4600 });
    return false;
  }
  const html = portalSearchBuildPreviewDocumentHtml(title || "文档预览", contentHtml || "");
  try {
    previewWindow.document.open("text/html", "replace");
    previewWindow.document.write(html);
    previewWindow.document.close();
    return true;
  } catch {
    try {
      const htmlBlob = new Blob([html], { type: "text/html;charset=utf-8" });
      const htmlUrl = URL.createObjectURL(htmlBlob);
      previewWindow.location.replace(htmlUrl);
      window.setTimeout(() => {
        try {
          URL.revokeObjectURL(htmlUrl);
        } catch {
          // Ignore URL revoke failures.
        }
      }, 10000);
      return true;
    } catch {
      try {
        previewWindow.close();
      } catch {
        // Ignore close failures.
      }
      portalSearchSetNotice("浏览器拦截了新标签页，请允许弹窗后重试。", { tone: "error", durationMs: 4600 });
      return false;
    }
  }
}

function portalSearchOpenPreviewPayloadInNewTab() {
  const payload = portalSearchState.previewOpenPayload;
  if (!payload || typeof payload !== "object") {
    return portalSearchOpenBlobUrlInNewTab(portalSearchState.previewBlobUrl);
  }
  if (payload.mode === "image") {
    return portalSearchOpenImagePreviewInNewTab(payload.title || "图片预览", payload.url || portalSearchState.previewBlobUrl);
  }
  if (payload.mode === "blob") {
    return portalSearchOpenBlobUrlInNewTab(payload.url || portalSearchState.previewBlobUrl);
  }
  if (payload.mode === "html") {
    return portalSearchOpenPreviewHtmlInNewTab(payload.title || "文档预览", payload.contentHtml || "");
  }
  return portalSearchOpenBlobUrlInNewTab(portalSearchState.previewBlobUrl);
}

function portalSearchShowPreviewModal(title, meta = "") {
  const overlay = portalSearchById("portalSearchPreviewOverlay");
  const modal = portalSearchById("portalSearchPreviewModal");
  const titleNode = portalSearchById("portalSearchPreviewTitle");
  const metaNode = portalSearchById("portalSearchPreviewMeta");
  const contentNode = portalSearchById("portalSearchPreviewContent");
  if (!overlay || !modal || !titleNode || !metaNode || !contentNode) return null;
  if (portalSearchState.previewCloseTimerId) {
    window.clearTimeout(portalSearchState.previewCloseTimerId);
    portalSearchState.previewCloseTimerId = null;
  }
  portalSearchSetPreviewOpenPayload(null);
  portalSearchRevokePreviewBlobUrl();
  titleNode.textContent = title;
  metaNode.textContent = meta;
  contentNode.innerHTML = "";
  overlay.hidden = false;
  modal.hidden = false;
  requestAnimationFrame(() => {
    overlay.classList.add("is-open");
    modal.classList.add("is-open");
  });
  return contentNode;
}

function portalSearchOpenPreview(title, content, meta = "") {
  const contentNode = portalSearchShowPreviewModal(title, meta);
  if (!contentNode) return;
  const text = String(content || "").trim();
  if (!text) {
    const empty = document.createElement("p");
    empty.className = "portal-search-preview-empty";
    empty.textContent = "[空文件]";
    contentNode.append(empty);
    return;
  }
  const stage = document.createElement("div");
  stage.className = "portal-search-preview-text-stage";
  const pre = document.createElement("pre");
  pre.className = "portal-search-preview-text";
  pre.textContent = text;
  stage.append(pre);
  contentNode.append(stage);
}

function portalSearchClosePreview() {
  const overlay = portalSearchById("portalSearchPreviewOverlay");
  const modal = portalSearchById("portalSearchPreviewModal");
  const metaNode = portalSearchById("portalSearchPreviewMeta");
  const contentNode = portalSearchById("portalSearchPreviewContent");
  if (!overlay || !modal) {
    portalSearchSetPreviewOpenPayload(null);
    portalSearchRevokePreviewBlobUrl();
    return;
  }
  portalSearchState.previewRenderToken += 1;
  if (modal.hidden) {
    if (metaNode) metaNode.textContent = "";
    if (contentNode) contentNode.innerHTML = "";
    portalSearchSetPreviewOpenPayload(null);
    portalSearchRevokePreviewBlobUrl();
    return;
  }
  overlay.classList.remove("is-open");
  modal.classList.remove("is-open");
  if (portalSearchState.previewCloseTimerId) window.clearTimeout(portalSearchState.previewCloseTimerId);
  portalSearchState.previewCloseTimerId = window.setTimeout(() => {
    overlay.hidden = true;
    modal.hidden = true;
    if (metaNode) metaNode.textContent = "";
    if (contentNode) contentNode.innerHTML = "";
    portalSearchSetPreviewOpenPayload(null);
    portalSearchRevokePreviewBlobUrl();
    portalSearchState.previewCloseTimerId = null;
  }, 220);
}

function portalSearchUpdateLocalStatus(text) {
  const statusNode = portalSearchById("portalSearchLocalStatus");
  if (statusNode) statusNode.textContent = text;
}

function portalSearchSetProgress(percent) {
  const progressFill = portalSearchById("portalSearchIndexProgress");
  if (!progressFill) return;
  const safePercent = Math.max(0, Math.min(100, Number(percent) || 0));
  progressFill.style.width = `${safePercent}%`;
}

function portalSearchNormalizeIndexReportCount(value) {
  const count = Number(value);
  if (!Number.isFinite(count)) return null;
  return Math.max(0, Math.floor(count));
}

function portalSearchExtractPathBaseName(path) {
  const safePath = portalSearchNormalizePathSeparators(String(path || "")).replace(/^\/+/, "");
  if (!safePath) return "";
  const parts = safePath.split("/").filter(Boolean);
  return parts.length ? parts[parts.length - 1] : "";
}

function portalSearchNormalizeIndexReportDetailItem(item) {
  if (!item || typeof item !== "object") return null;
  const safePath = portalSearchNormalizePathSeparators(String(item.path || "")).replace(/^\/+/, "");
  const inferredName = portalSearchExtractPathBaseName(safePath);
  const safeName = String(item.name || inferredName || "未命名文件").trim() || "未命名文件";
  const sizeRaw = Number(item.size);
  const limitRaw = Number(item.limitBytes);
  const safeSize = Number.isFinite(sizeRaw) && sizeRaw >= 0 ? Math.floor(sizeRaw) : null;
  const safeLimit = Number.isFinite(limitRaw) && limitRaw >= 0 ? Math.floor(limitRaw) : null;
  const safeReason = String(item.reason || "").trim();
  return {
    name: safeName,
    path: safePath || safeName,
    size: safeSize,
    limitBytes: safeLimit,
    reason: safeReason,
  };
}

function portalSearchNormalizeIndexReportDetailList(list, options = {}) {
  const source = Array.isArray(list) ? list : [];
  const maxItemsRaw = Number(options.maxItems);
  const maxItems = Number.isFinite(maxItemsRaw) && maxItemsRaw > 0 ? Math.floor(maxItemsRaw) : PORTAL_SEARCH_INDEX_DETAIL_MAX_ITEMS;
  const normalized = [];
  const dedupe = new Set();
  for (const entry of source) {
    const safeItem = portalSearchNormalizeIndexReportDetailItem(entry);
    if (!safeItem) continue;
    const key = `${safeItem.path.toLowerCase()}|${safeItem.reason.toLowerCase()}|${safeItem.size ?? ""}|${safeItem.limitBytes ?? ""}`;
    if (dedupe.has(key)) continue;
    dedupe.add(key);
    normalized.push(safeItem);
    if (normalized.length >= maxItems) break;
  }
  return normalized;
}

function portalSearchPushIndexReportDetailItem(list, item) {
  if (!Array.isArray(list)) return;
  if (list.length >= PORTAL_SEARCH_INDEX_DETAIL_MAX_ITEMS) return;
  const normalized = portalSearchNormalizeIndexReportDetailItem(item);
  if (!normalized) return;
  const duplicateKey = `${normalized.path.toLowerCase()}|${normalized.reason.toLowerCase()}|${normalized.size ?? ""}|${normalized.limitBytes ?? ""}`;
  const exists = list.some((entry) => {
    const safeEntry = portalSearchNormalizeIndexReportDetailItem(entry);
    if (!safeEntry) return false;
    const entryKey = `${safeEntry.path.toLowerCase()}|${safeEntry.reason.toLowerCase()}|${safeEntry.size ?? ""}|${safeEntry.limitBytes ?? ""}`;
    return entryKey === duplicateKey;
  });
  if (exists) return;
  list.push(normalized);
}

function portalSearchGetIndexReportDetailEntries(detailType, report = portalSearchState.indexReport) {
  const safeReport = report && typeof report === "object" ? report : {};
  if (detailType === "failed") return portalSearchNormalizeIndexReportDetailList(safeReport.failedFiles, { maxItems: PORTAL_SEARCH_INDEX_DETAIL_MAX_ITEMS });
  if (detailType === "oversize")
    return portalSearchNormalizeIndexReportDetailList(safeReport.oversizeFiles, { maxItems: PORTAL_SEARCH_INDEX_DETAIL_MAX_ITEMS });
  if (detailType === "readFailed")
    return portalSearchNormalizeIndexReportDetailList(safeReport.readFailedFiles, { maxItems: PORTAL_SEARCH_INDEX_DETAIL_MAX_ITEMS });
  return [];
}

function portalSearchGetIndexReportDetailConfig(detailType) {
  return PORTAL_SEARCH_INDEX_DETAIL_CONFIG[detailType] || null;
}

function portalSearchSetIndexReportDetailCardState(cardId, detailType, report = portalSearchState.indexReport) {
  const card = portalSearchById(cardId);
  if (!card) return;
  const config = portalSearchGetIndexReportDetailConfig(detailType);
  const items = portalSearchGetIndexReportDetailEntries(detailType, report);
  const hasData = items.length > 0;
  card.classList.toggle("has-detail", hasData);
  card.setAttribute("tabindex", hasData ? "0" : "-1");
  card.setAttribute("aria-disabled", hasData ? "false" : "true");
  if (hasData && config) {
    card.setAttribute("aria-label", `${config.title}，共 ${items.length} 项`);
  } else if (config) {
    card.setAttribute("aria-label", `${config.empty}`);
  }
}

function portalSearchRenderIndexReportDetailCards(report = portalSearchState.indexReport) {
  portalSearchSetIndexReportDetailCardState("portalSearchReportCardFailed", "failed", report);
  portalSearchSetIndexReportDetailCardState("portalSearchReportCardOversize", "oversize", report);
  portalSearchSetIndexReportDetailCardState("portalSearchReportCardReadFailed", "readFailed", report);
}

function portalSearchClearIndexReportHoverHideTimer() {
  if (!portalSearchState.indexReportHoverHideTimerId) return;
  window.clearTimeout(portalSearchState.indexReportHoverHideTimerId);
  portalSearchState.indexReportHoverHideTimerId = 0;
}

function portalSearchHideIndexReportHover() {
  portalSearchClearIndexReportHoverHideTimer();
  const panel = portalSearchById("portalSearchIndexReportHover");
  if (!panel) return;
  panel.hidden = true;
  panel.style.left = "";
  panel.style.top = "";
  portalSearchState.indexReportHoverActiveType = "";
  ["portalSearchReportCardFailed", "portalSearchReportCardOversize", "portalSearchReportCardReadFailed"].forEach((id) => {
    const card = portalSearchById(id);
    card?.classList.remove("is-active");
  });
}

function portalSearchBuildIndexReportDetailItemHtml(item) {
  const safeItem = portalSearchNormalizeIndexReportDetailItem(item);
  if (!safeItem) return "";
  return `<li class="portal-search-index-report-hover-item"><div class="portal-search-index-report-hover-item-title">${portalSearchEscapeHtml(
    safeItem.name
  )}</div></li>`;
}

function portalSearchShowIndexReportHover(detailType, anchorElement) {
  const panel = portalSearchById("portalSearchIndexReportHover");
  const titleNode = portalSearchById("portalSearchIndexReportHoverTitle");
  const bodyNode = portalSearchById("portalSearchIndexReportHoverBody");
  const reportNode = portalSearchById("portalSearchIndexReport");
  if (!panel || !titleNode || !bodyNode || !reportNode || !(anchorElement instanceof HTMLElement)) return;
  const config = portalSearchGetIndexReportDetailConfig(detailType);
  if (!config) return;
  const allItems = portalSearchGetIndexReportDetailEntries(detailType);
  const previewItems = allItems.slice(0, PORTAL_SEARCH_INDEX_DETAIL_PREVIEW_ITEMS);
  titleNode.textContent = config.title;
  if (!previewItems.length) {
    bodyNode.innerHTML = `<p class="portal-search-index-report-hover-empty">${portalSearchEscapeHtml(config.empty)}</p>`;
  } else {
    bodyNode.innerHTML = `<ul class="portal-search-index-report-hover-list">${previewItems
      .map((item) => portalSearchBuildIndexReportDetailItemHtml(item))
      .join("")}</ul>`;
  }
  portalSearchClearIndexReportHoverHideTimer();
  portalSearchState.indexReportHoverActiveType = detailType;
  ["portalSearchReportCardFailed", "portalSearchReportCardOversize", "portalSearchReportCardReadFailed"].forEach((id) => {
    const card = portalSearchById(id);
    card?.classList.toggle("is-active", card === anchorElement);
  });
  panel.hidden = false;
  panel.style.left = "0px";
  panel.style.top = "0px";
  const reportRect = reportNode.getBoundingClientRect();
  const anchorRect = anchorElement.getBoundingClientRect();
  const panelRect = panel.getBoundingClientRect();
  const maxLeft = Math.max(0, reportRect.width - panelRect.width - 8);
  const preferredLeft = anchorRect.left - reportRect.left;
  const safeLeft = Math.max(0, Math.min(maxLeft, preferredLeft));
  let safeTop = anchorRect.bottom - reportRect.top + 8;
  if (safeTop + panelRect.height > reportRect.height - 4) {
    safeTop = Math.max(6, anchorRect.top - reportRect.top - panelRect.height - 8);
  }
  panel.style.left = `${Math.round(safeLeft)}px`;
  panel.style.top = `${Math.round(safeTop)}px`;
}

function portalSearchScheduleHideIndexReportHover() {
  portalSearchClearIndexReportHoverHideTimer();
  portalSearchState.indexReportHoverHideTimerId = window.setTimeout(() => {
    portalSearchState.indexReportHoverHideTimerId = 0;
    portalSearchHideIndexReportHover();
  }, 140);
}

function portalSearchBindIndexReportHoverInteractions() {
  const panel = portalSearchById("portalSearchIndexReportHover");
  const bindings = [
    ["portalSearchReportCardFailed", "failed"],
    ["portalSearchReportCardOversize", "oversize"],
    ["portalSearchReportCardReadFailed", "readFailed"],
  ];
  bindings.forEach(([cardId, detailType]) => {
    const card = portalSearchById(cardId);
    if (!card || card.dataset.reportHoverBound === "1") return;
    card.dataset.reportHoverBound = "1";
    card.addEventListener("mouseenter", () => {
      if (!card.classList.contains("has-detail")) return;
      portalSearchShowIndexReportHover(detailType, card);
    });
    card.addEventListener("mouseleave", portalSearchScheduleHideIndexReportHover);
    card.addEventListener("focus", () => {
      if (!card.classList.contains("has-detail")) return;
      portalSearchShowIndexReportHover(detailType, card);
    });
    card.addEventListener("blur", portalSearchScheduleHideIndexReportHover);
    card.addEventListener("click", () => {
      if (!card.classList.contains("has-detail")) return;
      if (!panel?.hidden && portalSearchState.indexReportHoverActiveType === detailType) {
        portalSearchHideIndexReportHover();
        return;
      }
      portalSearchShowIndexReportHover(detailType, card);
    });
    card.addEventListener("keydown", (event) => {
      if (event.key !== "Enter" && event.key !== " ") return;
      if (!card.classList.contains("has-detail")) return;
      event.preventDefault();
      portalSearchShowIndexReportHover(detailType, card);
    });
  });
  if (panel && panel.dataset.reportHoverBound !== "1") {
    panel.dataset.reportHoverBound = "1";
    panel.addEventListener("mouseenter", portalSearchClearIndexReportHoverHideTimer);
    panel.addEventListener("mouseleave", portalSearchScheduleHideIndexReportHover);
  }
}

function portalSearchSetIndexReportMetricText(nodeId, value) {
  const node = portalSearchById(nodeId);
  if (!node) return;
  const count = portalSearchNormalizeIndexReportCount(value);
  node.textContent = count == null ? "--" : String(count);
}

function portalSearchRenderIndexReport(report = portalSearchState.indexReport) {
  const noteNode = portalSearchById("portalSearchIndexReportNote");
  if (!noteNode) return;
  const safeReport = report && typeof report === "object" ? report : {};
  portalSearchSetIndexReportMetricText("portalSearchIndexReportScanned", safeReport.scanned);
  portalSearchSetIndexReportMetricText("portalSearchIndexReportIndexed", safeReport.indexed);
  portalSearchSetIndexReportMetricText("portalSearchIndexReportSearchable", safeReport.searchable);
  portalSearchSetIndexReportMetricText("portalSearchIndexReportTextSuccess", safeReport.textSuccess);
  portalSearchSetIndexReportMetricText("portalSearchIndexReportDocSuccess", safeReport.docSuccess);
  portalSearchSetIndexReportMetricText("portalSearchIndexReportFailed", safeReport.failed);
  portalSearchSetIndexReportMetricText("portalSearchIndexReportSkipped", safeReport.skipped);
  portalSearchSetIndexReportMetricText("portalSearchIndexReportUnsupported", safeReport.unsupported);
  portalSearchSetIndexReportMetricText("portalSearchIndexReportOversize", safeReport.oversize);
  portalSearchSetIndexReportMetricText("portalSearchIndexReportReadFailed", safeReport.readFailed);
  noteNode.textContent = String(safeReport.note || "等待首次索引");
  portalSearchRenderIndexReportDetailCards(safeReport);
  const activeType = String(portalSearchState.indexReportHoverActiveType || "");
  if (!activeType) return;
  const activeCardId =
    activeType === "failed"
      ? "portalSearchReportCardFailed"
      : activeType === "oversize"
        ? "portalSearchReportCardOversize"
        : activeType === "readFailed"
          ? "portalSearchReportCardReadFailed"
          : "";
  const activeCard = activeCardId ? portalSearchById(activeCardId) : null;
  if (!(activeCard instanceof HTMLElement) || !activeCard.classList.contains("has-detail")) {
    portalSearchHideIndexReportHover();
    return;
  }
  const hoverPanel = portalSearchById("portalSearchIndexReportHover");
  if (hoverPanel && !hoverPanel.hidden) {
    portalSearchShowIndexReportHover(activeType, activeCard);
  }
}

function portalSearchSetIndexReport(report = {}) {
  portalSearchState.indexReport = {
    scanned: portalSearchNormalizeIndexReportCount(report.scanned),
    indexed: portalSearchNormalizeIndexReportCount(report.indexed),
    searchable: portalSearchNormalizeIndexReportCount(report.searchable),
    textSuccess: portalSearchNormalizeIndexReportCount(report.textSuccess),
    docSuccess: portalSearchNormalizeIndexReportCount(report.docSuccess),
    failed: portalSearchNormalizeIndexReportCount(report.failed),
    skipped: portalSearchNormalizeIndexReportCount(report.skipped),
    unsupported: portalSearchNormalizeIndexReportCount(report.unsupported),
    oversize: portalSearchNormalizeIndexReportCount(report.oversize),
    readFailed: portalSearchNormalizeIndexReportCount(report.readFailed),
    failedFiles: portalSearchNormalizeIndexReportDetailList(report.failedFiles),
    oversizeFiles: portalSearchNormalizeIndexReportDetailList(report.oversizeFiles),
    readFailedFiles: portalSearchNormalizeIndexReportDetailList(report.readFailedFiles),
    note: String(report.note || "等待首次索引"),
  };
  portalSearchRenderIndexReport(portalSearchState.indexReport);
}

function portalSearchSyncIndexReportFromGuard(guard, note = "") {
  const docFailed = Math.max(0, Number(guard?.documentParseFailedCount) || 0);
  const docSkipped = Math.max(0, Number(guard?.documentParseSkippedCount) || 0);
  const textSkipped = Math.max(0, Number(guard?.textParseSkippedCount) || 0);
  const unsupported = Math.max(0, Number(guard?.unsupportedTypeCount) || 0);
  portalSearchSetIndexReport({
    scanned: Number(guard?.fileScannedCount) || 0,
    indexed: Number(guard?.count) || 0,
    searchable: Number(guard?.searchableCount) || 0,
    textSuccess: Number(guard?.textDirectSuccessCount) || 0,
    docSuccess: Number(guard?.documentParsedCount) || 0,
    failed: docFailed,
    skipped: docSkipped + textSkipped + unsupported,
    unsupported,
    oversize: Number(guard?.oversizeSkippedCount) || 0,
    readFailed: Number(guard?.readFailedCount) || 0,
    failedFiles: guard?.documentParseFailedFiles,
    oversizeFiles: guard?.oversizeSkippedFiles,
    readFailedFiles: guard?.readFailedFiles,
    note: String(note || ""),
  });
}

function portalSearchClearCancelArmTimer() {
  if (portalSearchState.indexCancelArmTimerId) {
    window.clearTimeout(portalSearchState.indexCancelArmTimerId);
    portalSearchState.indexCancelArmTimerId = 0;
  }
}

function portalSearchSetCancelButtonArmed(isArmed) {
  const cancelButton = portalSearchById("portalSearchCancelIndexBtn");
  if (!cancelButton) return;
  if (isArmed) {
    cancelButton.classList.add("is-armed");
    cancelButton.textContent = "确认取消";
    cancelButton.setAttribute("aria-label", "确认取消索引");
    return;
  }
  cancelButton.classList.remove("is-armed");
  cancelButton.textContent = "取消索引";
  cancelButton.setAttribute("aria-label", "取消索引");
}

function portalSearchBuildIndexingProgressStatus(guard) {
  const elapsedMs = Math.max(0, Date.now() - (Number(guard?.startedAtMs) || Date.now()));
  const elapsedSeconds = Math.max(1, elapsedMs / 1000);
  const scannedCount = Math.max(0, Number(guard?.fileScannedCount) || Number(guard?.count) || 0);
  const indexedCount = Math.max(0, Number(guard?.count) || 0);
  const searchableCount = Math.max(0, Number(guard?.searchableCount) || 0);
  const rate = indexedCount / elapsedSeconds;
  const rateText = Number.isFinite(rate) && rate > 0 ? `${rate >= 10 ? rate.toFixed(0) : rate.toFixed(1)} 个/秒` : "0 个/秒";
  const failedTip = Number(guard?.failedCount) > 0 ? `，失败 ${Math.max(0, Number(guard.failedCount) || 0)} 个` : "";
  const documentTip = portalSearchBuildDocumentParseStatus(guard);
  return `索引中：已扫描 ${scannedCount} 个文件，已纳入索引 ${indexedCount} 个，正文可检索 ${searchableCount} 个${failedTip}${documentTip}（用时 ${portalSearchFormatDurationMs(elapsedMs)}，${rateText}）`;
}

function portalSearchSyncIndexingProgress(guard, options = {}) {
  const maxPercentRaw = Number(options.maxPercent);
  const maxPercent = Number.isFinite(maxPercentRaw) ? Math.max(1, Math.min(99, maxPercentRaw)) : 95;
  const processedCount = Math.max(0, Number(guard?.count) || 0);
  const scannedCount = Math.max(0, Number(guard?.fileScannedCount) || processedCount);
  const progress = Math.min(maxPercent, (processedCount / PORTAL_SEARCH_MAX_INDEX_FILES) * 100);
  portalSearchSetProgress(progress);
  portalSearchUpdateLocalStatus(portalSearchBuildIndexingProgressStatus(guard));
  portalSearchSyncIndexReportFromGuard(guard, `索引进行中 · 已扫描 ${scannedCount} 个文件`);
}

function portalSearchRequestCancelIndexing() {
  if (!portalSearchState.indexing || portalSearchState.indexCancelRequested) return;
  const now = Date.now();
  if (now > portalSearchState.indexCancelArmedUntil) {
    const armSeconds = Math.max(1, Math.round(PORTAL_SEARCH_CANCEL_ARM_WINDOW_MS / 1000));
    portalSearchState.indexCancelArmedUntil = now + PORTAL_SEARCH_CANCEL_ARM_WINDOW_MS;
    portalSearchSetCancelButtonArmed(true);
    portalSearchClearCancelArmTimer();
    portalSearchState.indexCancelArmTimerId = window.setTimeout(() => {
      portalSearchState.indexCancelArmTimerId = 0;
      if (!portalSearchState.indexing || portalSearchState.indexCancelRequested) return;
      if (Date.now() < portalSearchState.indexCancelArmedUntil) return;
      portalSearchState.indexCancelArmedUntil = 0;
      portalSearchSetCancelButtonArmed(false);
      portalSearchSetNotice("已取消本次“取消索引”操作。", { tone: "info", durationMs: 2200 });
    }, PORTAL_SEARCH_CANCEL_ARM_WINDOW_MS + 100);
    const confirmTip = `再次点击“取消索引”可确认取消（${armSeconds}秒内）`;
    portalSearchUpdateLocalStatus(confirmTip);
    portalSearchSetNotice(confirmTip, { tone: "info", durationMs: 3000 });
    return;
  }
  portalSearchState.indexCancelArmedUntil = 0;
  portalSearchClearCancelArmTimer();
  portalSearchSetCancelButtonArmed(false);
  portalSearchState.indexCancelRequested = true;
  const cancelButton = portalSearchById("portalSearchCancelIndexBtn");
  if (cancelButton) cancelButton.disabled = true;
  portalSearchUpdateLocalStatus("正在取消索引，请稍候...");
  portalSearchSetNotice("正在取消索引，请稍候...", { tone: "info", durationMs: 2600 });
}

function portalSearchResolveImportedRootName(files) {
  const firstFile = Array.isArray(files) ? files.find((item) => item instanceof File) : null;
  if (!firstFile) return "";
  const relative = portalSearchNormalizePathSeparators(String(firstFile.webkitRelativePath || "")).replace(/^\/+/, "");
  if (!relative) return "";
  const [root] = relative.split("/").filter(Boolean);
  return String(root || "").trim();
}

function portalSearchResolveImportedFilePath(file, rootName = "") {
  const relative = portalSearchNormalizePathSeparators(String(file?.webkitRelativePath || "")).replace(/^\/+/, "");
  if (relative) return relative;
  const name = String(file?.name || "未命名文件").trim() || "未命名文件";
  const safeRoot = String(rootName || "").trim();
  return safeRoot ? `${safeRoot}/${name}` : name;
}

function portalSearchChooseFolderFilesFromInput() {
  const input = portalSearchById("portalSearchFolderInput");
  if (!(input instanceof HTMLInputElement)) {
    return Promise.reject(new Error("文件夹导入控件未就绪"));
  }
  return new Promise((resolve, reject) => {
    let settled = false;
    const finalize = (cb, payload) => {
      if (settled) return;
      settled = true;
      input.removeEventListener("change", onChange);
      window.removeEventListener("focus", onWindowFocus);
      cb(payload);
    };
    const onChange = () => {
      const files = Array.from(input.files || []).filter((item) => item instanceof File);
      finalize(resolve, files);
    };
    const onWindowFocus = () => {
      window.setTimeout(() => {
        if (settled) return;
        const files = Array.from(input.files || []).filter((item) => item instanceof File);
        if (files.length > 0) {
          finalize(resolve, files);
          return;
        }
        const error = new Error("AbortError");
        error.name = "AbortError";
        finalize(reject, error);
      }, 280);
    };
    input.value = "";
    input.addEventListener("change", onChange);
    window.addEventListener("focus", onWindowFocus);
    input.click();
  });
}

async function portalSearchWalkImportedFiles(files, guard) {
  const sourceFiles = Array.isArray(files) ? files : [];
  if (guard.cancelRequested()) return;
  for (const file of sourceFiles) {
    if (!(file instanceof File)) continue;
    if (guard.reachedLimit || guard.cancelRequested()) break;
    if (guard.count >= PORTAL_SEARCH_MAX_INDEX_FILES) {
      guard.reachedLimit = true;
      break;
    }
    guard.fileScannedCount += 1;
    const fullPath = portalSearchResolveImportedFilePath(file, guard.rootName || "");

    try {
      if (guard.cancelRequested()) break;
      const extension = portalSearchGetExtension(file.name);
      let text = "";
      if (PORTAL_SEARCH_TEXT_EXTENSIONS.has(extension)) {
        if (file.size > PORTAL_SEARCH_MAX_TEXT_FILE_BYTES) {
          guard.textParseSkippedCount += 1;
          guard.oversizeSkippedCount += 1;
          portalSearchPushIndexReportDetailItem(guard.oversizeSkippedFiles, {
            name: file.name,
            path: fullPath,
            size: file.size,
            limitBytes: PORTAL_SEARCH_MAX_TEXT_FILE_BYTES,
            reason: "文本文件超过解析大小限制",
          });
        } else {
          text = await file.text();
          if (guard.cancelRequested()) break;
          if (text.length > PORTAL_SEARCH_MAX_TEXT_CHARS) {
            text = text.slice(0, PORTAL_SEARCH_MAX_TEXT_CHARS);
          }
          guard.textCount += 1;
          guard.textDirectSuccessCount += 1;
          if (text.trim()) {
            guard.searchableCount += 1;
          }
        }
      } else if (PORTAL_SEARCH_DOCUMENT_EXTENSIONS.has(extension)) {
        if (file.size > PORTAL_SEARCH_MAX_DOCUMENT_FILE_BYTES) {
          guard.documentParseSkippedCount += 1;
          guard.oversizeSkippedCount += 1;
          portalSearchPushIndexReportDetailItem(guard.oversizeSkippedFiles, {
            name: file.name,
            path: fullPath,
            size: file.size,
            limitBytes: PORTAL_SEARCH_MAX_DOCUMENT_FILE_BYTES,
            reason: "文档文件超过解析大小限制",
          });
        } else if (portalSearchState.documentParseEndpointUnavailable) {
          guard.documentParseSkippedCount += 1;
        } else {
          try {
            const extractedText = await portalSearchExtractDocumentText(file, extension);
            if (guard.cancelRequested()) break;
            if (extractedText) {
              text = extractedText;
              guard.textCount += 1;
              guard.searchableCount += 1;
              guard.documentParsedCount += 1;
            } else {
              guard.documentParseFailedCount += 1;
              portalSearchPushIndexReportDetailItem(guard.documentParseFailedFiles, {
                name: file.name,
                path: fullPath,
                size: file.size,
                reason: "提取结果为空",
              });
            }
          } catch (error) {
            if (error?.code === "DOCUMENT_PARSE_UNAVAILABLE") {
              guard.documentParseSkippedCount += 1;
            } else {
              guard.documentParseFailedCount += 1;
              portalSearchPushIndexReportDetailItem(guard.documentParseFailedFiles, {
                name: file.name,
                path: fullPath,
                size: file.size,
                reason: String(error?.message || error?.code || "文档解析异常"),
              });
            }
          }
        }
      } else {
        guard.unsupportedTypeCount += 1;
      }
      portalSearchState.localIndex.push(
        portalSearchBuildLocalIndexEntry(
          {
            name: file.name,
            path: fullPath,
            relativePath: portalSearchDeriveRelativePath(fullPath, guard.rootName || ""),
            extension,
            size: file.size,
            modified: file.lastModified,
            text,
            file,
          },
          {
            rootName: guard.rootName || "",
          }
        )
      );
      portalSearchState.selectedFilesByPath.set(fullPath.toLowerCase(), file);
      guard.count += 1;

      if (guard.count % 20 === 0) {
        portalSearchSyncIndexingProgress(guard, { maxPercent: 95 });
        await new Promise((resolve) => setTimeout(resolve, 0));
      }
    } catch (error) {
      // Ignore single file failures and continue indexing.
      guard.failedCount += 1;
      guard.readFailedCount += 1;
      portalSearchPushIndexReportDetailItem(guard.readFailedFiles, {
        name: file.name,
        path: fullPath,
        size: file.size,
        reason: String(error?.message || "读取失败"),
      });
    }
  }
}

async function portalSearchWalkLegacyDirectory(directoryHandle, parentPath, guard) {
  const safeParentPath = portalSearchNormalizePathSeparators(parentPath).replace(/^\/+/, "");
  if (!directoryHandle || typeof directoryHandle.values !== "function") return;
  if (guard.cancelRequested()) return;
  for await (const entry of directoryHandle.values()) {
    if (guard.reachedLimit || guard.cancelRequested()) break;
    const fullPath = `${safeParentPath}/${entry.name}`;
    if (entry?.kind === "directory") {
      await portalSearchWalkLegacyDirectory(entry, fullPath, guard);
      if (guard.reachedLimit || guard.cancelRequested()) break;
      continue;
    }
    if (entry?.kind !== "file" || typeof entry.getFile !== "function") continue;
    if (guard.count >= PORTAL_SEARCH_MAX_INDEX_FILES) {
      guard.reachedLimit = true;
      break;
    }
    guard.fileScannedCount += 1;

    try {
      const file = await entry.getFile();
      if (!(file instanceof File)) continue;
      if (guard.cancelRequested()) break;
      const extension = portalSearchGetExtension(file.name);
      let text = "";
      if (PORTAL_SEARCH_TEXT_EXTENSIONS.has(extension)) {
        if (file.size > PORTAL_SEARCH_MAX_TEXT_FILE_BYTES) {
          guard.textParseSkippedCount += 1;
          guard.oversizeSkippedCount += 1;
          portalSearchPushIndexReportDetailItem(guard.oversizeSkippedFiles, {
            name: file.name,
            path: fullPath,
            size: file.size,
            limitBytes: PORTAL_SEARCH_MAX_TEXT_FILE_BYTES,
            reason: "文本文件超过解析大小限制",
          });
        } else {
          text = await file.text();
          if (guard.cancelRequested()) break;
          if (text.length > PORTAL_SEARCH_MAX_TEXT_CHARS) {
            text = text.slice(0, PORTAL_SEARCH_MAX_TEXT_CHARS);
          }
          guard.textCount += 1;
          guard.textDirectSuccessCount += 1;
          if (text.trim()) {
            guard.searchableCount += 1;
          }
        }
      } else if (PORTAL_SEARCH_DOCUMENT_EXTENSIONS.has(extension)) {
        if (file.size > PORTAL_SEARCH_MAX_DOCUMENT_FILE_BYTES) {
          guard.documentParseSkippedCount += 1;
          guard.oversizeSkippedCount += 1;
          portalSearchPushIndexReportDetailItem(guard.oversizeSkippedFiles, {
            name: file.name,
            path: fullPath,
            size: file.size,
            limitBytes: PORTAL_SEARCH_MAX_DOCUMENT_FILE_BYTES,
            reason: "文档文件超过解析大小限制",
          });
        } else if (portalSearchState.documentParseEndpointUnavailable) {
          guard.documentParseSkippedCount += 1;
        } else {
          try {
            const extractedText = await portalSearchExtractDocumentText(file, extension);
            if (guard.cancelRequested()) break;
            if (extractedText) {
              text = extractedText;
              guard.textCount += 1;
              guard.searchableCount += 1;
              guard.documentParsedCount += 1;
            } else {
              guard.documentParseFailedCount += 1;
              portalSearchPushIndexReportDetailItem(guard.documentParseFailedFiles, {
                name: file.name,
                path: fullPath,
                size: file.size,
                reason: "提取结果为空",
              });
            }
          } catch (error) {
            if (error?.code === "DOCUMENT_PARSE_UNAVAILABLE") {
              guard.documentParseSkippedCount += 1;
            } else {
              guard.documentParseFailedCount += 1;
              portalSearchPushIndexReportDetailItem(guard.documentParseFailedFiles, {
                name: file.name,
                path: fullPath,
                size: file.size,
                reason: String(error?.message || error?.code || "文档解析异常"),
              });
            }
          }
        }
      } else {
        guard.unsupportedTypeCount += 1;
      }

      portalSearchState.localIndex.push(
        portalSearchBuildLocalIndexEntry(
          {
            name: file.name,
            path: fullPath,
            relativePath: portalSearchDeriveRelativePath(fullPath, guard.rootName || ""),
            extension,
            size: file.size,
            modified: file.lastModified,
            text,
            file,
          },
          {
            rootName: guard.rootName || "",
          }
        )
      );
      portalSearchState.selectedFilesByPath.set(fullPath.toLowerCase(), file);
      guard.count += 1;

      if (guard.count % 20 === 0) {
        portalSearchSyncIndexingProgress(guard, { maxPercent: 95 });
        await new Promise((resolve) => setTimeout(resolve, 0));
      }
    } catch (error) {
      guard.failedCount += 1;
      guard.readFailedCount += 1;
      portalSearchPushIndexReportDetailItem(guard.readFailedFiles, {
        name: entry?.name || portalSearchExtractPathBaseName(fullPath),
        path: fullPath,
        reason: String(error?.message || "读取失败"),
      });
    }
  }
}

async function portalSearchBuildLocalIndex(files, options = {}) {
  const reindexButton = portalSearchById("portalSearchReindexBtn");
  const cancelButton = portalSearchById("portalSearchCancelIndexBtn");
  const clearIndexButton = portalSearchById("portalSearchClearIndexBtn");
  if (portalSearchState.indexing) return;
  const sourceFiles = Array.isArray(files) ? files.filter((item) => item instanceof File) : [];
  const legacyDirectoryHandle =
    sourceFiles.length === 0 && portalSearchState.directoryHandle && typeof portalSearchState.directoryHandle.values === "function"
      ? portalSearchState.directoryHandle
      : null;
  if (!sourceFiles.length && !legacyDirectoryHandle) {
    portalSearchUpdateLocalStatus("未选择文件夹或目录为空。");
    portalSearchSetIndexReport({
      note: "等待选择文件夹",
    });
    if (reindexButton) reindexButton.disabled = false;
    if (cancelButton) cancelButton.disabled = true;
    return;
  }

  portalSearchState.indexing = true;
  portalSearchState.indexCancelRequested = false;
  portalSearchState.indexCancelArmedUntil = 0;
  portalSearchState.documentParseEndpointUnavailable = false;
  portalSearchState.documentParseUnavailableNoticeShown = false;
  portalSearchState.pdfWebOcrNoticeShown = false;
  portalSearchState.pdfWebRuntimeUnavailableNoticeShown = false;
  portalSearchClearCancelArmTimer();
  portalSearchState.localIndex = [];
  portalSearchState.localResults = [];
  portalSearchState.selectedFilesByPath = new Map();
  portalSearchClearResultPanel();
  if (reindexButton) reindexButton.disabled = true;
  portalSearchSetCancelButtonArmed(false);
  if (cancelButton) cancelButton.disabled = false;
  if (clearIndexButton) clearIndexButton.disabled = true;
  portalSearchSetProgress(0);
  portalSearchUpdateLocalStatus("正在构建索引...");
  portalSearchSetIndexReport({
    scanned: 0,
    indexed: 0,
    searchable: 0,
    textSuccess: 0,
    docSuccess: 0,
    failed: 0,
    skipped: 0,
    unsupported: 0,
    oversize: 0,
    readFailed: 0,
    note: "索引准备中...",
  });

  const resolvedRootName = String(options.rootName || "").trim();
  const inferredRootName =
    resolvedRootName ||
    portalSearchResolveImportedRootName(sourceFiles) ||
    String(legacyDirectoryHandle?.name || "").trim() ||
    String(portalSearchState.selectedRootName || "").trim();
  portalSearchState.selectedRootName = inferredRootName;

  const guard = {
    rootName: inferredRootName,
    fileScannedCount: 0,
    count: 0,
    textCount: 0,
    searchableCount: 0,
    textDirectSuccessCount: 0,
    textParseSkippedCount: 0,
    unsupportedTypeCount: 0,
    oversizeSkippedCount: 0,
    readFailedCount: 0,
    failedCount: 0,
    documentParsedCount: 0,
    documentParseFailedCount: 0,
    documentParseSkippedCount: 0,
    documentParseFailedFiles: [],
    oversizeSkippedFiles: [],
    readFailedFiles: [],
    reachedLimit: false,
    startedAtMs: Date.now(),
    cancelRequested: () => portalSearchState.indexCancelRequested,
  };

  try {
    if (legacyDirectoryHandle) {
      const parentPath = guard.rootName || String(legacyDirectoryHandle.name || "").trim() || "导入目录";
      await portalSearchWalkLegacyDirectory(legacyDirectoryHandle, parentPath, guard);
    } else {
      await portalSearchWalkImportedFiles(sourceFiles, guard);
    }
    if (guard.cancelRequested()) {
      portalSearchSyncIndexingProgress(guard, { maxPercent: 99 });
      const cancelFailTip = guard.failedCount > 0 ? `，失败 ${guard.failedCount} 个` : "";
      const documentTip = portalSearchBuildDocumentParseStatus(guard);
      const cancelStatus = `索引已取消：已扫描 ${guard.fileScannedCount} 个文件，已纳入索引 ${guard.count} 个，正文可检索 ${guard.searchableCount} 个${cancelFailTip}${documentTip}（用时 ${portalSearchFormatDurationMs(
        Date.now() - guard.startedAtMs
      )}）`;
      portalSearchUpdateLocalStatus(cancelStatus);
      portalSearchSyncIndexReportFromGuard(guard, "索引已取消");
      if (guard.count > 0) {
        portalSearchSetNotice("已取消索引，已保留当前已处理结果。", { tone: "info", durationMs: 3800 });
      }
      return;
    }
    portalSearchSetProgress(100);
    const limitTip = guard.reachedLimit ? `，达到上限 ${PORTAL_SEARCH_MAX_INDEX_FILES}` : "";
    const failTip = guard.failedCount > 0 ? `，失败 ${guard.failedCount} 个` : "";
    const documentTip = portalSearchBuildDocumentParseStatus(guard);
    let persistedAt = 0;
    try {
      persistedAt = await portalSearchPersistLocalIndexSnapshot({
        rootName: guard.rootName || "",
        directoryHandle: legacyDirectoryHandle,
        items: portalSearchState.localIndex,
        textCount: guard.textCount,
        scannedCount: guard.fileScannedCount,
        searchableCount: guard.searchableCount,
        textDirectSuccessCount: guard.textDirectSuccessCount,
        documentParsedCount: guard.documentParsedCount,
        documentParseFailedCount: guard.documentParseFailedCount,
        documentParseSkippedCount: guard.documentParseSkippedCount,
        unsupportedTypeCount: guard.unsupportedTypeCount,
        oversizeSkippedCount: guard.oversizeSkippedCount,
        readFailedCount: guard.readFailedCount,
        textParseSkippedCount: guard.textParseSkippedCount,
        documentParseFailedFiles: guard.documentParseFailedFiles,
        oversizeSkippedFiles: guard.oversizeSkippedFiles,
        readFailedFiles: guard.readFailedFiles,
      });
    } catch {
      persistedAt = 0;
    }
    const persistTip = persistedAt
      ? `，已持久保存（${portalSearchFormatTime(persistedAt)}）`
      : "，持久保存失败（本次索引仅当前会话可用）";
    portalSearchUpdateLocalStatus(
      `索引完成：已扫描 ${guard.fileScannedCount} 个文件，纳入索引 ${guard.count} 个，正文可检索 ${guard.searchableCount} 个${failTip}${documentTip}${limitTip}${persistTip}`
    );
    portalSearchSyncIndexReportFromGuard(guard, persistedAt ? `索引完成（${portalSearchFormatTime(persistedAt)}）` : "索引完成（未持久保存）");
  } catch (error) {
    if (guard.cancelRequested()) {
      portalSearchSyncIndexingProgress(guard, { maxPercent: 99 });
      portalSearchUpdateLocalStatus(
        `索引已取消：已扫描 ${guard.fileScannedCount} 个文件，纳入索引 ${guard.count} 个（用时 ${portalSearchFormatDurationMs(
          Date.now() - guard.startedAtMs
        )}）`
      );
      portalSearchSyncIndexReportFromGuard(guard, "索引已取消");
    } else {
      portalSearchUpdateLocalStatus(`索引失败：${error?.message || "未知错误"}`);
      portalSearchSyncIndexReportFromGuard(guard, "索引失败");
    }
  } finally {
    portalSearchState.indexing = false;
    portalSearchState.indexCancelRequested = false;
    portalSearchState.indexCancelArmedUntil = 0;
    portalSearchClearCancelArmTimer();
    portalSearchSetCancelButtonArmed(false);
    if (cancelButton) cancelButton.disabled = true;
    if (reindexButton) reindexButton.disabled = false;
    if (clearIndexButton) clearIndexButton.disabled = portalSearchState.localIndex.length === 0;
  }
}

async function portalSearchChooseDirectory() {
  if (!portalSearchState.supportsEnhancedLocal) {
    portalSearchSetNotice("当前浏览器不支持本地目录索引。", {
      tone: "error",
      durationMs: 4600,
    });
    return;
  }
  try {
    if (typeof window.showDirectoryPicker === "function" && window.isSecureContext) {
      const handle = await window.showDirectoryPicker();
      portalSearchState.directoryHandle = handle;
      portalSearchState.selectedRootName = String(handle?.name || "").trim();
      await portalSearchBuildLocalIndex();
      return;
    }
    const files = await portalSearchChooseFolderFilesFromInput();
    const rootName = portalSearchResolveImportedRootName(files);
    portalSearchState.directoryHandle = null;
    portalSearchState.selectedRootName = rootName;
    await portalSearchBuildLocalIndex(files, { rootName });
  } catch (error) {
    if (error?.name !== "AbortError") {
      portalSearchUpdateLocalStatus(`选择文件夹失败：${error?.message || "未知错误"}`);
    }
  }
}

function portalSearchBuildSnippet(item, tokens) {
  if (!item.text) return "未索引正文内容，按文件名或路径匹配。";
  const flatText = item.text.replace(/\s+/g, " ").trim();
  const lowerText = flatText.toLowerCase();
  let anchor = -1;

  tokens.forEach((token) => {
    if (anchor !== -1) return;
    const index = lowerText.indexOf(token);
    if (index !== -1) anchor = index;
  });

  if (anchor === -1) {
    return flatText.slice(0, 150) + (flatText.length > 150 ? "..." : "");
  }

  const start = Math.max(0, anchor - 45);
  const end = Math.min(flatText.length, anchor + 130);
  const prefix = start > 0 ? "..." : "";
  const suffix = end < flatText.length ? "..." : "";
  return `${prefix}${flatText.slice(start, end)}${suffix}`;
}

function portalSearchResolveResultMatchSources(item, tokens) {
  const normalizedTokens = portalSearchNormalizeHighlightTokens(tokens).map((token) => token.toLowerCase());
  if (!normalizedTokens.length) return [];
  const sources = [];
  const safeName = String(item?.nameLower || "");
  const safePath = String(item?.pathLower || "");
  const safeText = String(item?.textLower || "");
  if (normalizedTokens.some((token) => safeName.includes(token))) sources.push("名称命中");
  if (normalizedTokens.some((token) => safePath.includes(token))) sources.push("路径命中");
  if (safeText && normalizedTokens.some((token) => safeText.includes(token))) sources.push("正文命中");
  return sources;
}

function portalSearchRenderLocalResults(results, queryTokens) {
  if (!results.length) {
    portalSearchSetResultPanelState("empty", "没有找到匹配项。可尝试换关键词，或重新建立索引。", {
      title: "本地搜索结果",
      meta: "0 条结果",
    });
    portalSearchState.localResults = [];
    return;
  }

  const visibleResults = results.slice(0, PORTAL_SEARCH_MAX_RENDER_RESULTS);
  portalSearchState.localResults = visibleResults;
  const html = visibleResults
    .map((item, index) => {
      const sourceTags = portalSearchResolveResultMatchSources(item, queryTokens);
      const sourceHtml = sourceTags.length
        ? `<div class="portal-search-result-source-row">${sourceTags
            .map((label) => `<span class="portal-search-result-source-tag">${portalSearchEscapeHtml(label)}</span>`)
            .join("")}</div>`
        : "";
      return `<div class="portal-search-result-item"><div class="portal-search-result-name">${portalSearchHighlightText(
        item.name,
        queryTokens
      )}</div><div class="portal-search-result-path">${portalSearchHighlightText(item.path, queryTokens)}</div>${sourceHtml}<div class="portal-search-result-meta">${portalSearchHighlightText(
        portalSearchBuildSnippet(item, queryTokens),
        queryTokens
      )}</div><div class="portal-search-result-action-row"><button class="portal-search-small-btn" data-result-action="preview" data-result-index="${index}" type="button">预览</button><span class="portal-search-result-meta">${portalSearchFormatBytes(
        item.size
      )} | ${portalSearchFormatTime(item.modified)}</span></div></div>`;
    })
    .join("");

  portalSearchSetResultPanel("本地搜索结果", `${results.length} 条结果（显示前 ${visibleResults.length} 条）`, html);
}

function portalSearchSearchLocal(keyword) {
  if (!portalSearchState.localIndex.length) {
    portalSearchSetResultPanelState("empty", "请先选择文件夹并建立索引。", {
      title: "本地搜索结果",
      meta: "无索引",
    });
    return;
  }

  const queryTokens = portalSearchTokenize(keyword);
  const normalizedQueryTokens = queryTokens
    .map((token) => String(token || "").replace(/^[`"'“”‘’]+|[`"'“”‘’]+$/g, ""))
    .filter(Boolean);
  if (!normalizedQueryTokens.length) {
    portalSearchSetResultPanelState("empty", "请输入关键词再搜索。", {
      title: "本地搜索结果",
      meta: "0 条结果",
    });
    return;
  }

  const results = [];
  portalSearchState.localIndex.forEach((item) => {
    let score = 0;
    let matchedAll = true;
    normalizedQueryTokens.forEach((token) => {
      if (!matchedAll) return;
      let matched = false;
      const extensionTokenMatch = token.match(/^\.(?<ext>[a-z0-9]+)$/);
      if (extensionTokenMatch?.groups?.ext) {
        const ext = extensionTokenMatch.groups.ext;
        if (item.extension === ext) {
          matched = true;
          score += 10;
        }
        if (item.nameLower.endsWith(token)) {
          matched = true;
          score += 3;
        }
      } else {
        if (item.nameLower.includes(token)) {
          matched = true;
          score += 6;
        }
        if (item.pathLower.includes(token)) {
          matched = true;
          score += 2;
        }
        if (item.textLower.includes(token)) {
          matched = true;
          score += 1;
        }
      }
      if (!matched) matchedAll = false;
    });
    if (!matchedAll) return;

    const ageDays = (Date.now() - item.modified) / (24 * 60 * 60 * 1000);
    if (ageDays < 7) score += 2;
    else if (ageDays < 30) score += 1;
    results.push({ ...item, score });
  });

  results.sort((a, b) => b.score - a.score || b.modified - a.modified);
  portalSearchRenderLocalResults(results, normalizedQueryTokens);
}

function portalSearchSearchWeb(keyword) {
  const query = String(keyword || "").trim();
  if (!query) return;
  const allEngines = portalSearchGetAllEngines();
  const current = allEngines.find((engine) => engine.id === portalSearchState.currentEngine);
  const target = current || PORTAL_SEARCH_PRESET_ENGINES[0];
  const searchUrl = portalSearchBuildSearchUrl(target.url, query);
  const openedWindow = portalSearchOpenBlankTab();
  if (!openedWindow) {
    try {
      window.location.assign(searchUrl);
    } catch {
      portalSearchSetNotice("网络搜索启动失败，请稍后重试。", { tone: "error", durationMs: 4600 });
    }
    return;
  }
  try {
    openedWindow.location.replace(searchUrl);
    return;
  } catch {
    try {
      openedWindow.location.href = searchUrl;
      return;
    } catch {
      try {
        openedWindow.close();
      } catch {
        // Ignore close failures.
      }
      try {
        window.location.assign(searchUrl);
      } catch {
        portalSearchSetNotice("网络搜索启动失败，请稍后重试。", { tone: "error", durationMs: 4600 });
      }
    }
  }
}

function portalSearchPerformSearch() {
  const input = portalSearchById("portalSearchInput");
  if (!input) return;
  const keyword = String(input.value || "").trim();
  if (!keyword) {
    if (portalSearchState.currentMode === "local") {
      portalSearchSetResultPanelState("empty", "请输入关键词再搜索。", {
        title: "本地搜索结果",
        meta: "0 条结果",
      });
    } else {
      portalSearchSetNotice("请输入关键词再搜索。");
      portalSearchClearResultPanel();
    }
    input.focus();
    return;
  }
  if (portalSearchState.currentMode === "local") {
    portalSearchSearchLocal(keyword);
    return;
  }
  portalSearchSearchWeb(keyword);
}

function portalSearchClearLocalIndex() {
  const reindexButton = portalSearchById("portalSearchReindexBtn");
  const cancelButton = portalSearchById("portalSearchCancelIndexBtn");
  const clearIndexButton = portalSearchById("portalSearchClearIndexBtn");
  portalSearchState.indexCancelRequested = false;
  portalSearchState.indexCancelArmedUntil = 0;
  portalSearchClearCancelArmTimer();
  portalSearchState.localIndex = [];
  portalSearchState.localResults = [];
  portalSearchState.directoryHandle = null;
  portalSearchState.selectedRootName = "";
  portalSearchState.selectedFilesByPath = new Map();
  portalSearchSetProgress(0);
  portalSearchSetCancelButtonArmed(false);
  if (reindexButton) reindexButton.disabled = false;
  if (cancelButton) cancelButton.disabled = true;
  if (clearIndexButton) clearIndexButton.disabled = true;
  portalSearchUpdateLocalStatus("索引已清空");
  portalSearchSetIndexReport({
    note: "索引已清空",
  });
  portalSearchClearResultPanel();
  void portalSearchClearPersistedLocalSnapshot();
}

async function portalSearchRenderFilePreview(item, file) {
  const requestToken = portalSearchState.previewRenderToken + 1;
  portalSearchState.previewRenderToken = requestToken;
  if (!(file instanceof Blob)) {
    portalSearchOpenPreview(item?.path || "文件预览", "预览数据不可用，请重试。");
    return;
  }

  const fileName = String(file.name || item?.name || "未命名文件");
  const filePath = String(item?.path || fileName);
  const normalizedType = normalizeVaultFileMimeType(file.type, fileName);
  const category = getVaultFilePreviewCategory(normalizedType, fileName);
  const displayTypeLabel = getVaultFileDisplayTypeLabel(normalizedType, fileName, category);
  const modifiedTime = Number(file.lastModified) || Number(item?.modified) || Date.now();
  const metaParts = [portalSearchFormatBytes(file.size), portalSearchFormatTime(modifiedTime)];
  if (displayTypeLabel) metaParts.push(displayTypeLabel);
  const contentNode = portalSearchShowPreviewModal(filePath, metaParts.join(" · "));
  if (!contentNode) return;

  const previewBlob = file.type === normalizedType ? file : file.slice(0, file.size, normalizedType);
  const previewUrl = URL.createObjectURL(previewBlob);
  portalSearchState.previewBlobUrl = previewUrl;
  portalSearchSetPreviewOpenPayload({
    mode: "blob",
    url: previewUrl,
    title: fileName,
    kind: category,
  });
  const htmlLikeText = category === "text" && isVaultHtmlLikeText({ name: fileName }, normalizedType);
  const markdownLikeText = category === "text" && isVaultMarkdownLikeText({ name: fileName }, normalizedType);

  const appendDocHint = (text) => {
    const hint = document.createElement("span");
    hint.className = "portal-search-preview-doc-hint";
    hint.textContent = text;
    contentNode.append(hint);
  };

  const appendOpenCard = (text) => {
    const button = document.createElement("button");
    button.type = "button";
    button.className = "portal-search-preview-open-card";
    button.dataset.previewAction = "open";
    button.textContent = text;
    contentNode.append(button);
  };

  if (category === "image") {
    portalSearchSetPreviewOpenPayload({
      mode: "image",
      url: previewUrl,
      title: fileName,
      kind: category,
    });
    const button = document.createElement("button");
    button.type = "button";
    button.className = "portal-search-preview-image-stage";
    button.dataset.previewAction = "open";
    button.title = "点击在新标签打开图片";
    const img = document.createElement("img");
    img.className = "portal-search-preview-image";
    img.src = previewUrl;
    img.alt = fileName;
    img.draggable = false;
    const hint = document.createElement("span");
    hint.className = "portal-search-preview-image-hint";
    hint.textContent = "点击图片在新标签打开（支持缩放与拖拽）";
    button.append(img, hint);
    contentNode.append(button);
    return;
  }

  if (category === "pdf") {
    const wrap = document.createElement("div");
    wrap.className = "portal-search-preview-frame-wrap";
    const frame = document.createElement("iframe");
    frame.className = "portal-search-preview-frame";
    frame.src = previewUrl;
    frame.title = fileName;
    wrap.append(frame);
    contentNode.append(wrap);
    appendDocHint("PDF 已内嵌预览，可直接滚动查看。");
    return;
  }

  if (category === "video") {
    const wrap = document.createElement("div");
    wrap.className = "portal-search-preview-media";
    const video = document.createElement("video");
    video.className = "portal-search-preview-video";
    video.controls = true;
    video.src = previewUrl;
    wrap.append(video);
    contentNode.append(wrap);
    return;
  }

  if (category === "audio") {
    const wrap = document.createElement("div");
    wrap.className = "portal-search-preview-audio-wrap";
    const audio = document.createElement("audio");
    audio.controls = true;
    audio.src = previewUrl;
    wrap.append(audio);
    contentNode.append(wrap);
    return;
  }

  if (category === "office-ppt") {
    const ext = getVaultFileExtension(fileName);
    if (ext === "pptx") {
      const wrap = document.createElement("div");
      wrap.className = "portal-search-preview-frame-wrap";
      const frame = document.createElement("iframe");
      frame.className = "portal-search-preview-frame";
      frame.title = fileName;
      frame.setAttribute("sandbox", "allow-scripts allow-same-origin");
      frame.srcdoc = buildVaultInlineOfficePreviewDocument(category, previewUrl, fileName);
      wrap.append(frame);
      contentNode.append(wrap);
      appendDocHint("PPTX 已按页面渲染预览。");
      return;
    }
    appendOpenCard("旧版 .ppt 浏览器无法稳定页面渲染，建议转为 .pptx 后预览。点击在新标签打开。");
    return;
  }

  if (category.startsWith("office-")) {
    const wrap = document.createElement("div");
    wrap.className = "portal-search-preview-frame-wrap";
    const frame = document.createElement("iframe");
    frame.className = "portal-search-preview-frame";
    frame.title = fileName;
    frame.setAttribute("sandbox", "allow-scripts allow-same-origin");
    frame.srcdoc = buildVaultInlineOfficePreviewDocument(category, previewUrl, fileName);
    wrap.append(frame);
    contentNode.append(wrap);
    appendDocHint("Office 文档已内嵌预览。");
    return;
  }

  if (htmlLikeText) {
    const wrap = document.createElement("div");
    wrap.className = "portal-search-preview-frame-wrap";
    const frame = document.createElement("iframe");
    frame.className = "portal-search-preview-frame";
    frame.src = previewUrl;
    frame.title = fileName;
    frame.setAttribute("sandbox", "allow-scripts allow-forms allow-popups allow-downloads");
    wrap.append(frame);
    contentNode.append(wrap);
    appendDocHint("HTML 已按页面渲染显示，不再以源码文本展示。");
    return;
  }

  if (markdownLikeText && previewBlob.size <= VAULT_FILE_PREVIEW_MAX_TEXT_SIZE) {
    const markdownText = await previewBlob.text();
    if (requestToken !== portalSearchState.previewRenderToken) return;
    const safePreviewText =
      markdownText.length > PORTAL_SEARCH_MAX_PREVIEW_CHARS ? markdownText.slice(0, PORTAL_SEARCH_MAX_PREVIEW_CHARS) : markdownText;
    const markdownHtml = renderMarkdownToSafeHtml(safePreviewText);
    const stage = document.createElement("div");
    stage.className = "portal-search-preview-markdown-stage";
    stage.dataset.previewAction = "open";
    stage.setAttribute("role", "button");
    stage.setAttribute("tabindex", "0");
    stage.setAttribute("aria-label", "在新标签打开 Markdown 文档");
    const article = document.createElement("article");
    article.className = "portal-search-preview-markdown";
    article.innerHTML = markdownHtml;
    stage.append(article);
    contentNode.append(stage);
    portalSearchSetPreviewOpenPayload({
      mode: "html",
      title: fileName,
      kind: "markdown",
      contentHtml: `<article class="markdown-view">${markdownHtml}</article>`,
    });
    appendDocHint(
      safePreviewText.length < markdownText.length ? "内容过长，右栏仅渲染部分；点击预览区在新标签查看完整文档。" : "点击预览区在新标签打开 Markdown 文档。"
    );
    return;
  }

  if (category === "text" && previewBlob.size <= VAULT_FILE_PREVIEW_MAX_TEXT_SIZE) {
    const textContent = await previewBlob.text();
    if (requestToken !== portalSearchState.previewRenderToken) return;
    const safePreviewText =
      textContent.length > PORTAL_SEARCH_MAX_PREVIEW_CHARS ? textContent.slice(0, PORTAL_SEARCH_MAX_PREVIEW_CHARS) : textContent;
    const stage = document.createElement("div");
    stage.className = "portal-search-preview-text-stage";
    stage.dataset.previewAction = "open";
    stage.setAttribute("role", "button");
    stage.setAttribute("tabindex", "0");
    stage.setAttribute("aria-label", "在新标签打开文档");
    const pre = document.createElement("pre");
    pre.className = "portal-search-preview-text";
    pre.textContent = safePreviewText;
    stage.append(pre);
    contentNode.append(stage);
    portalSearchSetPreviewOpenPayload({
      mode: "html",
      title: fileName,
      kind: "text",
      contentHtml: `<pre>${portalSearchEscapeHtml(safePreviewText)}</pre>`,
    });
    appendDocHint(
      safePreviewText.length < textContent.length ? "内容过长，右栏仅显示部分；点击预览区在新标签查看完整文档。" : "点击预览区在新标签打开文档。"
    );
    return;
  }

  appendOpenCard("该文件类型暂不支持内嵌渲染，点击在新标签打开。");
}

function portalSearchHandlePreviewAction(event) {
  const target = event.target;
  if (!(target instanceof Element)) return;
  const actionNode = target.closest("[data-preview-action]");
  if (!actionNode) return;
  const action = String(actionNode.getAttribute("data-preview-action") || "");
  if (action !== "open") return;
  event.preventDefault();
  portalSearchOpenPreviewPayloadInNewTab();
}

function portalSearchHandlePreviewActionKeydown(event) {
  if (event.key !== "Enter" && event.key !== " ") return;
  const target = event.target;
  if (!(target instanceof Element)) return;
  const actionNode = target.closest("[data-preview-action]");
  if (!actionNode) return;
  const action = String(actionNode.getAttribute("data-preview-action") || "");
  if (action !== "open") return;
  event.preventDefault();
  portalSearchOpenPreviewPayloadInNewTab();
}

async function portalSearchHandleResultAction(event) {
  const target = event.target;
  if (!(target instanceof Element)) return;
  const button = target.closest("button[data-result-action]");
  if (!button) return;
  const action = String(button.dataset.resultAction || "");
  const index = Number.parseInt(button.dataset.resultIndex || "", 10);
  if (!Number.isFinite(index) || index < 0 || index >= portalSearchState.localResults.length) return;
  const item = portalSearchState.localResults[index];
  if (!item) return;

  if (action === "preview") {
    try {
      const file = await portalSearchGetFileForResultItem(item);
      await portalSearchRenderFilePreview(item, file);
    } catch (error) {
      portalSearchOpenPreview(item.path, `无法预览该文件：${error?.message || "未知错误"}`);
    }
    return;
  }
}

function portalSearchIsEditableElement(element) {
  if (!element || !(element instanceof HTMLElement)) return false;
  const tag = element.tagName.toLowerCase();
  return (
    tag === "input" ||
    tag === "textarea" ||
    tag === "select" ||
    Boolean(element.closest('[contenteditable="true"]'))
  );
}

function portalSearchBindEvents() {
  const searchInput = portalSearchById("portalSearchInput");
  const searchButton = portalSearchById("portalSearchButton");
  const openSettingsButton = portalSearchById("portalSearchOpenSettings");
  const closeSettingsButton = portalSearchById("portalSearchCloseSettings");
  const settingsPanel = portalSearchById("portalSearchSettingsPanel");
  const settingsOverlay = portalSearchById("portalSearchOverlay");
  const addCustomEngineButton = portalSearchById("portalSearchAddCustomEngine");
  const pickFolderButton = portalSearchById("portalSearchPickFolderBtn");
  const reindexButton = portalSearchById("portalSearchReindexBtn");
  const cancelIndexButton = portalSearchById("portalSearchCancelIndexBtn");
  const clearIndexButton = portalSearchById("portalSearchClearIndexBtn");
  const closePreviewButton = portalSearchById("portalSearchClosePreview");
  const previewOverlay = portalSearchById("portalSearchPreviewOverlay");
  const previewContent = portalSearchById("portalSearchPreviewContent");
  const resultList = portalSearchById("portalSearchResultList");
  const modeSwitch = portalSearchById("portalSearchModeSwitch");
  const dropdown = portalSearchById("portalSearchEngineDropdown");
  const dropdownButton = portalSearchById("portalSearchEngineDropdownBtn");
  const dropdownMenu = portalSearchById("portalSearchEngineDropdownMenu");
  const customNameInput = portalSearchById("portalSearchCustomName");
  const customUrlInput = portalSearchById("portalSearchCustomUrl");

  if (searchInput) {
    searchInput.addEventListener("keydown", (event) => {
      if (event.key !== "Enter") return;
      event.preventDefault();
      portalSearchPerformSearch();
    });
  }
  if (searchButton) searchButton.addEventListener("click", portalSearchPerformSearch);
  if (openSettingsButton) openSettingsButton.addEventListener("click", portalSearchOpenSettings);
  if (closeSettingsButton) closeSettingsButton.addEventListener("click", portalSearchCloseSettings);
  if (settingsPanel) settingsPanel.addEventListener("keydown", portalSearchHandleSettingsPanelKeydown);
  if (settingsOverlay) settingsOverlay.addEventListener("click", portalSearchCloseSettings);
  if (addCustomEngineButton) {
    addCustomEngineButton.addEventListener("click", () => {
      if (!portalSearchCanUseSettings()) {
        portalSearchRequestSettingsAuth();
        return;
      }
      const name = String(customNameInput?.value || "").trim();
      const url = String(customUrlInput?.value || "").trim();
      if (!name || !url) {
        portalSearchSetNotice("请填写引擎名称和搜索URL", { tone: "error" });
        return;
      }
      try {
        const normalizedUrl = portalSearchNormalizeCustomEngineUrl(url);
        const normalizedNameLower = name.toLowerCase();
        const normalizedUrlLower = normalizedUrl.toLowerCase();
        const duplicateName = portalSearchState.customEngines.some(
          (engine) => String(engine?.name || "").trim().toLowerCase() === normalizedNameLower
        );
        const duplicateUrl = portalSearchState.customEngines.some(
          (engine) => String(engine?.url || "").trim().toLowerCase() === normalizedUrlLower
        );
        if (duplicateName || duplicateUrl) {
          if (duplicateName && duplicateUrl) {
            portalSearchSetNotice("该引擎名称和搜索URL均已存在，请勿重复添加。", { tone: "error" });
          } else if (duplicateName) {
            portalSearchSetNotice("该引擎名称已存在，请更换名称后再添加。", { tone: "error" });
          } else {
            portalSearchSetNotice("该搜索URL已存在，请勿重复添加。", { tone: "error" });
          }
          return;
        }
        portalSearchState.customEngines.push({ name, url: normalizedUrl });
        portalSearchSaveCustomEngines();
        portalSearchRenderEngineSelector();
        portalSearchRenderSettings();
        if (customNameInput) customNameInput.value = "";
        if (customUrlInput) customUrlInput.value = "";
        portalSearchSetNotice(`已添加自定义引擎：${name}`, { tone: "success" });
      } catch {
        portalSearchSetNotice("搜索URL格式不正确，请检查后重试。", { tone: "error" });
      }
    });
  }

  [customNameInput, customUrlInput].forEach((input) => {
    if (!input) return;
    input.addEventListener("keydown", (event) => {
      if (event.key !== "Enter") return;
      event.preventDefault();
      addCustomEngineButton?.click();
    });
  });

  if (pickFolderButton) pickFolderButton.addEventListener("click", () => void portalSearchChooseDirectory());
  if (reindexButton) {
    reindexButton.addEventListener("click", () => {
      if (portalSearchState.directoryHandle && typeof portalSearchState.directoryHandle.values === "function") {
        void (async () => {
          const granted = await portalSearchQueryDirectoryPermission(portalSearchState.directoryHandle);
          if (!granted) {
            portalSearchUpdateLocalStatus("当前目录授权未就绪，请点击“选择文件夹并索引”重新确认。");
            portalSearchSetNotice("当前目录授权未就绪，请先点击“选择文件夹并索引”。", {
              tone: "info",
              durationMs: 4200,
            });
            return;
          }
          await portalSearchBuildLocalIndex();
        })();
        return;
      }
      portalSearchUpdateLocalStatus("未检测到可直接重索引的当前目录，请先点击“选择文件夹并索引”。");
      portalSearchSetNotice("请先点击“选择文件夹并索引”确认当前目录后，再执行“重新索引”。", {
        tone: "info",
        durationMs: 4200,
      });
    });
  }
  if (cancelIndexButton) cancelIndexButton.addEventListener("click", portalSearchRequestCancelIndexing);
  if (clearIndexButton) clearIndexButton.addEventListener("click", portalSearchClearLocalIndex);
  if (closePreviewButton) closePreviewButton.addEventListener("click", portalSearchClosePreview);
  if (previewOverlay) previewOverlay.addEventListener("click", portalSearchClosePreview);
  if (previewContent) previewContent.addEventListener("click", portalSearchHandlePreviewAction);
  if (previewContent) previewContent.addEventListener("keydown", portalSearchHandlePreviewActionKeydown);
  if (resultList) resultList.addEventListener("click", (event) => void portalSearchHandleResultAction(event));

  if (modeSwitch) {
    modeSwitch.addEventListener("click", (event) => {
      const button = event.target.closest(".portal-search-mode-btn");
      if (!button) return;
      const nextMode = button.dataset.mode === "local" ? "local" : "web";
      if (nextMode === "local" && !portalSearchState.supportsEnhancedLocal) {
        portalSearchSetNotice("当前浏览器不支持本地目录索引。", {
          tone: "error",
          durationMs: 4600,
        });
        return;
      }
      portalSearchState.currentMode = nextMode;
      portalSearchRenderModeSwitch();
    });
  }

  if (dropdown && dropdownButton) {
    dropdownButton.addEventListener("click", (event) => {
      if (portalSearchState.currentMode === "local") return;
      event.stopPropagation();
      const shouldOpen = !dropdown.classList.contains("open");
      portalSearchSetEngineDropdownOpen(shouldOpen, { focusActive: false });
    });
    dropdownButton.addEventListener("keydown", (event) => {
      if (portalSearchState.currentMode === "local") return;
      if (event.key === "Enter" || event.key === " ") {
        event.preventDefault();
        portalSearchSetEngineDropdownOpen(!dropdown.classList.contains("open"), { focusActive: true });
        return;
      }
      if (event.key === "ArrowDown") {
        event.preventDefault();
        portalSearchSetEngineDropdownOpen(true, { focusActive: true });
      }
    });
  }

  if (dropdownMenu) {
    dropdownMenu.addEventListener("keydown", (event) => {
      const options = portalSearchGetVisibleEngineOptions();
      if (!options.length) return;
      const activeElement = document.activeElement;
      let currentIndex = options.findIndex((node) => node === activeElement);
      if (currentIndex < 0) {
        currentIndex = options.findIndex((node) => node.classList.contains("active"));
      }
      if (event.key === "ArrowDown") {
        event.preventDefault();
        const nextIndex = currentIndex < 0 ? 0 : (currentIndex + 1) % options.length;
        options[nextIndex].focus();
        return;
      }
      if (event.key === "ArrowUp") {
        event.preventDefault();
        const nextIndex = currentIndex < 0 ? options.length - 1 : (currentIndex - 1 + options.length) % options.length;
        options[nextIndex].focus();
        return;
      }
      if (event.key === "Home") {
        event.preventDefault();
        options[0].focus();
        return;
      }
      if (event.key === "End") {
        event.preventDefault();
        options[options.length - 1].focus();
        return;
      }
      if (event.key === "Escape") {
        event.preventDefault();
        portalSearchCloseEngineDropdown();
        dropdownButton?.focus();
        return;
      }
      if (event.key === "Tab") {
        portalSearchCloseEngineDropdown();
        return;
      }
      if (event.key === "Enter" || event.key === " ") {
        if (activeElement instanceof HTMLElement && activeElement.classList.contains("portal-search-engine-dropdown-item")) {
          event.preventDefault();
          activeElement.click();
        }
      }
    });
  }

  document.addEventListener("click", (event) => {
    if (!portalSearchRoot) return;
    if (dropdown && !dropdown.contains(event.target)) {
      portalSearchCloseEngineDropdown();
    }
  });

  document.addEventListener("keydown", (event) => {
    if (event.key === "Escape" && dropdown?.classList.contains("open")) {
      portalSearchCloseEngineDropdown();
      dropdownButton?.focus();
      return;
    }
    if (event.defaultPrevented) return;
    if (event.key !== "/") return;
    if (state.mainView !== "search") return;
    if (event.ctrlKey || event.metaKey || event.altKey) return;
    const activeElement = document.activeElement;
    if (activeElement === searchInput) return;
    if (portalSearchIsEditableElement(activeElement)) return;
    event.preventDefault();
    searchInput?.focus();
  });

  portalSearchBindIndexReportHoverInteractions();
}

function portalSearchInitializeLocalSupportStatus() {
  const pickFolderButton = portalSearchById("portalSearchPickFolderBtn");
  const reindexButton = portalSearchById("portalSearchReindexBtn");
  const cancelButton = portalSearchById("portalSearchCancelIndexBtn");
  const clearIndexButton = portalSearchById("portalSearchClearIndexBtn");
  portalSearchState.indexCancelArmedUntil = 0;
  portalSearchClearCancelArmTimer();
  portalSearchSetCancelButtonArmed(false);
  portalSearchState.supportsEnhancedLocal = portalSearchDetectEnhancedSupport();
  portalSearchRenderEnhancedSupport();

  if (!portalSearchState.supportsEnhancedLocal) {
    if (portalSearchState.currentMode === "local") {
      portalSearchState.currentMode = "web";
      portalSearchWriteStorage(PORTAL_SEARCH_STORAGE_KEYS.searchMode, portalSearchState.currentMode);
    }
    portalSearchUpdateLocalStatus("本地索引不可用（浏览器不支持目录索引）");
    if (pickFolderButton) pickFolderButton.disabled = true;
    if (reindexButton) reindexButton.disabled = true;
    if (cancelButton) cancelButton.disabled = true;
    if (clearIndexButton) clearIndexButton.disabled = true;
    portalSearchSetProgress(0);
    portalSearchSetIndexReport({
      note: "当前环境不支持本地索引",
    });
    return;
  }

  portalSearchUpdateLocalStatus("尚未选择文件夹");
  portalSearchSetIndexReport({
    note: "等待首次索引",
  });
  if (pickFolderButton) pickFolderButton.disabled = false;
  if (reindexButton) reindexButton.disabled = false;
  if (cancelButton) cancelButton.disabled = true;
}

function initializePortalSearchFeature() {
  if (!portalSearchRoot || portalSearchState.initialized) return;
  portalSearchState.currentEngine =
    portalSearchReadStorage(PORTAL_SEARCH_STORAGE_KEYS.currentEngine, PORTAL_SEARCH_PRESET_ENGINES[0].id) ||
    PORTAL_SEARCH_PRESET_ENGINES[0].id;
  portalSearchState.currentMode = portalSearchReadStorage(PORTAL_SEARCH_STORAGE_KEYS.searchMode, "web") === "local" ? "local" : "web";
  portalSearchLoadCustomEngines();
  portalSearchEnsureCurrentEngine();
  portalSearchInitializeLocalSupportStatus();
  portalSearchRenderEngineSelector();
  portalSearchRenderSettings();
  portalSearchRenderModeSwitch();
  portalSearchBindEvents();
  portalSearchSyncSettingsAccess({ force: true });
  if (portalSearchState.supportsEnhancedLocal) {
    void portalSearchRestorePersistedLocalState();
  }
  portalSearchState.initialized = true;
}

function initializeRecommendFeature() {
  if (!recommendGrid) return;
  void loadRecommendItems(true);
}

function bindViewSearchInputEvents(view) {
  const { input, clear } = getViewSearchElements(view);
  if (input) {
    syncViewSearchInputValue(view);
    const applySearch = createDebouncedFunction(() => {
      setViewSearchKeyword(view, input.value, { syncInput: false, refresh: true });
    }, VIEW_SEARCH_DEBOUNCE_MS);
    input.addEventListener("input", () => {
      syncViewSearchClearButton(view);
      applySearch();
    });
    input.addEventListener("search", () => {
      setViewSearchKeyword(view, input.value, { syncInput: false, refresh: true });
    });
  }
  if (clear) {
    clear.addEventListener("click", () => {
      setViewSearchKeyword(view, "", { syncInput: true, refresh: true });
      const { input: viewInput } = getViewSearchElements(view);
      viewInput?.focus();
    });
  }
  syncViewSearchClearButton(view);
}

function initializeViewSearchFeature() {
  bindViewSearchInputEvents("recommend");
  bindViewSearchInputEvents("internal");
  bindViewSearchInputEvents("local");
  setViewSearchMetaText("recommend", "共 0 个分组 / 0 条内容");
  setViewSearchMetaText("internal", "共 0 个分组 / 0 条内容");
  updateLocalSearchMeta();
  syncViewSearchBarVisibility(state.mainView);
}

function getWeekdayName(date) {
  return WEEKDAY_NAMES[date.getDay()];
}

function isDateInCalendarCoverage(date) {
  const year = date.getFullYear();
  return year >= CALENDAR_YEAR_MIN && year <= CALENDAR_YEAR_MAX;
}

function isCalendarAuthorityReady() {
  return typeof window.Solar?.fromYmd === "function";
}

function getAuthoritativeLunarBundle(date) {
  if (!isCalendarAuthorityReady() || !isDateInCalendarCoverage(date)) return null;
  try {
    const solar = window.Solar.fromYmd(date.getFullYear(), date.getMonth() + 1, date.getDate());
    const lunar = solar.getLunar();
    if (!lunar) return null;
    return { solar, lunar };
  } catch {
    return null;
  }
}

function getLunarParts(date) {
  const authBundle = getAuthoritativeLunarBundle(date);
  if (authBundle?.lunar) {
    const lunar = authBundle.lunar;
    const month = `${lunar.getMonthInChinese()}月`;
    const day = lunar.getDayInChinese();
    return {
      month,
      day,
      text: lunar.toString(),
      monthNumber: lunar.getMonth(),
      dayNumber: lunar.getDay(),
    };
  }

  try {
    const formatter = new Intl.DateTimeFormat("zh-CN-u-ca-chinese", {
      year: "numeric",
      month: "long",
      day: "numeric",
    });
    const parts = formatter.formatToParts(date);
    const month = parts.find((part) => part.type === "month")?.value || "";
    const day = parts.find((part) => part.type === "day")?.value || "";
    const text = formatter.format(date);

    const numericFormatter = new Intl.DateTimeFormat("zh-CN-u-ca-chinese", {
      month: "numeric",
      day: "numeric",
    });
    const numericParts = numericFormatter.formatToParts(date);
    const monthNumberRaw = numericParts.find((part) => part.type === "month")?.value || "";
    const dayNumberRaw = numericParts.find((part) => part.type === "day")?.value || "";
    const monthNumber = Number(monthNumberRaw.replace(/[^\d]/g, ""));
    const dayNumber = Number(dayNumberRaw.replace(/[^\d]/g, ""));

    return {
      month,
      day,
      text,
      monthNumber: Number.isFinite(monthNumber) && monthNumber > 0 ? monthNumber : null,
      dayNumber: Number.isFinite(dayNumber) && dayNumber > 0 ? dayNumber : null,
    };
  } catch {
    return { month: "", day: "", text: "农历信息暂不可用", monthNumber: null, dayNumber: null };
  }
}

function normalizeLunarMonth(monthText) {
  return monthText.replace("闰", "");
}

function toSolarFestivalKey(date) {
  return `${pad2(date.getMonth() + 1)}-${pad2(date.getDate())}`;
}

function findSolarTermByDate(date) {
  const authBundle = getAuthoritativeLunarBundle(date);
  if (authBundle?.lunar) {
    const termName = authBundle.lunar.getJieQi();
    if (termName) return { name: termName, month: date.getMonth() + 1, day: date.getDate() };
  }

  const month = date.getMonth() + 1;
  const day = date.getDate();
  return SOLAR_TERMS.find((term) => term.month === month && term.day === day) || null;
}

function getFestivalsOfDate(date) {
  const authBundle = getAuthoritativeLunarBundle(date);
  if (authBundle?.solar && authBundle?.lunar) {
    const solarFestivals = authBundle.solar.getFestivals?.() || [];
    const solarOtherFestivals = authBundle.solar.getOtherFestivals?.() || [];
    const lunarFestivals = authBundle.lunar.getFestivals?.() || [];
    const lunarOtherFestivals = authBundle.lunar.getOtherFestivals?.() || [];
    return [...new Set([...solarFestivals, ...solarOtherFestivals, ...lunarFestivals, ...lunarOtherFestivals])];
  }

  const festivals = [];
  const solarFestival = SOLAR_FESTIVALS[toSolarFestivalKey(date)];
  if (solarFestival) festivals.push(solarFestival);

  const lunar = getLunarParts(date);
  const lunarKey = `${normalizeLunarMonth(lunar.month)}-${lunar.day}`;
  const lunarFestival = LUNAR_FESTIVALS[lunarKey];
  const lunarNumericKey =
    lunar.monthNumber && lunar.dayNumber ? `${lunar.monthNumber}-${lunar.dayNumber}` : "";
  const lunarFestivalNumeric = LUNAR_FESTIVALS_NUMERIC[lunarNumericKey];
  if (lunarFestival) festivals.push(lunarFestival);
  if (lunarFestivalNumeric && !festivals.includes(lunarFestivalNumeric)) {
    festivals.push(lunarFestivalNumeric);
  }

  const solarTerm = findSolarTermByDate(date);
  if (solarTerm) festivals.push(`${solarTerm.name}（节气）`);

  return festivals;
}

function getAuthoritativeAuspiciousInfo(date) {
  const authBundle = getAuthoritativeLunarBundle(date);
  if (!authBundle?.lunar) return null;

  const lunar = authBundle.lunar;
  const dayTianShen = lunar.getDayTianShen?.() || "";
  const dayTianShenType = lunar.getDayTianShenType?.() || "";
  const dayTianShenLuck = lunar.getDayTianShenLuck?.() || "";
  const luckyDayParts = [dayTianShen, dayTianShenType].filter(Boolean).join("");
  const luckyDay = luckyDayParts ? `${luckyDayParts}${dayTianShenLuck ? `（${dayTianShenLuck}）` : ""}` : "暂无";

  const times = lunar.getTimes?.() || [];
  const seenBranch = new Set();
  const luckyHourList = [];
  times.forEach((time) => {
    if (!time || time.getTianShenLuck?.() !== "吉") return;
    const branch = time.getZhi?.();
    if (!branch || seenBranch.has(branch)) return;
    seenBranch.add(branch);
    const range = CHINESE_TIME_RANGE_MAP[branch] || `${time.getMinHm?.() || "--:--"}-${time.getMaxHm?.() || "--:--"}`;
    luckyHourList.push(`${branch}时(${range})`);
  });
  const luckyHours = luckyHourList.length > 0 ? luckyHourList.join("、") : "今日无吉时";

  const xi = lunar.getDayPositionXiDesc?.();
  const fu = lunar.getDayPositionFuDesc?.();
  const cai = lunar.getDayPositionCaiDesc?.();
  const directionParts = [];
  if (xi) directionParts.push(`喜神${xi}`);
  if (fu) directionParts.push(`福神${fu}`);
  if (cai) directionParts.push(`财神${cai}`);
  const luckyDirection = directionParts.length > 0 ? directionParts.join(" / ") : "暂无";

  return { luckyDay, luckyHours, luckyDirection };
}

function updateCalendarDataModeStatus() {
  if (!calendarDataModeLabel || !calendarDataSource || !calendarDataCoverage) return;
  if (isCalendarAuthorityReady()) {
    calendarDataModeLabel.textContent = "权威数据模式（已启用）";
    calendarDataSource.textContent = `数据来源：${CALENDAR_AUTH_SOURCE_NAME}，仓库：${CALENDAR_AUTH_SOURCE_LINK}`;
    calendarDataCoverage.textContent = `覆盖范围：${CALENDAR_YEAR_MIN}-${CALENDAR_YEAR_MAX}（本页面启用范围）`;
    return;
  }

  calendarDataModeLabel.textContent = "权威数据模式（未启用）";
  calendarDataSource.textContent = `数据来源未加载：${CALENDAR_AUTH_SOURCE_NAME}`;
  calendarDataCoverage.textContent = `覆盖范围：${CALENDAR_YEAR_MIN}-${CALENDAR_YEAR_MAX}；已停止展示吉日/吉时/吉方向，避免误导`;
}

function clampCalendarView(year, month) {
  let safeYear = Number(year);
  let safeMonth = Number(month);
  if (!Number.isFinite(safeYear)) safeYear = new Date().getFullYear();
  if (!Number.isFinite(safeMonth)) safeMonth = new Date().getMonth();

  while (safeMonth < 0) {
    safeMonth += 12;
    safeYear -= 1;
  }
  while (safeMonth > 11) {
    safeMonth -= 12;
    safeYear += 1;
  }

  if (safeYear < CALENDAR_YEAR_MIN) {
    safeYear = CALENDAR_YEAR_MIN;
    safeMonth = 0;
  }
  if (safeYear > CALENDAR_YEAR_MAX) {
    safeYear = CALENDAR_YEAR_MAX;
    safeMonth = 11;
  }

  return { year: safeYear, month: safeMonth };
}

function setCalendarView(year, month) {
  const clamped = clampCalendarView(year, month);
  const currentDay = calendarState.selectedDate ? calendarState.selectedDate.getDate() : 1;
  const maxDay = new Date(clamped.year, clamped.month + 1, 0).getDate();
  calendarState.viewYear = clamped.year;
  calendarState.viewMonth = clamped.month;
  calendarState.selectedDate = new Date(clamped.year, clamped.month, Math.min(currentDay, maxDay));
}

function jumpToTodayDate() {
  const today = new Date();
  if (isDateInCalendarCoverage(today)) {
    calendarState.viewYear = today.getFullYear();
    calendarState.viewMonth = today.getMonth();
    calendarState.selectedDate = new Date(today.getFullYear(), today.getMonth(), today.getDate());
  } else {
    const clamped = clampCalendarView(today.getFullYear(), today.getMonth());
    const maxDay = new Date(clamped.year, clamped.month + 1, 0).getDate();
    calendarState.viewYear = clamped.year;
    calendarState.viewMonth = clamped.month;
    calendarState.selectedDate = new Date(clamped.year, clamped.month, Math.min(today.getDate(), maxDay));
  }
  closeCalendarMonthPicker();
  renderCalendarGrid();
  renderCalendarDetails();
}

function initializeCalendarPickerOptions() {
  if (!calendarYearSelect) return;
  if (calendarYearSelect.options.length > 0) return;
  for (let year = CALENDAR_YEAR_MIN; year <= CALENDAR_YEAR_MAX; year += 1) {
    const option = document.createElement("option");
    option.value = String(year);
    option.textContent = `${year}年`;
    calendarYearSelect.append(option);
  }
}

function openCalendarMonthPicker() {
  if (!calendarMonthPicker) return;
  initializeCalendarPickerOptions();
  if (calendarYearSelect) calendarYearSelect.value = String(calendarState.viewYear);
  if (calendarMonthSelect) calendarMonthSelect.value = String(calendarState.viewMonth + 1);
  calendarMonthPicker.hidden = false;
  if (calendarMonthTrigger) calendarMonthTrigger.setAttribute("aria-expanded", "true");
}

function closeCalendarMonthPicker() {
  if (!calendarMonthPicker) return;
  calendarMonthPicker.hidden = true;
  if (calendarMonthTrigger) calendarMonthTrigger.setAttribute("aria-expanded", "false");
}

function applyCalendarMonthPicker() {
  if (!calendarYearSelect || !calendarMonthSelect) return;
  const year = Number(calendarYearSelect.value);
  const month = Number(calendarMonthSelect.value) - 1;
  setCalendarView(year, month);
  closeCalendarMonthPicker();
  renderCalendarGrid();
  renderCalendarDetails();
}

function updateCalendarHeaderTime() {
  if (!calendarDateLabel || !calendarTimeLabel || !calendarLunarLabel) return;
  const now = new Date();
  const lunar = getLunarParts(now);
  calendarDateLabel.textContent = `${formatGregorianDate(now)} ${getWeekdayName(now)}`;
  calendarTimeLabel.textContent = formatTime24(now);
  calendarLunarLabel.textContent = lunar.month && lunar.day ? `农历 ${lunar.month}${lunar.day}` : lunar.text;
}

function renderCalendarGrid() {
  if (!calendarGrid || !calendarMonthLabel) return;

  const year = calendarState.viewYear;
  const month = calendarState.viewMonth;
  const monthNumber = month + 1;
  const firstDayWeek = new Date(year, month, 1).getDay();
  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const today = new Date();
  calendarMonthLabel.textContent = `${year}年${pad2(monthNumber)}月`;
  if (calendarPrevMonth) calendarPrevMonth.disabled = year === CALENDAR_YEAR_MIN && month === 0;
  if (calendarNextMonth) calendarNextMonth.disabled = year === CALENDAR_YEAR_MAX && month === 11;
  calendarGrid.innerHTML = "";

  for (let i = 0; i < firstDayWeek; i += 1) {
    const blank = document.createElement("button");
    blank.type = "button";
    blank.className = "calendar-day is-empty";
    blank.disabled = true;
    calendarGrid.append(blank);
  }

  for (let day = 1; day <= daysInMonth; day += 1) {
    const date = new Date(year, month, day);
    const button = document.createElement("button");
    button.type = "button";
    button.className = "calendar-day";
    button.textContent = String(day);
    button.dataset.year = String(year);
    button.dataset.month = String(month);
    button.dataset.day = String(day);

    if (isSameDate(date, today)) button.classList.add("is-today");
    if (isSameDate(date, calendarState.selectedDate)) button.classList.add("is-selected");

    const term = findSolarTermByDate(date);
    if (term) {
      const mark = document.createElement("span");
      mark.className = "calendar-mark";
      mark.textContent = term.name;
      button.append(mark);
    }

    button.addEventListener("click", () => {
      calendarState.selectedDate = date;
      renderCalendarGrid();
      renderCalendarDetails();
    });

    calendarGrid.append(button);
  }
}

function renderCalendarDetails() {
  if (!calendarSelectedLabel || !calendarFestivalLabel || !calendarTermLabel) return;

  const selected = calendarState.selectedDate;
  const lunar = getLunarParts(selected);
  const festivals = getFestivalsOfDate(selected);
  const solarTerm = findSolarTermByDate(selected);
  const auspicious = getAuthoritativeAuspiciousInfo(selected);

  const lunarText = lunar.month && lunar.day ? `农历 ${lunar.month}${lunar.day}` : lunar.text;
  calendarSelectedLabel.textContent = `公历：${formatGregorianDate(selected)} ${getWeekdayName(selected)} | ${lunarText}`;
  calendarFestivalLabel.textContent = `中国节日：${festivals.length > 0 ? festivals.join("、") : "暂无"}`;
  calendarTermLabel.textContent = `二十四节气：${solarTerm ? solarTerm.name : "当日无节气"}`;

  if (!auspicious) {
    if (calendarLuckyDay) calendarLuckyDay.textContent = "吉日：权威数据未加载";
    if (calendarLuckyTime) calendarLuckyTime.textContent = "吉时：权威数据未加载";
    if (calendarLuckyDirection) calendarLuckyDirection.textContent = "吉方向：权威数据未加载";
    return;
  }

  if (calendarLuckyDay) calendarLuckyDay.textContent = `吉日：${auspicious.luckyDay}`;
  if (calendarLuckyTime) calendarLuckyTime.textContent = `吉时：${auspicious.luckyHours}`;
  if (calendarLuckyDirection) calendarLuckyDirection.textContent = `吉方向：${auspicious.luckyDirection}`;
}

