document.addEventListener("click", (event) => {
  const sidebar = document.getElementById("sidebar");
  const clickedMobileTrigger = mobileTrigger && mobileTrigger.contains(event.target);
  const shouldCloseOnMobile =
    window.innerWidth <= 980 &&
    body.classList.contains("sidebar-open") &&
    !sidebar.contains(event.target) &&
    !clickedMobileTrigger;
  if (shouldCloseOnMobile) {
    body.classList.remove("sidebar-open");
    syncMobileTriggerState();
  }
  if (calendarChip && calendarPopover && !calendarPopover.hidden && !calendarChip.contains(event.target)) {
    closeCalendarPopover();
  }
  if (visitChip && visitPopover && !visitPopover.hidden && !visitChip.contains(event.target)) {
    closeVisitPopover();
  }
  if (notesContextMenu && !notesContextMenu.hidden && !notesContextMenu.contains(event.target)) {
    closeNotesContextMenu();
  }
  if (
    notesToolbarMoreMenu &&
    !notesToolbarMoreMenu.hidden &&
    !notesToolbarMoreMenu.contains(event.target) &&
    !(notesToolbarMoreButton && notesToolbarMoreButton.contains(event.target))
  ) {
    closeNotesToolbarMoreMenu();
  }
  if (
    notesRichToolsConfigPanel &&
    !notesRichToolsConfigPanel.hidden &&
    !notesRichToolsConfigPanel.contains(event.target) &&
    !(notesRichToolsConfigButton && notesRichToolsConfigButton.contains(event.target))
  ) {
    closeNotesRichToolsConfigPanel();
  }
});

document.addEventListener("keydown", (event) => {
  if (handleNotesSearchGlobalShortcut(event)) return;
  if (event.key === "Escape") {
    if (tasksAlarmRingBackdrop && !tasksAlarmRingBackdrop.hidden) {
      stopTasksAlarmRinging();
      return;
    }
    if (tasksAlarmModal && !tasksAlarmModal.hidden) {
      closeTasksAlarmModal();
      return;
    }
    if (closeAiCodePreview()) return;
    if (closeAiImagePreview()) return;
    if (closeNetworkImagePreview()) return;
    closeBgModal();
    closeNoticeModal();
    closeTasksSearchResultModal();
    closeNotesAuthModal();
    closeWebsiteAddModal();
    closeNetworkImageModal();
    closeNotesContextMenu();
    closeNotesToolbarMoreMenu();
    closeNotesRichToolsConfigPanel();
    closeAiApiSettingsModal();
    closeCalendarPopover();
    closeVisitPopover();
    portalSearchCloseSettings();
    portalSearchClosePreview();
    if (window.innerWidth <= 980) {
      body.classList.remove("sidebar-open");
      syncMobileTriggerState();
    }
  }
});

document.addEventListener("visibilitychange", () => {
  visitState.tickLastMs = Date.now();
  updateCalendarHeaderTime();
});

window.addEventListener("beforeunload", () => {
  portalSearchStopCosmosAnimation();
  if (visitState.unsavedSeconds > 0) saveVisitDailyTotals();
  flushVisitDailyTotalsToServer();
  if (visitTickerId) window.clearInterval(visitTickerId);
  if (calendarTickerId) window.clearInterval(calendarTickerId);
  if (tasksAlarmRuntimeState.clockTimerId) {
    window.clearInterval(tasksAlarmRuntimeState.clockTimerId);
    tasksAlarmRuntimeState.clockTimerId = null;
  }
  if (tasksAlarmRuntimeState.statusTimerId) {
    window.clearTimeout(tasksAlarmRuntimeState.statusTimerId);
    tasksAlarmRuntimeState.statusTimerId = null;
  }
  stopTasksAlarmRinging({ silent: true });
  if (aiAssistantState.requestAbortController) aiAssistantState.requestAbortController.abort();
  revokeBackgroundBlobUrl();
});

window.addEventListener("resize", () => {
  if (window.innerWidth > 980 && body.classList.contains("sidebar-open")) {
    body.classList.remove("sidebar-open");
  }
  syncMobileTriggerState();
});

applyTheme();
applyBackground();
void restoreCachedLocalBackgroundIfNeeded();
applySidebar();
syncMobileTriggerState();
initializeRecommendFeature();
initializePortalSearchFeature();
initializeNotesFeature();
initializeNetworkImageFeature();
initializeLocalFeature();
initializeProtectedFeatureModules();
initializeWebsiteCollectionFeature();
initializeVaultFileCenter();
initializeAiAssistantFeature();
initializeViewSearchFeature();
applyMainView();
initializeNoticeFeature();
initializeTutorialFeature();
initializeCalendarFeature();
initializeVisitFeature();
